-- Poems batch 257
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6b70f95e-a9d5-4731-a3c9-c4ebb4bf1c7c','遊霍童  其三','陳嘉言','宋','宋诗','song-poetry','','[]','瀑聲深澗淺澗，峰勢烟籠霧籠。',28,'全唐诗/poet.song.230000.json','["瀑聲深澗淺澗，峰勢烟籠霧籠。", "彷彿身遊海上，須臾覺上山中。"]'),
('5ce90f52-97a1-4259-ab8c-5666fc392ce1','遊霍童  其四','陳嘉言','宋','宋诗','song-poetry','','[]','翠篠輕挑綠酒，紫芝閒對黄冠。',28,'全唐诗/poet.song.230000.json','["翠篠輕挑綠酒，紫芝閒對黄冠。", "半醉風迴鐵笛，中宵冷露瑶壇。"]'),
('3c41653e-3cbd-4bc2-bac3-d28c4ab55db4','哭陳丞相','鄭鉞','宋','宋诗','song-poetry','','[]','大厦將傾一木支，登陴慟哭志難移。',64,'全唐诗/poet.song.230000.json','["大厦將傾一木支，登陴慟哭志難移。", "螳螂怒臂當車日，精衛銜沙塞海時。", "夢裏忽驚元主朔，軍中猶卓宋家旗。", "孤臣萬死原無恨，獨怪山翁總不知。"]'),
('7c992b28-a3c2-460a-b632-48f6492273b0','寶祐甲寅巧夕陪趙簾谿游乳洞時秋意已□俗塵頓洗西疇項大受謾賦一詩以紀歲月','項大受','宋','宋诗','song-poetry','','[]','三洞相連等貫珠，高秋登覽興何如。',64,'全唐诗/poet.song.230000.json','["三洞相連等貫珠，高秋登覽興何如。", "安得□借世人□，仙境寧嫌釋氏居。", "□甚□宜深避□，□然賸喜共逃虛。", "重遊未必歡□□，石上聊得歲月書。"]'),
('d67fcf9e-6f7d-4966-838c-eecd54913b24','冷清生活與賦拙何異圍棋酌酒其樂無涯再得一律','項大受','宋','宋诗','song-poetry','','[]','□带無遺賞，尋盟乳洞仙。',48,'全唐诗/poet.song.230000.json','["□带無遺賞，尋盟乳洞仙。", "萬山如玉立，三穴自珠聯。", "局外棋尤審，杯餘酒更傳。", "回頭笑牛女，虹氣直衝天。"]'),
('19413d83-a4be-4e4c-872d-0d86909adf7c','次韻大受游乳洞謾賦','趙簾谿','宋','宋诗','song-poetry','','[]','等閒過似得明珠，三洞山行喜自如。',64,'全唐诗/poet.song.230000.json','["等閒過似得明珠，三洞山行喜自如。", "俗客□□尋□處，仙人何必好樓居。", "石聲玉磬傳空谷，水色冰壺照碧虛。", "便好結茅採芝木，利名盡委絕交書。"]'),
('37c6e911-c7c3-4b05-b9d9-a7d7fcd6e0bb','次韻大受冷清生活與賦拙何異','趙簾谿','宋','宋诗','song-poetry','','[]','群雞今無術，乘風擬學仙。',48,'全唐诗/poet.song.230000.json','["群雞今無術，乘風擬學仙。", "登臨皆雀躍，酬倡欲蟬聯。", "坐久昏鐘定，□遲夜漏傳。", "南中□福地，此是一□天。"]'),
('355b8c88-9a13-40c1-8720-e4596de17aa6','詩一首','黄震喜','宋','宋诗','song-poetry','','[]','手挹龍頭蹽龍脊，山聳螺鬟水澄碧。',32,'全唐诗/poet.song.230000.json','["手挹龍頭蹽龍脊，山聳螺鬟水澄碧。", "酒酣一笑且掀髯，春日融融浮霽色。"]'),
('5955b46c-5fa2-4fb9-baa2-b85ea79e7a54','言志','趙必㳅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','足濯長江萬里流，手提三尺龍泉遊。',32,'全唐诗/poet.song.230000.json','["足濯長江萬里流，手提三尺龍泉遊。", "胸中一片英雄氣，生不殺奸死不休。"]'),
('50e23e52-973a-4b6a-8ada-5853893d39b0','秋夜玩月','趙必㳅','宋','宋诗','song-poetry','','[]','幾度停杯發浩歌，月華偏照別離多。',32,'全唐诗/poet.song.230000.json','["幾度停杯發浩歌，月華偏照別離多。", "牀頭賸有樽酒綠，醉飲鯨飛滄海波。"]'),
('647464f0-d741-4649-8453-e786638fdb54','和孫逢辰遊子吟','趙必㳅','宋','宋诗','song-poetry','','[]','獨向春風淚幾回，經年遊子自堪悲。',64,'全唐诗/poet.song.230000.json','["獨向春風淚幾回，經年遊子自堪悲。", "天涯只爲青雲絆，堂上應憐白雪垂。", "離思不隨音問去，浪身惟逐夢魂歸。", "有時得慰故鄉願，骨肉團團醉壽杯。"]'),
('be32331d-b5b4-430d-820f-6bd516f0f4de','憶西湖','陳昌時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','游夢春成昨，東風感舊題。',48,'全唐诗/poet.song.230000.json','["游夢春成昨，東風感舊題。", "江流如汴水，柳色似隋堤。", "地重天王塔，山寒處士棲。", "最憐三月暮，愁眼爲花迷。"]'),
('e7fefe3c-42f3-4fda-b11b-7e9b134c6f1c','黄金臺','陳昌時','宋','宋诗','song-poetry','','[]','峩峩燕中臺，悠悠易上水。',48,'全唐诗/poet.song.230000.json','["峩峩燕中臺，悠悠易上水。", "懷哉燕昭王，招彼天下士。", "士貴相知深，豈爲多黄金。", "築臺置黄金，自是君王心。"]'),
('224221d4-76e0-4ef8-8d53-170dbd8aed26','周公輔別業','陳昌時','宋','宋诗','song-poetry','','[]','同余棲隠地，只在白雲根。',48,'全唐诗/poet.song.230000.json','["同余棲隠地，只在白雲根。", "野草行無路，孤舟入有門。", "已存栽竹地，不買種桃園。", "眼底饒蒼翠，南山带北村。"]'),
('67525bee-b6c9-425b-b042-dfa1fc8abb87','湛江歸自浙西','陳昌時','宋','宋诗','song-poetry','','[]','尚憶滄洲舊釣舲，一瓢收盡浙江靈。',64,'全唐诗/poet.song.230000.json','["尚憶滄洲舊釣舲，一瓢收盡浙江靈。", "鬢欺北斗憐歸鶴，眼暗西風悔聚螢。", "蚌浦有光秋孕月，劍床留怪夜眠星。", "不堪雨外重回首，塔壓吳山□□青。"]'),
('e0dfcd52-eac8-4a37-9a2b-276eecc4109e','太真圖','陳昌時','宋','宋诗','song-poetry','','[]','繡帕香韉玉履麟，侍兒扶上不勝春。',32,'全唐诗/poet.song.230000.json','["繡帕香韉玉履麟，侍兒扶上不勝春。", "如何攬轡宮階日，却把中原踏作塵。"]'),
('00b6136d-0d7c-465c-8cb2-fb24c98743be','即事','陳昌時','宋','宋诗','song-poetry','','[]','石室無來客，閒雲伴晚眠。',48,'全唐诗/poet.song.230000.json','["石室無來客，閒雲伴晚眠。", "夢添身外事，髮減鏡中年。", "小雨溪平路，牛衣業在田。", "劍星橫照膽，歸意未應全。"]'),
('efc355ae-ff33-4d12-8fc5-12302c511423','曉程','陳昌時','宋','宋诗','song-poetry','','[]','男兒腰下带芙蓉，羞睹秦官老徑松。',64,'全唐诗/poet.song.230000.json','["男兒腰下带芙蓉，羞睹秦官老徑松。", "羊胛日生寒戍鼓，馬蹄風起夜樓鐘。", "菊花憔悴三分雨，楓葉青紅一半冬。", "只爲新詩吟太早，滿衣風露濕重重。"]'),
('97835db0-8f8b-4ff9-85b7-70f0110a0f03','太平宴','陳昌時','宋','宋诗','song-poetry','','[]','朝陽鳴鳳馬圖河，雷動官僚宴泰和。',64,'全唐诗/poet.song.230000.json','["朝陽鳴鳳馬圖河，雷動官僚宴泰和。", "萬國春風酣組綬，九天明月照笙歌。", "紅雲瑞擁山呼壽，滄海恩深酒作波。", "元朔丹崖聲教遠，願昭鴻業刻嵯峨。"]'),
('b6a9b0f6-aebe-4aff-98eb-c8a800e96c5c','留湖心寺','陳昌時','宋','宋诗','song-poetry','','[]','出城五里凄無宿，清境光輝日遍曝。',64,'全唐诗/poet.song.230000.json','["出城五里凄無宿，清境光輝日遍曝。", "水仙飛結空中樓，佛香吹化蓮花國。", "老僧坐久忘身心，夜凉恍住蛟人屋。", "何當使我出世愁，苔逕幽窗弄藝竹。"]'),
('3b33f894-6d0d-4f6c-950d-9c4fd65215fa','露坐','陳得時','宋','宋诗','song-poetry','','[]','露坐當中夜，誰家夢正迷。',48,'全唐诗/poet.song.230000.json','["露坐當中夜，誰家夢正迷。", "行人在邊戍，孤月到深閨。", "天迥斗橫北，海寒風自西。", "庭前有高樹，分借老烏棲。"]'),
('2b6ef529-a0a1-4ce2-b156-c3a96d87b19f','曉思','陳得時','宋','宋诗','song-poetry','','[]','南樓捲書坐，極目動清□。',48,'全唐诗/poet.song.230000.json','["南樓捲書坐，極目動清□。", "野色春千里，晴光曉萬家。", "人耕烟外草，鳥啄樹頭花。", "記得夜來夢，清天飛日華。"]'),
('d107c05e-5b8d-4e1b-a365-5385e23371cf','餞陳隨隠歸臨川','吳大有','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我昔見君方成童，長吉才華驚鉅公。',264,'全唐诗/poet.song.230000.json','["我昔見君方成童，長吉才華驚鉅公。", "人間科第不屑就，直使聲名聞九重。", "乃翁引上凝華殿，子虛不待他人薦。", "入直來來凡幾年，天上奇書盡曾見。", "翩然歸去大江西，二疏父子還相隨。", "故鄉分得雲水地，却喜不爽漁樵期。", "春雨騎牛對烟草，何如振衣隨龍五雲表。", "秋霜黄獨煨地爐，何如駝峰犀筯食天厨。", "林間拾葉抄詩句，何如宮妃捧硯揮毫處。", "溪邊照影著荷衣，何如龍門應制奪錦時。", "鈞天夢斷難回顧，浩然合在山中住。", "金石臺前伴白雲，六年不踏西湖路。", "今日重來發長吁，忍看清平破草廬。", "盡拈書籍向人賣，歸買田園供荷鋤。", "乃翁八十齒髮落，倚門待兒斜日薄。", "孤山梅花带不歸，却喚扁舟載童鶴。"]'),
('34e23ef4-f0bc-4c70-9aff-6c6812756909','晚過西湖','吳大有','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曙色溟溟濕縕袍，湧金門下上輕橈。',64,'全唐诗/poet.song.230000.json','["曙色溟溟濕縕袍，湧金門下上輕橈。", "五更鍾鼓星初沒，兩岸樓臺霧未消。", "路傍柳洲人語近，山連葛嶺鶴聲遥。", "衝寒亦有尋梅客，擁袖騎馿過短橋。"]'),
('78af6222-310c-41ff-a920-099902545a2c','雜詩  其一','吳大有','宋','宋诗','song-poetry','','[]','多年書問斷，湖海竟悠悠。',48,'全唐诗/poet.song.230000.json','["多年書問斷，湖海竟悠悠。", "一見心雖滿，相看淚忽流。", "彩烟山色暮，碧瀨月痕秋。", "明日登程去，鶺鴒河上愁。"]'),
('0bc11abc-62a7-406b-9a58-bf2ec52bdd20','雜詩  其二','吳大有','宋','宋诗','song-poetry','','[]','山中多雨水，秋晚正妨農。',48,'全唐诗/poet.song.230000.json','["山中多雨水，秋晚正妨農。", "病菜和根煮，新粳带溼舂。", "擁沙埋廢井，墮石折枯松。", "寂寂猿啼晝，白雲藏數峰。"]'),
('7f618900-d0e6-44ab-a63c-ef14163cdd06','雜詩  其三','吳大有','宋','宋诗','song-poetry','','[]','客行情最苦，草草共清尊。',24,'全唐诗/poet.song.230000.json','["客行情最苦，草草共清尊。", "萬水千山路，今朝好出門。"]'),
('5d811c74-1bc8-4a54-8e7d-0bdab6639e0f','雜詩  其四','吳大有','宋','宋诗','song-poetry','','[]','雁聲低度水村深，中有人敲月下門。',32,'全唐诗/poet.song.230000.json','["雁聲低度水村深，中有人敲月下門。", "滿屋秋風燈欲暗，江山千里故園心。"]'),
('d854efc6-3f05-4675-aedf-4f7876eca34a','遊上竺寺','吳大有','宋','宋诗','song-poetry','','[]','編茅爲屋住，結葉作衣裳。',48,'全唐诗/poet.song.230000.json','["編茅爲屋住，結葉作衣裳。", "不試燒金訣，惟尋煮石方。", "洗瓢溪月冷，采藥野雲香。", "嘗有仙家鶴，飛來繞石傍。"]'),
('2aec0074-3de1-4a57-b1ed-9bf7a151f412','遊虞山','陳蒙','宋','宋诗','song-poetry','','[]','野店杏花紅滿枝，江南天氣早春時。',64,'全唐诗/poet.song.230000.json','["野店杏花紅滿枝，江南天氣早春時。", "青山笑我來何晚，白髮催人老不知。", "雲竇雪消龍澗滿，星壇樹偃鶻巢危。", "明朝欲盡登臨興，還赴雲間羽士期。"]'),
('a21a7db9-2bee-4cc9-b82a-ee3105e78173','穿山','陳蒙','宋','宋诗','song-poetry','','[]','石門空虛誰鑿闢，薜荔挂影蒼苔積。',32,'全唐诗/poet.song.230000.json','["石門空虛誰鑿闢，薜荔挂影蒼苔積。", "懸崖偃樹鶻棲巢，古洞出雲龍啟蟄。"]'),
('b2ca1e2b-4461-4203-956c-8696e187e18b','題玉芝祠','陳蒙','宋','宋诗','song-poetry','','[]','玉芝不見草蕭蕭，古柏陰廊晝寂寥。',64,'全唐诗/poet.song.230000.json','["玉芝不見草蕭蕭，古柏陰廊晝寂寥。", "琳館廢來餘福地，名碑留在記前朝。", "碧梧樹老鸞飛遠，華表天空鶴去遥。", "惟有迎仙橋上月，夜深還自照吹簫。"]'),
('81d6bd20-d418-4aae-9b0c-3816151eb1fb','游雲門','陳蒙','宋','宋诗','song-poetry','','[]','杖策耶溪寺，風流憶晉唐。',48,'全唐诗/poet.song.230000.json','["杖策耶溪寺，風流憶晉唐。", "門深雲未散，梁古帖猶香。", "晚翠千峰遠，春深一澗長。", "徘徊松影下，覓句向斜陽。"]'),
('b3b33946-ccd1-4084-a5fb-205de6fda88b','賦梅花','布衣某','宋','宋诗','song-poetry','','[]','影摇溪脚月猶冷，香滿枝頭雪未乾。',32,'全唐诗/poet.song.230000.json','["影摇溪脚月猶冷，香滿枝頭雪未乾。", "只爲傳家太清白，致令生子亦辛酸。"]'),
('d941df07-13db-47eb-8f3f-09a7147fe48a','孟享仰瞻聖駕','阮秀實','宋','宋诗','song-poetry','','[]','紫烟斂翠碧天長，柳陰旌旗午尚霜。',32,'全唐诗/poet.song.230000.json','["紫烟斂翠碧天長，柳陰旌旗午尚霜。", "一朵彩雲擎瑞日，光華盡在舜衣裳。"]'),
('b1791d6f-6c8c-4fa4-9fd5-5f179834dab9','景靈宮恭謝駕回丞相以下皆簪花','阮秀實','宋','宋诗','song-poetry','','[]','宮花密映帽簷新，誤蝶疑蜂逐去塵。',32,'全唐诗/poet.song.230000.json','["宮花密映帽簷新，誤蝶疑蜂逐去塵。", "自是近臣偏得賜，繡鞍扶上不勝春。"]'),
('4e74028a-2d24-4652-baf4-d9e77dbb5c7f','思親五首  其一','謝枋得','宋','宋诗','song-poetry','','[]','九十萱親天下稀，十年甘旨誤庭闈。',32,'全唐诗/poet.song.230000.json','["九十萱親天下稀，十年甘旨誤庭闈。", "臨行有懇慈心喜，再覩衣冠兒便歸。"]'),
('94d69e35-7c94-4a5b-8849-da80974bd0c8','思親五首  其二','謝枋得','宋','宋诗','song-poetry','','[]','九十萱親天下稀，吾王何在子何之。',32,'全唐诗/poet.song.230000.json','["九十萱親天下稀，吾王何在子何之。", "倚閭旦暮無他念，一片好心天得知。"]'),
('f67e7933-6374-4a06-a36b-d4685248d528','思親五首  其三','謝枋得','宋','宋诗','song-poetry','','[]','九十萱親天下稀，人無容力荷天慈。',32,'全唐诗/poet.song.230000.json','["九十萱親天下稀，人無容力荷天慈。", "衣冠禮樂江東聚，此是癡兒奉母時。"]'),
('4fe146a0-09fe-4ac8-8ec7-c258764e9666','思親五首  其四','謝枋得','宋','宋诗','song-poetry','','[]','九十萱親天下稀，平生教子欲何爲。',32,'全唐诗/poet.song.230000.json','["九十萱親天下稀，平生教子欲何爲。", "楚王肯立韓公子，良也歸韓亦有辭。"]'),
('2c056b09-77af-4d17-9682-dd3992ed606f','思親五首  其五','謝枋得','宋','宋诗','song-poetry','','[]','九十萱親天下稀，教兒只誦白華詩。',32,'全唐诗/poet.song.230000.json','["九十萱親天下稀，教兒只誦白華詩。", "溪冰山玉人無愧，百拜慈闈喜可知。"]'),
('cc9c51b8-f733-4ac2-b9d5-e10eb0d7b32b','代上杜按察三首  其一','謝枋得','宋','宋诗','song-poetry','','[]','東南官吏欠清風，五十年來世道窮。',32,'全唐诗/poet.song.230000.json','["東南官吏欠清風，五十年來世道窮。", "須信太平在今日，人間又有杜祁公。"]'),
('335c4784-3918-4bac-ad2b-d750f1ed7a43','代上杜按察三首  其二','謝枋得','宋','宋诗','song-poetry','','[]','慶曆諸公開太平，選賢按察救生靈。',32,'全唐诗/poet.song.230000.json','["慶曆諸公開太平，選賢按察救生靈。", "當時只有一杜杞，豈若先生真福星。"]'),
('7412c63b-5ac2-487e-bfd0-925f78c154fc','代上杜按察三首  其三','謝枋得','宋','宋诗','song-poetry','','[]','萬物寧無吐氣時，平生愛誦杜陵詩。',32,'全唐诗/poet.song.230000.json','["萬物寧無吐氣時，平生愛誦杜陵詩。", "如今天下知元結，六百年間再見之。"]'),
('5f7786d5-f710-4a8d-bcd8-2c8e0e5ce459','送程楚翁遠游','謝枋得','宋','宋诗','song-poetry','','[]','近日人傳庾嶺梅，南枝落盡北枝開。',32,'全唐诗/poet.song.230000.json','["近日人傳庾嶺梅，南枝落盡北枝開。", "長安舊日元無此，盡是江南人送來。"]'),
('117af504-48b9-4630-bd15-c7616ed755a5','寄謝叔魯三首  其一','謝枋得','宋','宋诗','song-poetry','','[]','紅葉飄摇霜露清，去年今日正同行。',32,'全唐诗/poet.song.230000.json','["紅葉飄摇霜露清，去年今日正同行。", "夜來似與君相見，明月一窗梅影橫。"]'),
('9d1f6d2c-f63a-4ae2-93e2-4a84c8048ffc','寄謝叔魯三首  其二','謝枋得','宋','宋诗','song-poetry','','[]','一歲思君君不來，君來我去欠徘徊。',32,'全唐诗/poet.song.230000.json','["一歲思君君不來，君來我去欠徘徊。", "歸時只見留詩在，何日相逢暢好懷。"]'),
('9d443341-1fac-4233-b859-bd0b84ea23f8','寄謝叔魯三首  其三','謝枋得','宋','宋诗','song-poetry','','[]','平生結客知心少，亂世逢人笑口難。',32,'全唐诗/poet.song.230000.json','["平生結客知心少，亂世逢人笑口難。", "近日老天頻送喜，誰來對酒共清歡。"]'),
('dedfd00f-eccf-438a-9f8c-3a9475d2022f','五星','謝枋得','宋','宋诗','song-poetry','','[]','五緯煌煌聚在秦，項王稱霸沛公臣。',32,'全唐诗/poet.song.230000.json','["五緯煌煌聚在秦，項王稱霸沛公臣。", "誰知四百年天下，已屬寬仁大度人。"]'),
('4a788e08-2d85-445a-a13b-d52014f8f256','元旦阻雨二首  其一','謝枋得','宋','宋诗','song-poetry','','[]','洪鈞一轉歲開端，草木群生亦喜歡。',32,'全唐诗/poet.song.230000.json','["洪鈞一轉歲開端，草木群生亦喜歡。", "安得明年此時節，江東重覩舊衣冠。"]'),
('3ad06d5f-3886-45a2-83b7-d7895b69648e','元旦阻雨二首  其二','謝枋得','宋','宋诗','song-poetry','','[]','莫道新年賀客遲，晴天暖日却相期。',32,'全唐诗/poet.song.230000.json','["莫道新年賀客遲，晴天暖日却相期。", "春風只被多情苦，紅嫩青新總要詩。"]'),
('f411dde9-6ea2-4c4a-abd8-39c7024f5b13','戲道士阮太虛','謝枋得','宋','宋诗','song-poetry','','[]','阮郎正好住天台，玉女多情忍放回。',32,'全唐诗/poet.song.230000.json','["阮郎正好住天台，玉女多情忍放回。", "雨散雲收一天碧，薰風吹夢到瑶臺。"]'),
('f207b928-2712-466e-81ea-eb18bcb5c19e','春日聞杜宇','謝枋得','宋','宋诗','song-poetry','','[]','杜鵑日日勸人歸，一片歸心誰得知。',32,'全唐诗/poet.song.230000.json','["杜鵑日日勸人歸，一片歸心誰得知。", "望帝有神如可問，謂余何日是歸期。"]'),
('1df8d0f6-d0e0-467c-893b-f487ccbcbdc4','謝送夏衣','謝枋得','宋','宋诗','song-poetry','','[]','南州久客困炎歊，汗浥春衫上白毛。',32,'全唐诗/poet.song.230000.json','["南州久客困炎歊，汗浥春衫上白毛。", "細葛含風常著看，此情猶勝舊綈袍。"]'),
('1e719d82-0095-4dcd-b6da-4dc00964b871','謝惠楮衾','謝枋得','宋','宋诗','song-poetry','','[]','吳宮金蹙鳳花綾，春暖熏籠換水沉。',32,'全唐诗/poet.song.230000.json','["吳宮金蹙鳳花綾，春暖熏籠換水沉。", "那似冰橋楮夫子，滿牀明月解微吟。"]'),
('d22bfe9e-6c61-4e9c-9de9-721f51b6a567','贈儒醫陳西巖','謝枋得','宋','宋诗','song-poetry','','[]','豬苓桔梗最爲奇，藥籠書囊用有時。',32,'全唐诗/poet.song.230000.json','["豬苓桔梗最爲奇，藥籠書囊用有時。", "莫把眼前窮達論，要知良相即良醫。"]'),
('2c0df890-cba4-4a68-bd45-e9776916ca97','桃','謝枋得','宋','宋诗','song-poetry','','["\u5199\u82b1", "\u5411\u5f80", "\u751f\u6d3b", "\u82b1"]','尋得桃源好避秦，桃紅又見一年春。',32,'全唐诗/poet.song.230000.json','["尋得桃源好避秦，桃紅又見一年春。", "花飛莫遣隨流水，怕有漁郎來問津。"]'),
('b99b4a75-954d-4306-babf-fdaa77046d69','覓茶','謝枋得','宋','宋诗','song-poetry','','[]','茂綠林中三五家，短牆半露小桃花。',32,'全唐诗/poet.song.230000.json','["茂綠林中三五家，短牆半露小桃花。", "客行馬上多春日，特扣柴門覓一茶。"]'),
('6be66ad2-2918-4002-a141-1cf100ae3a68','贈畫士劉信可二首  其一','謝枋得','宋','宋诗','song-poetry','','[]','毛穎摧鋒入墨池，白雲窗下展烏絲。',32,'全唐诗/poet.song.230000.json','["毛穎摧鋒入墨池，白雲窗下展烏絲。", "乘君袖裏孤山月，寫盡橫斜竹外枝。"]'),
('3bed5052-7948-423c-8b8a-9296fad7263e','贈畫士劉信可二首  其二','謝枋得','宋','宋诗','song-poetry','','[]','譜係庭筠出管城，胸中千畝盡秋清。',32,'全唐诗/poet.song.230000.json','["譜係庭筠出管城，胸中千畝盡秋清。", "兒童不悞揮毫意，閑傍虛簷聽雨聲。"]'),
('5552bf45-c6c4-4229-80d2-c8ec2e01e614','竹','謝枋得','宋','宋诗','song-poetry','','[]','新篁娟娟如綠玉，瀟然出塵澹無欲。',32,'全唐诗/poet.song.230000.json','["新篁娟娟如綠玉，瀟然出塵澹無欲。", "清風明月誰主張，留得此君在空谷。"]'),
('86398845-6dac-4de2-a7ea-e2671703896c','扇','謝枋得','宋','宋诗','song-poetry','','[]','蒲葵也解歸掌握，紈素未應捐篋中。',32,'全唐诗/poet.song.230000.json','["蒲葵也解歸掌握，紈素未應捐篋中。", "莫把暗塵涴明月，好驅大暑來清風。"]'),
('64394385-01b6-4dec-8087-cfc80ab60fac','菊','謝枋得','宋','宋诗','song-poetry','','[]','淵明豈但隠逸人，淵明素懷諸葛志。',32,'全唐诗/poet.song.230000.json','["淵明豈但隠逸人，淵明素懷諸葛志。", "清香不獨占秋天，菊潭一滴三千歲。"]'),
('ed55d6b6-4421-4091-9862-92726ef044a1','賦松','謝枋得','宋','宋诗','song-poetry','','[]','喬松磊磊多奇節，冬無霜雪夏無熱。',32,'全唐诗/poet.song.230000.json','["喬松磊磊多奇節，冬無霜雪夏無熱。", "根頭更有千歲苓，知誰可語長生訣。"]'),
('5ba6aa38-15ad-4fc1-809d-e79e157d9c25','與魏梅墅','謝枋得','宋','宋诗','song-poetry','','[]','義熙陶令書甲子，春秋仲尼尊天王。',32,'全唐诗/poet.song.230000.json','["義熙陶令書甲子，春秋仲尼尊天王。", "孔明漢賊不兩立，梁公十念臣而皇。"]'),
('bd6de969-8faa-480f-aef7-6f166c6fdbeb','花影','謝枋得','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u65e0\u5948", "\u6292\u6000", "\u548f\u7269", "\u5931\u610f"]','重重疊疊上瑶臺，幾度呼童掃不開。',32,'全唐诗/poet.song.230000.json','["重重疊疊上瑶臺，幾度呼童掃不開。", "剛被太陽收拾去，又教明月送將來。"]'),
('b962bdf0-215f-434e-8279-60f23acc3a5a','絕粒偶書二首  其一','謝枋得','宋','宋诗','song-poetry','','[]','丹府金童善主家，百神聽命靜無譁。',32,'全唐诗/poet.song.230000.json','["丹府金童善主家，百神聽命靜無譁。", "從今何必餐松柏，但吸日精吐月華。"]'),
('80a4f3a7-1201-4d18-a048-0044f69662d8','絕粒偶書二首  其二','謝枋得','宋','宋诗','song-poetry','','[]','龜啣甘露爭先到，鳳吸醴泉隨後來。',32,'全唐诗/poet.song.230000.json','["龜啣甘露爭先到，鳳吸醴泉隨後來。", "投在太清仙酒甕，道人日飲兩三杯。"]'),
('14a06b27-7086-430e-b6ff-9f92cf99fbf2','古詩贈相士吳楚峰','謝枋得','宋','宋诗','song-poetry','','[]','世亂異人出，高者爲神仙。',48,'全唐诗/poet.song.230000.json','["世亂異人出，高者爲神仙。", "方術皆救世，可知愚與賢。", "喜君風鑒別，妙處不可傳。", "著眼看福人，要識太平年。"]'),
('f7b1faf8-5a70-4e22-bf62-68ccc991b320','贈宋相士','謝枋得','宋','宋诗','song-poetry','','[]','墮甑看無益，乘軒計亦疏。',48,'全唐诗/poet.song.230000.json','["墮甑看無益，乘軒計亦疏。", "忍貧吾自解，過論子姑徐。", "但得耆而艾，飽觀詩與書。", "時乎一杯酒，此外儘從渠。"]'),
('f915dd81-71c2-43d6-b922-81b6c0e0e58c','求紙衾','謝枋得','宋','宋诗','song-poetry','','[]','避世知無地，危身只信天。',48,'全唐诗/poet.song.230000.json','["避世知無地，危身只信天。", "寧持龔勝扇，不著挺之綿。", "養性真同道，知心有宿緣。", "紙衾加惠絮，晴日卧雲邊。"]'),
('0678d2c2-5b48-4df3-b307-e14932072c07','贈相士郭少仙','謝枋得','宋','宋诗','song-poetry','','[]','崇蘭生深林，澹泊一點芳。',48,'全唐诗/poet.song.230000.json','["崇蘭生深林，澹泊一點芳。", "江梅倚修竹，醖藉萬斛香。", "氣骨抱金玉，精神貯冰霜。", "若以色見我，照紅還海棠。"]'),
('0a10d7ea-18a9-49d4-b31d-85f810394b1d','送張子高歸延平','謝枋得','宋','宋诗','song-poetry','','[]','亂世讀書少，前人教子難。',48,'全唐诗/poet.song.230000.json','["亂世讀書少，前人教子難。", "青燈嘗合席，紅葉趲歸鞍。", "梅自知春近，松應耐歲寒。", "樓高新月好，後夜與誰看。"]'),
('0b45ead8-4937-4e32-aa82-b13c822793af','送劉治中之信州','謝枋得','宋','宋诗','song-poetry','','[]','冰玉古溪山，治中今士元。',48,'全唐诗/poet.song.230000.json','["冰玉古溪山，治中今士元。", "邦人敬文簡，道化望曾孫。", "朱子書堂在，東萊講席存。", "十年儒道晦，此日喜登門。"]'),
('9a466307-e42a-4c96-8650-142010ef4c52','示兒二首  其一','謝枋得','宋','宋诗','song-poetry','','[]','門戶興衰不自由，樂天知命我無憂。',64,'全唐诗/poet.song.230000.json','["門戶興衰不自由，樂天知命我無憂。", "大兒安得孔文舉，生子何如孫仲謀。", "天上麒麟元有數，人間豚犬不須愁。", "養男不教父之過，莫視詩書如寇仇。"]'),
('2bd76678-8810-4d03-a25d-325ce16dfe7a','示兒二首  其二','謝枋得','宋','宋诗','song-poetry','','[]','千古興亡我盡知，一家消息又何疑。',64,'全唐诗/poet.song.230000.json','["千古興亡我盡知，一家消息又何疑。", "古來聖哲少才子，世亂英雄多義兒。", "靖節少陵能自解，孔明王猛使人悲。", "只虞錯改金根字，焉用城南勸學詩。"]'),
('0f19a926-87ac-4915-80ab-68e9d47e6c80','代上張經歷','謝枋得','宋','宋诗','song-poetry','','[]','中原自古多豪傑，晉國尤多賢大夫。',64,'全唐诗/poet.song.230000.json','["中原自古多豪傑，晉國尤多賢大夫。", "學問斷無虛議論，功名須有大規模。", "臂間弓矢真良將，舌底詩書笑腐儒。", "自恨兩賢相識晚，不妨杯酒恣歌呼。"]'),
('9792bc30-ff25-4150-98ae-3660a6082f0b','贈卜者魏易齋','謝枋得','宋','宋诗','song-poetry','','[]','伯陽曾著易參同，奪盡陰陽造化功。',64,'全唐诗/poet.song.230000.json','["伯陽曾著易參同，奪盡陰陽造化功。", "白玉五城人可到，黄金一鼎道無窮。", "先生救世心良苦，後派多才命必通。", "魏本大名名易顯，子明且爲筮江東。"]'),
('dc68b1c8-89fe-4d0d-ae30-e68db638fd8f','題東觀壁  其一','謝枋得','宋','宋诗','song-poetry','','[]','觀外好看船往回，觀中幾度見桃開。',64,'全唐诗/poet.song.230000.json','["觀外好看船往回，觀中幾度見桃開。", "常瞻紫氣青牛去，又带白雲黄鶴來。", "天地無情搔短髮，古今多變付殘杯。", "醉中尚有醒時眼，不信玉山人可推。"]'),
('85b9569d-7afd-4189-8920-1befbd72108b','題東觀壁  其二','謝枋得','宋','宋诗','song-poetry','','[]','老樹猶能識道回，好懷長對碧天開。',64,'全唐诗/poet.song.230000.json','["老樹猶能識道回，好懷長對碧天開。", "青山綠水何人管，明月清風要我來。", "少日曾聞黄石教，平生幾擲左慈杯。", "道兄慣見人間事，快抱棋枰信手推。"]'),
('dd82be84-5cba-419f-b620-c6ec69639d8c','和曹東谷韻','謝枋得','宋','宋诗','song-poetry','','[]','萬古綱常擔上肩，脊梁鐵硬對皇天。',64,'全唐诗/poet.song.230000.json','["萬古綱常擔上肩，脊梁鐵硬對皇天。", "人生芳穢有千載，世上榮枯無百年。", "此日識公知有道，何時與我詠遊仙。", "不爲蘇武即龔勝，萬一因行拜杜鵑。"]'),
('665f1091-5019-4f27-9731-ba6a6b3950e6','和葉愛梅韻','謝枋得','宋','宋诗','song-poetry','','[]','道逢患難正當行，禮食從來孰重輕。',64,'全唐诗/poet.song.230000.json','["道逢患難正當行，禮食從來孰重輕。", "綠鬢行藏堪檢點，白頭去就要分明。", "了知死別如龔勝，未必生還似子卿。", "緯地經天文不喪，許君獨擅大聲名。"]'),
('fc932bee-6225-44e8-901c-5fa73138ad36','和游古意韻','謝枋得','宋','宋诗','song-poetry','','[]','死易程嬰豈不知，十年死後未爲非。',64,'全唐诗/poet.song.230000.json','["死易程嬰豈不知，十年死後未爲非。", "文辭未必改秦甥，敲朴徒能抱御衣。", "無志何勞悲廟黍，得仁更不食山薇。", "儒冠有愧一廝養，何忍葵心對落暉。"]'),
('a1b2c8a1-a67b-42a1-b674-e67a13de3a26','和毛靜可韻','謝枋得','宋','宋诗','song-poetry','','[]','孟韓相慕久懸懸，恨不論詩早十年。',64,'全唐诗/poet.song.230000.json','["孟韓相慕久懸懸，恨不論詩早十年。", "吾道不行知有命，斯文將喪更由天。", "此生何恨爲龔勝，來世誰能知少連。", "不信無人扶宇宙，是邦豪傑已林然。"]'),
('e8a8455c-b014-4db1-a465-a223928a77ed','和詹蒼崖韻','謝枋得','宋','宋诗','song-poetry','','[]','八閩英傑盛如林，安得三忠存至今。',64,'全唐诗/poet.song.230000.json','["八閩英傑盛如林，安得三忠存至今。", "舊俗風流千載事，精忠大義一般心。", "早知平陸風波惡，何必巔崖雲霧深。", "此日脊梁非鐵硬，小顔拳爪定相侵。"]'),
('377e55a8-cfc2-4d03-9332-92a7b962af7d','初到建寧賦詩一首','謝枋得','宋','宋诗','song-poetry','','[]','雪中松柏愈青青，扶植綱常在此行。',64,'全唐诗/poet.song.230000.json','["雪中松柏愈青青，扶植綱常在此行。", "天下久無龔勝潔，人間何獨伯夷清。", "義高便覺生堪捨，禮重方知死甚輕。", "南八男兒終不屈，皇天上帝眼分明。"]'),
('68e7ae0c-71bb-47bc-aa8f-5cd67a198603','辭洞齋華父二劉兄惠寒衣','謝枋得','宋','宋诗','song-poetry','','[]','平生愛讀龔勝傳，進退存亡斷得明。',64,'全唐诗/poet.song.230000.json','["平生愛讀龔勝傳，進退存亡斷得明。", "范叔綈袍雖見意，大顛衣服莫留行。", "此時要看英雄樣，好漢應無兒女情。", "只願諸賢扶世教，餓夫含笑死猶生。"]'),
('3f551841-bf4e-4782-985d-f9918604e985','和道士陳天隠  其一','謝枋得','宋','宋诗','song-poetry','','[]','明知儒道本同流，未了因緣不自由。',64,'全唐诗/poet.song.230000.json','["明知儒道本同流，未了因緣不自由。", "紫府寥陽隨念到，紅塵辛苦幾時休。", "精神嘗與天來往，軀殻不知誰滯留。", "穹壤豈無陸修靜，知君認得故吾不。"]'),
('12be3d83-89bc-41dd-9e8e-2f969afd425c','和道士陳天隠  其二','謝枋得','宋','宋诗','song-poetry','','[]','豈不逍遥自采真，世間何地可容身。',64,'全唐诗/poet.song.230000.json','["豈不逍遥自采真，世間何地可容身。", "碧潭秋月元無物，麗日祥風只愛春。", "天上儘多知己友，塵中安得見心人。", "赤虬一躍蓬萊近，又恐丹丘有宿因。"]'),
('b2c9ef5f-47be-403a-b3c7-d818e32f7cce','和道士陳天隠  其三','謝枋得','宋','宋诗','song-poetry','','[]','學道無魔道不成，神人得計是無名。',64,'全唐诗/poet.song.230000.json','["學道無魔道不成，神人得計是無名。", "光風自覺長瀟灑，明月何曾有死生。", "早悟梅山難養性，何如福地別尋盟。", "梅花香裏堪聯句，莫笑人間石鼎鳴。"]'),
('a4a3de06-8c8c-4cad-a212-1a0e2e9891cf','謝劉純父惠木綿布','謝枋得','宋','宋诗','song-poetry','','[]','嘉樹種木綿，天何厚八閩。',288,'全唐诗/poet.song.230000.json','["嘉樹種木綿，天何厚八閩。", "厥土不宜桑，蠶事殊艱辛。", "木綿收千株，八口不憂貧。", "江東易此種，亦可致富殷。", "奈何來瘴癘，或者畏蒼旻。", "吾知饒信間，蠶月如岐邠。", "兒童皆衣帛，豈但奉老親。", "婦女賤羅綺，賣絲買金銀。", "角齒不兼與，天道斯平均。", "所以木綿利，不畀江東人。", "避秦衣木葉，矧肯羞懸鶉。", "天下有元德，孔融願卜鄰。", "綈袍望不及，共裘志自仁。", "贈我以兩端，物意皆可珍。", "潔白如雪積，麗密過綿純。", "羔縫不足貴，狐腋難擬倫。", "絺纊皆作貢，此物不薦陳。", "豈非神禹意，隠匿遺小民。", "詩多草木名，箋疏欲諄諄。", "國家無楚越，欲識固無因。", "剪裁爲大裘，窮冬勝三春。", "拜嘉重感激，觸物尤酸辛。", "吁嗟彼寒谷，鄒律今不神。", "三宮坐穹廬，雨雪或十旬。"]'),
('eac0bd7b-e41a-47ba-a5ce-1b53c51235ef','謝張四居士惠紙衾','謝枋得','宋','宋诗','song-poetry','','[]','何年擣玉楮，瑩潔無滓坌。',168,'全唐诗/poet.song.230000.json','["何年擣玉楮，瑩潔無滓坌。", "清興厭純綿，安有塵可振。", "夜卧白晝中，冰雪心不紊。", "夢覺梅花香，爐紅絕烟熅。", "疑到玉皇前，俯視日月暈。", "人間綺羅帳，何異錦覆糞。", "吾慕忍寒人，從師游魯鄰。", "爵祿不可辭，高舉已在汶。", "獨憐無褐民，茅簷凍欲僨。", "大裘正萬丈，德心欠廣運。", "天下皆無寒，孔孟有素藴。", "願與物爲春，衾鐵吾不慍。", "以君志趣高，惠我無俗韻。", "縞带報紵衣，僑札真契分。"]'),
('2800e5bc-8ba7-4000-804f-43fa38e295a2','謝人惠米線','謝枋得','宋','宋诗','song-poetry','','[]','玉粒百穀王，有功滿人寰。',156,'全唐诗/poet.song.230000.json','["玉粒百穀王，有功滿人寰。", "舂磨作瓊屑，飛雷落九關。", "翕張化瑶線，弦直又可彎。", "湯鑊海沸騰，玉龍自相扳。", "銀濤滾雪浪，出沒幾漩澴。", "有味勝湯餠，飫歌不愁癏。", "包裹數十里，瑩潔無點班。", "興師遠持糒，此物正可頒。", "千萬一日飽，不費金數鍰。", "長安權貴人，五鼎靳笑顔。", "玉食過九重，恨無土宇版。", "豈知有瓊糜，天雨到市闤。", "願獻空峒帝，馬迷龍難攀。"]'),
('61ed84a4-83a0-4343-9b19-1fea5478759b','謝人冬至送鴨酒','謝枋得','宋','宋诗','song-poetry','','[]','陽復且閉關，萬物畏坤含。',120,'全唐诗/poet.song.230000.json','["陽復且閉關，萬物畏坤含。", "雙鳬飛天外，鶩食何貪婪。", "儒道又一泰，十年亂愈餤。", "誰家讀書堂，庭階無青藫。", "此時談詩書，蓮經提魚籃。", "平生太玄文，知者無一譚。", "之子愛野鶩，驥駒舞兩驂。", "厚顔酒食饌，不獵懸鶉鵪。", "寒威甚毒矢，三杯勝七䤴。", "爛醉尋梅花，登峰吾尚堪。"]'),
('983db6ea-1c3e-4703-bc43-5978f3717e9d','乞醯','謝枋得','宋','宋诗','song-poetry','','[]','平生忍酸寒，鼻吸醋三斗。',216,'全唐诗/poet.song.230000.json','["平生忍酸寒，鼻吸醋三斗。", "先民耻乞字，乞醯良可醜。", "賣鷄買魚烹，鷄魚誰舍取。", "將爲水晶鱠，聊悅苦吟口。", "主人曰無醯，調和只宜酒。", "一夜嚴霜寒，池冰堅可扣。", "誰知酒不冰，流澌魚可走。", "旁觀粲然笑，易牙知此否。", "始知五味和，鹹酸必相有。", "提壺我有求，君甕肯發瓿。", "宿諾惠未來，望梅渴已久。", "似聞君釀醯，巧心出楊柳。", "楊柳屬他人，腸斷香山叟。", "舉瓢酌醯時，又憶玉纖手。", "一顧一心酸，淚珠滿翠袖。", "此亦人至情，何不告朋友。", "古人有乞漿，得酒意愈厚。", "又恐酒俱來，太歲正在酉。"]'),
('a48eb110-6f89-43b0-b257-4236ac0e0f90','謝黄禪師華嚴會供食','謝枋得','宋','宋诗','song-poetry','','[]','十兆九萬拜，求道心如惔。',120,'全唐诗/poet.song.230000.json','["十兆九萬拜，求道心如惔。", "毗盧頂上珠，直欲一手探。", "天厨送誰饌，衆腹豈敢貪。", "君有維摩心，作繭憐吳蠶。", "八萬四千供，只須丈室函。", "昔我聞晨鐘，今載草堂柟。", "流年急如梭，長歌愧仙藍。", "勇尋趙州關，何畏白髮鬖。", "願爲護法輪，金甲持長錟。", "又恐囘道人，晚遇黄龍南。"]'),
('66fa69b8-1b1c-4ced-abeb-f1f1b3c7cfd5','贈道士阮太虛何存齋','謝枋得','宋','宋诗','song-poetry','','[]','六道四生苦，何人不煩惱。',168,'全唐诗/poet.song.230000.json','["六道四生苦，何人不煩惱。", "官人自做官，道人自修道。", "相逢不下馬，各自尋蓬島。", "前生非親契，今生如何好。", "本來無因緣，安得有果報。", "來非人捉來，到是天送到。", "我若不呈醜，道教一齊倒。", "春風縛不住，秋月蝕愈皎。", "莫登時貴門，談天恨欠早。", "對面不相識，開口便激惱。", "譬如弄雜劇，徒取傍人笑。", "道我是風顛，知我已明了。", "莫愁我饑渴，天厨食自飽。", "真宰善解家，未敢與人道。"]'),
('16d59079-c433-455f-ba99-c77baddf388f','菖蒲歌','謝枋得','宋','宋诗','song-poetry','','[]','有石奇峭天琢成，有草夭夭冬夏青。',300,'全唐诗/poet.song.230000.json','["有石奇峭天琢成，有草夭夭冬夏青。", "人言菖蒲非一種，上品九節通仙靈。", "異根不带塵埃氣，孤操愛結泉石盟。", "明窗凈几有宿契，花林草砌無交情。", "夜深不嫌清露重，晨光疑有白雲生。", "嫩如秦時童女登蓬瀛，手携綠玉杖徐行。", "瘦如天台山上聖賢僧，休糧絕粒孤鶴形。", "勁如五百義士從田橫，英氣凜凜磨青冥。", "清如三千弟子立孔庭，回琴點瑟天機鳴。", "堂前不入紅粉意，席上常聽詩書聲。", "怪石篠簜皆充貢，此物舜廟當共登。", "神農知己入本草，靈均蔽賢遺騷經。", "幽人躭玩發仙興，方士服餌延修齡。", "綵鸞紫鳳琪花苑，赤虬玉麟芙蓉城。", "上界真人好清凈，見此靈苗當大驚。", "我欲携之朝太清，瑶草不敢專芳馨。", "玉皇一笑留香案，錫與有道者長生。", "人間千花萬草儘榮豔，未必敢與此草爭高名。"]'),
('42f5d7f5-e982-4256-bbc0-dadc6113fe6f','荆棘中杏花','謝枋得','宋','宋诗','song-poetry','','[]','牆東荒蹊抱村斜，荆棘狼籍盤根芽。',192,'全唐诗/poet.song.230000.json','["牆東荒蹊抱村斜，荆棘狼籍盤根芽。", "何年丹杏此留種，小紅濈濈爭春華。", "野人慣見謾不省，獨有詩客來咨嗟。", "天真不到鉛粉筆，富豔自是宮闈花。", "曲池芳逕非宿昔，蒼苔濁酒同天涯。", "京師惜花如惜玉，曉擔賣徹東西家。", "杏花看紅不看白，十日忙殺遊春車。", "誰家園裏有此樹，鄭重已著重幃遮。", "阿嬌新寵貯金屋，明妃遠嫁愁清笳。", "落花縈簾拂牀席，亦有飄泊沾泥沙。", "天公無心物自物，得意未用相陵誇。", "黄昏人歸花不語，惟有落月啼棲鴉。"]'),
('31ec3877-eb67-4d3c-8266-06208fa37afd','贈何古梅學醫','謝枋得','宋','宋诗','song-poetry','','[]','永州何仙藥最靈，神丸能潰邕州城。',320,'全唐诗/poet.song.230000.json','["永州何仙藥最靈，神丸能潰邕州城。", "廣西兩道再清平，百萬赤子荷更生。", "笙鶴一去三百年，東南忽變爲腥膻。", "爲血爲肉生靈苦，在者瘡痍何日痊。", "上界真人有同性，不學神仙學孔孟。", "有術醫國無人知，要爲吾民救微命。", "察脈肥瘠韓子精，論疾陰陽子産明。", "神功端不讓思邈，古道依然如宋清。", "得錢賣藥少取利，無錢乞藥喜捨施。", "好客來時入酒壚，無朋終日閲書市。", "憶昔民生三皇前，下壽無疾享百年。", "神人妙用不可見，本草靈素猶有傳。", "古云醫不通三書，世上斷不服其藥。", "如君胸中有炎黄，冷笑三書盡糟粕。", "我聞上帝最好生，活人功多朝玉京。", "請看岐叟至陶葛，神仙多是良醫成。", "東南干戈二十秋，人無貧富眉長愁。", "千人幸有一人在，到處呻吟無歌謳。", "遺黎若要家平康，但願良醫自天降。", "不龜手藥有靈時，好看良醫作良相。"]'),
('78a34387-a6d8-43a7-a0ae-be44356fdded','贈畫梅吳雪塢','謝枋得','宋','宋诗','song-poetry','','[]','冷凝寒極雪漫漫，天下無人知袁安。',176,'全唐诗/poet.song.230000.json','["冷凝寒極雪漫漫，天下無人知袁安。", "起來門前問梅竹，吾友可以話歲寒。", "歲寒心腸似鐵石，不與萬木同摧殘。", "有時醉中畫梅竹，洪鈞只在掌握間。", "人生莫與天爭巧，上帝一見開笑顔。", "八極俗物不足道，千年陳人無可觀。", "誰人奈得此雪過，春風去後終須還。", "千紅萬紫爭爛熳，梅竹携手隠空山。", "臯陶庭堅不祀苦，程嬰杵臼存孤難。", "豈無當門獨立者，五更風雪不相干。", "上帝慈仁須動念，醒來紅日上三竿。"]'),
('a972ec5c-be37-4100-95be-0d502ddaca7c','謝藥','謝枋得','宋','宋诗','song-poetry','','[]','雪深不能鑱黄精，天寒不能斸茯苓。',64,'全唐诗/poet.song.230000.json','["雪深不能鑱黄精，天寒不能斸茯苓。", "瑶草共食何日長，還丹獨鍊何時成。", "如來憐我似鶴形，指揮龍樹露神靈。", "佛無老死無生滅，何用勞我以長生。"]'),
('bbe224d1-0361-406c-8b9a-7410c1803124','謝惠椒醤等物  其一','謝枋得','宋','宋诗','song-poetry','','[]','堇荼易地味不甘，薑桂到老性愈辣。',64,'全唐诗/poet.song.230000.json','["堇荼易地味不甘，薑桂到老性愈辣。", "人言申椒能變化，我見苾芬終不滅。", "古來郊廟薦德馨，此物氣味通神明。", "開口一笑露眼睛，望君點化佛先成。"]'),
('0b2bc2fe-895d-4d22-a132-833695664459','謝惠椒醤等物  其二','謝枋得','宋','宋诗','song-poetry','','[]','孔子愛食蔬菜羹，羹中無醤必不食。',64,'全唐诗/poet.song.230000.json','["孔子愛食蔬菜羹，羹中無醤必不食。", "先生執醤饋高年，此味珍羞豈易得。", "瓶中有粟豈過望，誰憐陶令分嘉餉。", "喜君不作無髮人，免得東坡借擂醤。"]'),
('8957e0bb-c5b1-4499-bc96-ecf7f5db185d','謝麫','謝枋得','宋','宋诗','song-poetry','','[]','豐年自古說來牟，四月麥熟勝秋收。',64,'全唐诗/poet.song.230000.json','["豐年自古說來牟，四月麥熟勝秋收。", "天厨送食不待求，有麫䬪飥吾何憂。", "安得化身爲兒童，戲沙作麫可報答。", "授記或爲阿育王，請鑄八萬四千塔。"]'),
('a29e5ad8-d139-49e0-aee5-7a0d2616f238','崇真院絕粒偶書付兒熙之定之并呈張蒼峰劉洞齋華甫','謝枋得','宋','宋诗','song-poetry','','[]','西漢有臣龔勝卒，閉口不食十四日。',96,'全唐诗/poet.song.230000.json','["西漢有臣龔勝卒，閉口不食十四日。", "我今半月忍渴饑，求死不死更無術。", "精神常與天往來，不知飲食爲何物。", "若非功行積未成，便是業債償未畢。", "太清群仙宴會多，鳳簫龍笛鳴瑶瑟。", "豈無道兄相提携，騎龍直上寥天一。"]'),
('e1aa9139-6a23-4c0f-bf1e-a850ea3835ac','吾友張四居士爲僧敢獻善頌','謝枋得','宋','宋诗','song-poetry','','[]','天台羅漢形模，也學丹霞剗草。',28,'全唐诗/poet.song.230000.json','["天台羅漢形模，也學丹霞剗草。", "少年大振宗風，好箇五山長老。"]'),
('a42fab50-8949-4658-9f92-cd26db5e47ee','書林十景詩  其一','謝枋得','宋','宋诗','song-poetry','','[]','巍巍文筆光書林，插空屹地皆天成。',64,'全唐诗/poet.song.230000.json','["巍巍文筆光書林，插空屹地皆天成。", "尖齊不假雲烟斂，圓健何勞雨露深。", "椽墨太阿窺小醜，書天不動龍蛇走。", "何用蒙恬製作工，五色光芒煥星斗。"]'),
('8e53abfe-26d9-4032-9ccf-050df2475200','書林十景詩  其二','謝枋得','宋','宋诗','song-poetry','','[]','元君吳老皆昇真，民懷被德爲斯亭。',64,'全唐诗/poet.song.230000.json','["元君吳老皆昇真，民懷被德爲斯亭。", "和烟芳草連天碧，笑日仙花滿樹春。", "前後古陰迎蓊鬰，遠近琅玕森玉立。", "祥風靜定不見寒，鳳尾婆娑暄暖日。"]'),
('ef225ceb-4015-404a-86a1-a7016fa65d2c','書林十景詩  其三','謝枋得','宋','宋诗','song-poetry','','[]','雄峰馳驟萬馬奔，浮空積翠如崑崙。',64,'全唐诗/poet.song.230000.json','["雄峰馳驟萬馬奔，浮空積翠如崑崙。", "中有一蛙清且瘦，天成不假鑽鋤痕。", "神物深潛清徹底，霹靂電光生石齒。", "桃花飛雨三月紅，洶湧湖光漲春水。"]'),
('1dfeb245-0521-49b3-af59-b68a25b17080','書林十景詩  其四','謝枋得','宋','宋诗','song-poetry','','[]','携鋤鑿破南山雲，種來修竹凌青冥。',64,'全唐诗/poet.song.230000.json','["携鋤鑿破南山雲，種來修竹凌青冥。", "參天引風挺蒼玉，匝地印月篩黄金。", "清瘦何妨惟却俗，凈掃胸中塵萬斛。", "何當裁製十二個，吹作來儀鳳凰曲。"]'),
('12d6ccce-fbcf-4296-9975-175844ede336','書林十景詩  其五','謝枋得','宋','宋诗','song-poetry','','["\u897f\u6e56"]','岱嶂吞吐雲烟迷，山川獨勝東南奇。',64,'全唐诗/poet.song.230000.json','["岱嶂吞吐雲烟迷，山川獨勝東南奇。", "銀河倒瀉風雨急，玉龍交戰冰霜飛。", "巨流濺石駕空谷，仰望斯須突起粟。", "西湖不羨冷泉亭，爽利可人清興足。"]'),
('2b8ea8bb-482f-4e1a-8210-37a5c39a9b4c','書林十景詩  其六','謝枋得','宋','宋诗','song-poetry','','[]','路盤屈曲蛇行驚，嶺危崒嵂龜紋真。',64,'全唐诗/poet.song.230000.json','["路盤屈曲蛇行驚，嶺危崒嵂龜紋真。", "俯窺毛悚超宇宙，仰捫手得探星辰。", "斜陽墮塊硃砂魄，暮霞幾縷胭脂色。", "來朝海氣汎扶桑，擁出金輪光赫赫。"]'),
('e8f9d8f5-e174-498a-930a-0945a4e8d0d8','書林十景詩  其七','謝枋得','宋','宋诗','song-poetry','','[]','長虹跨陸登雲衢，會同海宇皆車書。',64,'全唐诗/poet.song.230000.json','["長虹跨陸登雲衢，會同海宇皆車書。", "日斜市潰夜喧息，月來雲靜天無疵。", "水劫金蟇形不槁，常生玉兔藥常搗。", "可憐滄海幾桑田，照耀古今人盡老。"]'),
('d1d4677d-2ba7-435f-800d-059622a58955','書林十景詩  其八','謝枋得','宋','宋诗','song-poetry','','[]','仰山梵剎萬竹間，巨鯨吼動天風寒。',64,'全唐诗/poet.song.230000.json','["仰山梵剎萬竹間，巨鯨吼動天風寒。", "前聲穿雲出山久，後音待月揮槌難。", "長短輕重知多少，斷續參差不奇偶。", "敲殘一百餘八聲，樹色糢糊落星斗。"]'),
('6d487588-2c96-4b09-a750-972ac3821d34','書林十景詩  其九','謝枋得','宋','宋诗','song-poetry','','[]','古陰寂寂人蹤稀，一泓凝碧環招提。',64,'全唐诗/poet.song.230000.json','["古陰寂寂人蹤稀，一泓凝碧環招提。", "洪音清韻係風雨，山鳴谷響聲遲遲。", "昧爽初分天欲曉，嵐氣升騰迷木杪。", "金烏鼓翼海色紅，爍醒林中正棲鳥。"]'),
('f95e058f-6337-4ef5-a984-a929ab779781','書林十景詩  其一○','謝枋得','宋','宋诗','song-poetry','','[]','朔風吹折寒梅枝，嚴凝凍合彤雲癡。',64,'全唐诗/poet.song.230000.json','["朔風吹折寒梅枝，嚴凝凍合彤雲癡。", "華峰屹立亙今古，堆累積聚皆昏迷。", "楊花飛舞盈三尺，蜨翅交加呈六出。", "朝陽發焰照乾坤，萬壑千崖消粉飾。"]'),
('53ab1c5a-67c5-489e-a01b-920f634ff425','蠶婦吟','謝枋得','宋','宋诗','song-poetry','','[]','子規啼徹四更時，起視蠶稠怕葉稀。',32,'全唐诗/poet.song.230000.json','["子規啼徹四更時，起視蠶稠怕葉稀。", "不信樓頭楊柳月，玉人歌舞未曾歸。"]'),
('b6c2c316-6369-4823-91ff-fade0cd10637','武夷山中','謝枋得','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u6885\u82b1", "\u5b8b\u8bd7", "\u8a00\u5fd7", "\u54c1\u683c"]','十年無夢得還家，獨立青峰野水涯。',32,'全唐诗/poet.song.230000.json','["十年無夢得還家，獨立青峰野水涯。", "天地寂寥山雨歇，幾生修得到梅花。"]'),
('5b2d9a07-90a3-4b5d-999e-39984cca0642','仙隠觀','謝枋得','宋','宋诗','song-poetry','','[]','秋日閒十日，面懷秋山空。',84,'全唐诗/poet.song.230000.json','["秋日閒十日，面懷秋山空。", "烟霞固常態，敗葉鋪山紅。", "平生五大夫，投老一禿翁。", "相看各蕭索，事付不語中。", "二輪固代謝，四季弭初終。", "義霜素悽慘，溫律復沖融。", "相期保歲寒，木末回春風。"]'),
('09525847-65db-4f4e-9f37-feb04fc9b0ac','送半村厲元吉出尉烏程','謝枋得','宋','宋诗','song-poetry','','[]','十二街頭三尺雪，駿馬健行如跛鼈。',112,'全唐诗/poet.song.230000.json','["十二街頭三尺雪，駿馬健行如跛鼈。", "生懷故人厲半村，拂袖前行何勇决。", "疊山居士强欲吟，凍筆如椎硯欲裂。", "京國青衫十載交，欲言不言情哽咽。", "願君勿作繞指柔，願君勿作在鑛鐵。", "甘雨幽遐冤草甦，清風宇宙貪泉竭。", "循良詎困聖明時，玉燭光華待調燮。"]'),
('a507f763-0721-4d3c-b091-71eaae53da44','題龜峰','謝枋得','宋','宋诗','song-poetry','','[]','三十二峰峰最高，脚踏高處真人豪。',64,'全唐诗/poet.song.230000.json','["三十二峰峰最高，脚踏高處真人豪。", "遠觀靈山一㟝嶁，俯視彭蠡無波濤。", "眼明始見滄海闊，心閒却憐人世勞。", "後百千年誰獨立，萬古一覽皆秋毫。"]'),
('66dedbd1-9dbe-4ee1-b272-e25c1bcad089','小孤山','謝枋得','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u6258\u7269\u8a00\u5fd7"]','人言此是海門關，海眼無涯駭衆觀。',64,'全唐诗/poet.song.230000.json','["人言此是海門關，海眼無涯駭衆觀。", "天地偶然留砥柱，江山有此障狂瀾。", "堅如勇士專場立，危比孤臣末世難。", "明日登峰須造極，渺觀宇宙我心寬。"]'),
('ebbdb539-501f-4924-94ed-cbc8fe1330ae','忠賢祠','謝枋得','宋','宋诗','song-poetry','','[]','正氣沖融自一家，宦情儒墨共根芽。',64,'全唐诗/poet.song.230000.json','["正氣沖融自一家，宦情儒墨共根芽。", "身因世故歸民社，道爲時謀重聖涯。", "千古寒光流夜月，滿天餘彩漾晴霞。", "殷勤瞻拜諸公側，送盡長林幾晚鴉。"]'),
('d1cc1efd-b618-4b85-8a84-5263aeb27985','蠶','謝枋得','宋','宋诗','song-poetry','','[]','養口資身頼以桑，終成王道澤流長。',64,'全唐诗/poet.song.230000.json','["養口資身頼以桑，終成王道澤流長。", "吐絲不羨蜘蛛巧，飼葉頻催織女忙。", "三起三眠時化運，一生一死命天常。", "待看獻繭盆繅後，先與吾皇織衮裳。"]'),
('09f859b3-db2d-4100-844e-be20a8cb0ffb','儒富莊  其一','謝枋得','宋','宋诗','song-poetry','','[]','一從孔氏去藏書，直至秦人不喜儒。',32,'全唐诗/poet.song.230000.json','["一從孔氏去藏書，直至秦人不喜儒。", "柱下老仙今有後，安知文不在茲乎。"]'),
('a237db65-30d0-4bfa-a7be-2b2142a86030','儒富莊  其二','謝枋得','宋','宋诗','song-poetry','','[]','東觀羣儒作好官，束書不許散人看。',32,'全唐诗/poet.song.230000.json','["東觀羣儒作好官，束書不許散人看。", "何時遂作西林友，讀得韓文熟已難。"]'),
('da8cea2c-d911-4908-90b2-d5dfb8281a0a','九宮山','謝枋得','宋','宋诗','song-poetry','','[]','真人何代結幽棲，累世奎光煥紫泥。',32,'全唐诗/poet.song.230000.json','["真人何代結幽棲，累世奎光煥紫泥。", "日月高奔黄道近，衡廬傍出玉繩低。"]'),
('ad8081e6-bfd4-41d3-9b22-9801b7aea94e','贈秋山道人','謝枋得','宋','宋诗','song-poetry','','[]','曬衣臺上草春深，天遣詩人近士林。',32,'全唐诗/poet.song.230000.json','["曬衣臺上草春深，天遣詩人近士林。", "宇宙中間千萬變，長歌收拾付閒心。"]'),
('c3960014-6bdc-4faf-8dbe-1d07973ac462','和李白潯陽紫極宮感秋','謝枋得','宋','宋诗','song-poetry','','[]','雨歇月明松，天碧光入竹。',96,'全唐诗/poet.song.230000.json','["雨歇月明松，天碧光入竹。", "好懷一時開，乾坤清可掬。", "相携塵外遊，此樂豈我獨。", "掃開松上雲，恐有鶴來宿。", "爽氣逼斗牛，何待蜀仙卜。", "獨憐天心勞，千歲幾剝復。", "滄海有紅塵，不見虛舟覆。", "問訊安期生，何年棗當熟。"]'),
('ccf60fb7-21c4-4686-9f81-2bd2f570c03f','自况','謝枋得','宋','宋诗','song-poetry','','[]','手撚琪花吹玉蕭，至人長與道逍遥。',32,'全唐诗/poet.song.230000.json','["手撚琪花吹玉蕭，至人長與道逍遥。", "黄雲白鶴無拘束，閒看吳兒弄晚潮。"]'),
('ba25b437-36f1-43c7-a38e-20ad448967d7','挂冠','謝枋得','宋','宋诗','song-poetry','','[]','玉皇殿下卸恩袍，羞見冥鴻惜羽毛。',64,'全唐诗/poet.song.230000.json','["玉皇殿下卸恩袍，羞見冥鴻惜羽毛。", "天地有心扶社稷，朝廷無意得英豪。", "早知骨鯁攖時忌，何似山林遁跡高。", "次第秋風到蘭菊，歸家痛飲讀離騷。"]'),
('726d0ebe-0a21-4e91-8797-f1a5d2abc730','窗間戲題','謝枋得','宋','宋诗','song-poetry','','[]','雲在青山自往還，鶴穿雲外上青天。',32,'全唐诗/poet.song.230000.json','["雲在青山自往還，鶴穿雲外上青天。", "雲來鶴去不相試，兩個無心莫結緣。"]'),
('b03e7124-c3e2-4d22-bb9f-f07303f494e5','題慶全庵  其一','謝枋得','宋','宋诗','song-poetry','','[]','蓮如君子甘離世，菊似逸民難出山。',32,'全唐诗/poet.song.230000.json','["蓮如君子甘離世，菊似逸民難出山。", "不信衆芳□寂寞，天香流出滿人間。"]'),
('b166040c-ab3d-4c87-9eeb-c44455b12fb5','題慶全庵  其二','謝枋得','宋','宋诗','song-poetry','','[]','長松落落多奇節，冬無雪霜夏無熱。',32,'全唐诗/poet.song.230000.json','["長松落落多奇節，冬無雪霜夏無熱。", "根頭更有千歲苓，知誰可語長生訣。"]'),
('8803d5ca-ef78-45d4-83ee-944c4263babf','賞牡丹  其一','謝枋得','宋','宋诗','song-poetry','','[]','蘭佩蓉裳骨相寒，山中何日鼎成丹。',32,'全唐诗/poet.song.230000.json','["蘭佩蓉裳骨相寒，山中何日鼎成丹。", "春深富貴花如此，一笑尊前醉眼看。"]'),
('948da459-8802-4343-af43-52fdd2c3f603','賞牡丹  其二','謝枋得','宋','宋诗','song-poetry','','[]','洛陽園裏草茵寒，夢想堯夫一寸丹。',32,'全唐诗/poet.song.230000.json','["洛陽園裏草茵寒，夢想堯夫一寸丹。", "安得根頭知上品，今人多是就花看。"]'),
('1e0e5ecf-409d-4510-afd3-feb84013ebe8','秦人洞','謝枋得','宋','宋诗','song-poetry','','[]','來避秦人萬事休，鳥啼花落幾春秋。',32,'全唐诗/poet.song.230000.json','["來避秦人萬事休，鳥啼花落幾春秋。", "洞門深鎖無人到，山自青青水自流。"]'),
('55b7a0f0-54c1-4633-9676-e13fd21c91c7','句','謝枋得','宋','宋诗','song-poetry','','[]','要知今日謝枋得，便是當年許月卿。',16,'全唐诗/poet.song.230000.json','["要知今日謝枋得，便是當年許月卿。"]'),
('3d48ccf5-3f12-460c-875a-487f718c0198','贈疊山先生','葉愛梅','宋','宋诗','song-poetry','','[]','后土茫茫兩屩行，綱常事重此身輕。',64,'全唐诗/poet.song.230000.json','["后土茫茫兩屩行，綱常事重此身輕。", "大江有士一人半，千載見君雙眼明。", "俯仰元無愧今古，英雄何必盡公卿。", "早知莫賣成都卜，省得人知大隠名。"]'),
('291ca6e9-00da-449b-a373-3a40390af718','贈疊山先生','游古意','宋','宋诗','song-poetry','','[]','滿腔忠孝有天知，不管人間事已非。',64,'全唐诗/poet.song.230000.json','["滿腔忠孝有天知，不管人間事已非。", "萬里乾坤雙草履，百年身世一麻衣。", "行藏自信床頭易，卧病惟餐隴首薇。", "儻過宗周見離黍，幾多新淚向殘暉。"]'),
('c28f3cce-d851-448f-81ad-e960a15f35b3','送疊山先生北行','謝枋得友','宋','宋诗','song-poetry','','[]','流落崎嶇二十年，幾回灑血杜鵑前。',64,'全唐诗/poet.song.230000.json','["流落崎嶇二十年，幾回灑血杜鵑前。", "一雙芒屨乾坤窄，萬古丹心日月懸。", "案上靈龜元不食，樊中孤鶴且安眠。", "逃名不得名終在，行止非人亦有天。"]'),
('5f7367c9-6586-451e-94dd-ed68e6ee90a0','輓疊山先生','趙簡邊','宋','宋诗','song-poetry','','[]','西山東海莫容身，芒履蕭蕭萬里塵。',64,'全唐诗/poet.song.230000.json','["西山東海莫容身，芒履蕭蕭萬里塵。", "去住更無寬歲月，死生惟有一君親。", "丹心故國江雲冷，白骨他鄉塞草青。", "不是回頭春已暮，至今猶說似癡人。"]'),
('177b4def-228a-4cbe-a22d-ffa47deda6d4','仲夏書事十首  其一','方回','宋','宋诗','song-poetry','','[]','園林夏宜曉，葉葉溜晴光。',48,'全唐诗/poet.song.230000.json','["園林夏宜曉，葉葉溜晴光。", "此地吾能淨，非天獨肯凉。", "汲泉看馬飲，剗草免蛇藏。", "似亦爲形役，終無市井忙。"]'),
('a232ced5-09fd-4b45-808c-4780f6713f60','仲夏書事十首  其二','方回','宋','宋诗','song-poetry','','[]','南風吹密樹，古屋隠林隈。',48,'全唐诗/poet.song.230000.json','["南風吹密樹，古屋隠林隈。", "捲畫防梅雨，鎸詩惜石苔。", "醫書鄰叟借，庵記野僧催。", "細省仍微笑，猶勝走俗埃。"]'),
('c8264dc5-dbae-4797-8aad-4c495be6299c','仲夏書事十首  其三','方回','宋','宋诗','song-poetry','','[]','幽居少四鄰，長日屬閒人。',48,'全唐诗/poet.song.230000.json','["幽居少四鄰，長日屬閒人。", "石氣常蒸霧，鶑聲不改春。", "子錢償未已，卯酒醉何頻。", "說與耘畦者，無錐未是貧。"]'),
('8e74b72b-a13a-45d3-93d3-815b1a71fdf4','仲夏書事十首  其四','方回','宋','宋诗','song-poetry','','[]','閒身何所事，詩外別無心。',48,'全唐诗/poet.song.230000.json','["閒身何所事，詩外別無心。", "但見獨危坐，焉知長苦吟。", "兵戈生長老，夢幻去來今。", "感慨亦徒爾，賓來酒且斟。"]'),
('62bdd37e-f48b-4166-aa39-33ed0643cdf7','仲夏書事十首  其五','方回','宋','宋诗','song-poetry','','[]','息擔秋云季，扶犁夏欲中。',48,'全唐诗/poet.song.230000.json','["息擔秋云季，扶犁夏欲中。", "園林初畏日，里巷只雌風。", "餠粥慳鱐脯，醯鹽劣韭葱。", "藕絲冰水舊，誰識少陵翁。"]'),
('bff64d57-9b20-4ca6-8c1f-c72be42eb2b6','仲夏書事十首  其六','方回','宋','宋诗','song-poetry','','[]','菜梜朝酲後，茶甌午困前。',48,'全唐诗/poet.song.230000.json','["菜梜朝酲後，茶甌午困前。", "入簾禽避彈，升竈蟻求羶。", "觀物因多感，謀生各務全。", "蠶登新麥賤，田叟荷皇天。"]'),
('cb72ab26-966d-4fa5-91a2-00cff302897b','仲夏書事十首  其七','方回','宋','宋诗','song-poetry','','[]','勁瘦元弘博，凄酸忽壯豪。',48,'全唐诗/poet.song.230000.json','["勁瘦元弘博，凄酸忽壯豪。", "爲詩兼衆體，此事屬吾曹。", "俗學三書虎，雄心六釣鼇。", "蘭枯菊猶短，不羨蜀葵高。"]'),
('58f31a95-c68f-408e-92cb-feb50ca4bcfe','仲夏書事十首  其八','方回','宋','宋诗','song-poetry','','[]','棄置乾坤事，歸休水竹居。',48,'全唐诗/poet.song.230000.json','["棄置乾坤事，歸休水竹居。", "不因徵急債，儘可讀殘書。", "虀糝畬田粟，薑羹石澗魚。", "論文同小酌，未覺故人疏。"]'),
('8c0cf834-c55e-40ba-8f20-40aaadff6a1d','仲夏書事十首  其九','方回','宋','宋诗','song-poetry','','[]','細酌浮菖酒，閒吟樹蕙文。',48,'全唐诗/poet.song.230000.json','["細酌浮菖酒，閒吟樹蕙文。", "賣符羞米賊，采藥按桐君。", "壬日近梅溽，午風生草薰。", "湖航三紀夢，荷蓋石榴裙。"]'),
('83e9ef5c-75d7-4cb2-9efb-91b66ae13b69','仲夏書事十首  其一○','方回','宋','宋诗','song-poetry','','[]','暑月憶寒月，老身兼病身。',48,'全唐诗/poet.song.230000.json','["暑月憶寒月，老身兼病身。", "簟誰分長物，酒併缺賢人。", "山市冰難致，家園蒜自珍。", "黄芽冷香飲，迴首歎揚塵。"]'),
('e9350136-0964-4703-bbca-5e3721fde479','贈地理齊君龍吉','方回','宋','宋诗','song-poetry','','[]','積善出公侯，今於葬地求。',48,'全唐诗/poet.song.230000.json','["積善出公侯，今於葬地求。", "樊崇如叵測，郭璞殆徒謀。", "折臂終難驗，控頤自可憂。", "未拋金鎖甲，焉問土饅頭。"]'),
('ef047f12-45bf-4c05-bc35-ae35c064874f','獨遊塘頭五首  其一','方回','宋','宋诗','song-poetry','','[]','納謁心全懶，紬書眼倍昏。',48,'全唐诗/poet.song.230000.json','["納謁心全懶，紬書眼倍昏。", "偶思行藥圃，獨往叩柴門。", "濕岸鳬梳羽，頹塍棗露根。", "元來好詩句，只在數家村。"]'),
('a6745f41-f1f6-4791-9363-71fddc5b53dd','獨遊塘頭五首  其二','方回','宋','宋诗','song-poetry','','[]','詩必城之外，胡爲不出城。',48,'全唐诗/poet.song.230000.json','["詩必城之外，胡爲不出城。", "漸逢人少處，初聽水流聲。", "異卉梔香釅，纖梢笋粉明。", "是中亦堪隠，浪出誤平生。"]'),
('5056c726-37bc-4ba1-9a49-498eb1a09d78','獨遊塘頭五首  其三','方回','宋','宋诗','song-poetry','','[]','蒲藕上塘種，養魚於下塘。',48,'全唐诗/poet.song.230000.json','["蒲藕上塘種，養魚於下塘。", "積泥春糞樹，儲水歲澆秧。", "未藉知章敕，堪浮逸少觴。", "掃松須憩此，繫馬古垂楊。"]'),
('302b8391-6359-4d6a-a8f6-25aea05901a0','獨遊塘頭五首  其四','方回','宋','宋诗','song-poetry','','[]','密樹窺青果，方塘數綠荷。',48,'全唐诗/poet.song.230000.json','["密樹窺青果，方塘數綠荷。", "久晴田水細，向晚野烟多。", "兀坐幾忘起，成詩費屢哦。", "歸鞍猶覺早，再欲叩煙蘿。"]'),
('01d02231-94f3-4aee-acc7-531a094dfe5b','獨遊塘頭五首  其五','方回','宋','宋诗','song-poetry','','[]','雊雉古原側，歸牛荒潦濱。',48,'全唐诗/poet.song.230000.json','["雊雉古原側，歸牛荒潦濱。", "炊煙已昏野，花氣更留人。", "剩欲培幽築，端容買近鄰。", "向來惟有夢，今此豈非真。"]'),
('458e2b59-a468-4250-8939-5605572054fc','五月十一日早問政山房三首  其一','方回','宋','宋诗','song-poetry','','[]','道士携壺酒，相迎勸瓦巵。',48,'全唐诗/poet.song.230000.json','["道士携壺酒，相迎勸瓦巵。", "野葩芳杖屨，林靄潤鬚眉。", "自說夜頻醉，不知朝有饑。", "問曾辟穀否，擘樹嚼松芝。"]'),
('f8609fa3-fb8d-4a5a-800f-c38be4fafedd','五月十一日早問政山房三首  其二','方回','宋','宋诗','song-poetry','','[]','四十里蒼翠，中環萬屈盤。',48,'全唐诗/poet.song.230000.json','["四十里蒼翠，中環萬屈盤。", "望城藏谷底，覓路上雲端。", "笋出一春醉，樵深三伏寒。", "山翁無將相，祇是敬黄冠。"]'),
('c6829a9f-9fc7-4218-84c1-cd8d79fc7ff9','五月十一日早問政山房三首  其三','方回','宋','宋诗','song-poetry','','[]','縱不燒丹汞，村人總是仙。',48,'全唐诗/poet.song.230000.json','["縱不燒丹汞，村人總是仙。", "今朝才酒債，明日有柴錢。", "指草能醫病，爭棋每讓先。", "活龍肯相贈，竹杖掘深鞭。"]'),
('7040a9fc-c338-4ccf-8234-249504f7f0b7','贈送李顯之','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君居予昔至，古鄆泰山隈。',120,'全唐诗/poet.song.230000.json','["君居予昔至，古鄆泰山隈。", "釣地盧泉美，帆天鉅野開。", "霸思齊相競，道感魯儒培。", "歷世傳微學，隨時産異才。", "稍窮南土勝，端爲北堂來。", "金錯傾求硯，斑衣戲捧杯。", "三春芍藥國，六代鳳凰臺。", "搜覽心應愜，題評句必瑰。", "暑風初綠稻，霖雨正黄梅。", "江路宜珍護，鵬程積漸催。"]'),
('70125faf-f0c8-47d7-bce0-3c29c1641a1d','梅雨連日五首  其一','方回','宋','宋诗','song-poetry','','[]','蓑笠千村外，乾坤五月中。',48,'全唐诗/poet.song.230000.json','["蓑笠千村外，乾坤五月中。", "若無梅子雨，焉得稻花風。", "深貯陂塘滿，交流畎澮通。", "還知周廩積，敢嘆阮途窮。"]'),
('7f3b1866-d7e4-4a3f-9c33-4e9e0fe28b22','梅雨連日五首  其二','方回','宋','宋诗','song-poetry','','[]','草樹加蒙密，波濤計渺冥。',48,'全唐诗/poet.song.230000.json','["草樹加蒙密，波濤計渺冥。", "似宜穿野屩，直與眺江亭。", "薪濕厨煙重，泥渾井汲腥。", "虛堂坐昏黑，時見一流螢。"]'),
('4d593b05-ccc5-4502-92ad-29c90e356bae','梅雨連日五首  其三','方回','宋','宋诗','song-poetry','','[]','雨應猶不止，終夕汗如湍。',48,'全唐诗/poet.song.230000.json','["雨應猶不止，終夕汗如湍。", "胡蝶魂才返，蒲牢韻已殘。", "身今栖歙谷，家尚寄嚴灘。", "江漲忽如許，乘流未覺難。"]'),
('98c45c96-5d7a-4176-b815-cae0081b821e','梅雨連日五首  其四','方回','宋','宋诗','song-poetry','','[]','驟駭寒成暑，難求簟換氈。',48,'全唐诗/poet.song.230000.json','["驟駭寒成暑，難求簟換氈。", "通身都是癢，徹曉竟無眠。", "鼠侮貓猶幼，蚊邀蚤共儇。", "順流日千里，便合上江船。"]'),
('5fccbeb3-c878-4b17-bf9d-0c2dbe3ec834','梅雨連日五首  其五','方回','宋','宋诗','song-poetry','','[]','豈不苦於雨，江昏水迫城。',48,'全唐诗/poet.song.230000.json','["豈不苦於雨，江昏水迫城。", "市民扃暗戶，軍婦哭空營。", "螢外無燈影，蛬邊有柝聲。", "百憂餘一喜，曉望稻畦平。"]'),
('047ca0a0-24b0-44aa-b2e0-e8fff0a31780','雨後','方回','宋','宋诗','song-poetry','','[]','荒園綠草長，無客到書堂。',48,'全唐诗/poet.song.230000.json','["荒園綠草長，無客到書堂。", "百尺轆轤冷，一林薝蔔香。", "杭書歸蠟屐，睦艇致藤牀。", "閒步復閒卧，身凉心更凉。"]'),
('76c0afea-514d-4144-9b8b-65a385ca1cec','次韻謝平心胡祕監見惠生日五首  其一','方回','宋','宋诗','song-poetry','','[]','晚生何敢跂前賢，夫子宮牆賜及肩。',64,'全唐诗/poet.song.230000.json','["晚生何敢跂前賢，夫子宮牆賜及肩。", "憶枉朝車十官宅，喜成鄰舍萬山巔。", "尚堪湖學生徒齒，恰少汾陽考第年。", "想得囊中有仙訣，形容枯槁但神全。"]'),
('c0e48f46-beb3-4530-93cf-680c22af0876','次韻謝平心胡祕監見惠生日五首  其二','方回','宋','宋诗','song-poetry','','[]','五朝遺老冠時賢，家祭猶無掩豆肩。',64,'全唐诗/poet.song.230000.json','["五朝遺老冠時賢，家祭猶無掩豆肩。", "文采春花洛陽苑，精神秋隼華峰巔。", "難兄共對三千字，晚境今開九十年。", "富貴朱門百雜碎，先生歸卧故廬全。"]'),
('d678c64f-afa5-42d2-b2b3-357b710bd41a','次韻謝平心胡祕監見惠生日五首  其三','方回','宋','宋诗','song-poetry','','[]','勢途勇退似差賢，焉用鴻門切盾肩。',64,'全唐诗/poet.song.230000.json','["勢途勇退似差賢，焉用鴻門切盾肩。", "早賜輼輬埋厚夜，寧扶楖栗走荒巔。", "泥龜不羨鵾鵬路，糞菌徒輸栝柏年。", "我謂是身如尺璧，深藏短褐庶能全。"]'),
('650e27e5-29f3-4d54-8e31-07db068cc8f8','次韻謝平心胡祕監見惠生日五首  其四','方回','宋','宋诗','song-poetry','','[]','酒可吾中孰聖賢，定開愁眼聳吟肩。',64,'全唐诗/poet.song.230000.json','["酒可吾中孰聖賢，定開愁眼聳吟肩。", "共憐雪鬢雙垂叟，時到花屏萬仞巔。", "暫借松陰消永日，敢求藥訣覬長年。", "風驚塵愕奔車跌，醒者蒼黄醉者全。"]'),
('8e5bae11-9477-48d9-aa0f-57127deb1515','次韻謝平心胡祕監見惠生日五首  其五','方回','宋','宋诗','song-poetry','','[]','風追電逐角材賢，我獨從公息擔肩。',64,'全唐诗/poet.song.230000.json','["風追電逐角材賢，我獨從公息擔肩。", "野曠杖藜臨絕景，山寒采梠度層巔。", "淡湯煮飯身無病，小秤收租歲有年。", "臭橐腐倉死兵火，何如清節保生全。"]'),
('7dfc7e0e-c7ef-4ede-83b4-5c4ab6c35233','出馬家塢','方回','宋','宋诗','song-poetry','','[]','野逈夏無暑，塢深朝更凉。',48,'全唐诗/poet.song.230000.json','["野逈夏無暑，塢深朝更凉。", "路隨流水轉，山背古城荒。", "縣宇欹紅閣，僧庵缺粉牆。", "暗驚兵亂後，猶有數蓮塘。"]'),
('5bd149ae-5f14-43a5-9372-6e20acfb29de','白水寺','方回','宋','宋诗','song-poetry','','[]','壁畫暗金剛，無人犬吠堂。',48,'全唐诗/poet.song.230000.json','["壁畫暗金剛，無人犬吠堂。", "翠苔千古潤，玉水一尋方。", "塵路雲蒸火，陰林石凝霜。", "仙凡元不遠，咫尺異炎凉。"]'),
('14ebd779-4be8-4056-8b8d-dc26d00e66ac','坐白水寺門亭','方回','宋','宋诗','song-poetry','','[]','百病今朝愈，城南野寺濱。',48,'全唐诗/poet.song.230000.json','["百病今朝愈，城南野寺濱。", "石崖陰欲凍，沙路瑩無塵。", "松老枝垂地，溪清水見人。", "僧瓶送煎茗，泉冽味尤新。"]'),
('13d05e54-9691-41e1-b954-1227bb9cc4b2','次韻汪翔甫讀予詩稿見寄二首  其一','方回','宋','宋诗','song-poetry','','[]','我詩蒯侯劍，玉具謝華裝。',48,'全唐诗/poet.song.230000.json','["我詩蒯侯劍，玉具謝華裝。", "老矣三荒徑，悠哉一瓣香。", "漫垂船子釣，懶下趙州牀。", "忽憶高軒過，仙巾戴華陽。"]'),
('f840731a-4bfa-45a1-a462-edd7518d2c5f','次韻汪翔甫讀予詩稿見寄二首  其二','方回','宋','宋诗','song-poetry','','[]','十年兵甲夢，投老卸戎裝。',48,'全唐诗/poet.song.230000.json','["十年兵甲夢，投老卸戎裝。", "有藥醫詩病，無花惱夢香。", "書明螢度几，簟冷竹遮牀。", "屬與公携酒，蹉跎換歲陽。"]'),
('66decc01-6b56-48e3-bd99-81f02907c427','次韻汪翔甫和西城呂全州見過四首  其一','方回','宋','宋诗','song-poetry','','[]','想見花間路，籃舁草草裝。',48,'全唐诗/poet.song.230000.json','["想見花間路，籃舁草草裝。", "叩門馴犬喜，入室蠹魚香。", "躡石苔粘屐，眠松露滴牀。", "焉知人世事，積甲又宜陽。"]'),
('23edb20d-d667-4692-9a53-ccf082405915','次韻汪翔甫和西城呂全州見過四首  其二','方回','宋','宋诗','song-poetry','','[]','聞道過從地，衣冠異俗裝。',48,'全唐诗/poet.song.230000.json','["聞道過從地，衣冠異俗裝。", "小孫迎勸酒，後院出行香。", "賈客珠量斗，侯家笏滿牀。", "未如耆舊輩，龐馬隠襄陽。"]'),
('08d4913a-4556-41a0-b273-55a45d2ff5d0','次韻汪翔甫和西城呂全州見過四首  其三','方回','宋','宋诗','song-poetry','','[]','五鼎封君食，千金奉使裝。',48,'全唐诗/poet.song.230000.json','["五鼎封君食，千金奉使裝。", "儻來皆外物，不朽有真香。", "滿酌聖賢酒，虛爭上下牀。", "細思諸葛事，只合卧南陽。"]'),
('2de3d3c0-39f9-42da-bfd8-77f737d7bc01','次韻汪翔甫和西城呂全州見過四首  其四','方回','宋','宋诗','song-poetry','','[]','驟見纍侯印，遄聞趣相裝。',48,'全唐诗/poet.song.230000.json','["驟見纍侯印，遄聞趣相裝。", "相期終古事，未用暫時香。", "清論玉霏麈，高眠雷撼牀。", "前魚又堪笑，紅袖泣龍陽。"]'),
('2449f405-ecd7-4906-bedb-bf5bfd59914e','七月初一日晚大惡風而雨','方回','宋','宋诗','song-poetry','','[]','焦原沸澤火雲紅，忽變煤炲漆暮空。',64,'全唐诗/poet.song.230000.json','["焦原沸澤火雲紅，忽變煤炲漆暮空。", "定謫毒龍移舊穴，併驅奇鬼助狂風。", "落泥朱實爭殘果，劈瓦青株惜半桐。", "審雨堂中知是夢，未須豪橫詫衰翁。"]'),
('8ded693e-895b-4548-b108-07f3a68a6577','寄題佛智忠禪師實庵  其一','方回','宋','宋诗','song-poetry','','[]','皴皮槁項換兒童，依舊恒河見性同。',64,'全唐诗/poet.song.230000.json','["皴皮槁項換兒童，依舊恒河見性同。", "作繭蠶寧長戀葉，蛻形蟬待別嘶風。", "雙趺可逐茶毗盡，隻履誰知窣堵空。", "設土饅頭誑人眼，新羅鷂子過天東。"]'),
('432f4182-b98a-4fb7-b76e-543fb4878d78','寄題佛智忠禪師實庵  其二','方回','宋','宋诗','song-poetry','','[]','實翁大笑笑虛翁，自闢新庵地幾弓。',64,'全唐诗/poet.song.230000.json','["實翁大笑笑虛翁，自闢新庵地幾弓。", "萬事我俱捐墮甑，百年公已辦幽宮。", "恢張遠算遺身後，跳脫迷魂出夢中。", "智了愚冥莫分別，乾坤黄落一秋風。"]'),
('bda4b956-d096-4ad6-8c27-df7931f02ea5','暑中閒詠六首  其一','方回','宋','宋诗','song-poetry','','[]','解轡去秋杪，牆垣翳藋蒿。',48,'全唐诗/poet.song.230000.json','["解轡去秋杪，牆垣翳藋蒿。", "荷鋤今夏半，籬落熟瓜桃。", "道左門常掩，兵餘井未淘。", "向來手親種，唯喜一桐高。"]'),
('cb929446-a9da-48f5-954a-86be92b6eeae','暑中閒詠六首  其二','方回','宋','宋诗','song-poetry','','[]','驚奔萬馬屯，豈料此身存。',48,'全唐诗/poet.song.230000.json','["驚奔萬馬屯，豈料此身存。", "長日唯三飯，閒時或一樽。", "泉深添井索，果熟閉園門。", "老病更炎熱，收心此避喧。"]'),
('d047bbf5-8180-45f1-9205-c43e21fd1b37','暑中閒詠六首  其三','方回','宋','宋诗','song-poetry','','[]','能靜何憂暑，惟慳足禦貧。',48,'全唐诗/poet.song.230000.json','["能靜何憂暑，惟慳足禦貧。", "每圓欹枕夢，不記剖符身。", "僧熟頻求字，僮頑自澣巾。", "林間坐磐石，山畔駐行人。"]'),
('b19df080-9d43-4fe7-ada9-eabf40e51901','暑中閒詠六首  其四','方回','宋','宋诗','song-poetry','','[]','謂我無憂者，其誰會此心。',48,'全唐诗/poet.song.230000.json','["謂我無憂者，其誰會此心。", "乾坤今古事，歲月短長吟。", "井冷增瓜味，軒晴表樹陰。", "樽中適有酒，聊與客同斟。"]'),
('0f452256-eadd-417d-ba5f-be268a7d2133','暑中閒詠六首  其五','方回','宋','宋诗','song-poetry','','[]','嘆息歸來晚，園林亦自都。',48,'全唐诗/poet.song.230000.json','["嘆息歸來晚，園林亦自都。", "疏篁新茁笋，乳燕倍添雛。", "喜雨詩成軸，看山畫作圖。", "醤醯資豆麥，伏近笑無儲。"]'),
('71de082b-834b-44fc-9936-ee314e52a9d1','暑中閒詠六首  其六','方回','宋','宋诗','song-poetry','','[]','籬門矮復斜，烏桕發枯槎。',48,'全唐诗/poet.song.230000.json','["籬門矮復斜，烏桕發枯槎。", "曾守諸侯土，還同百姓家。", "葛囊懸苣子，梅鹵漬梔花。", "臧獲修時事，分衣缺布紗。"]'),
('d0ff5bac-8b44-4ea2-b43d-a50a06dfff4e','六月雨','方回','宋','宋诗','song-poetry','','[]','六月今年雨，千山每日雲。',48,'全唐诗/poet.song.230000.json','["六月今年雨，千山每日雲。", "稻登全可望，樹密最宜聞。", "預免憂饑色，先收破暑勳。", "稍容驕蛤黽，且爲屏蠅蚊。"]'),
('f1710e2b-d0c3-4cee-8100-5d18f63d8394','又雨','方回','宋','宋诗','song-poetry','','[]','霞紅疑太早，果不是晴天。',48,'全唐诗/poet.song.230000.json','["霞紅疑太早，果不是晴天。", "市漲危侵戶，村流喜入田。", "昏昏鄰寺鼓，滃滃晚厨煙。", "明日應猶雨，宵甜一枕眠。"]'),
('9221f885-4691-4fe9-8e7a-bc887e2c9e8f','急雨','方回','宋','宋诗','song-poetry','','[]','極熱方亭午，濃陰忽半空。',48,'全唐诗/poet.song.230000.json','["極熱方亭午，濃陰忽半空。", "衆蟬瘖急雨，獨鷂攧高風。", "過濕蔬爭綠，矜晴果驟紅。", "樹凉宜就飲，殘滴入樽中。"]'),
('c6656a07-d154-40d2-95c8-1056ce6f25c6','六月半屢雨','方回','宋','宋诗','song-poetry','','[]','甘雨作豐年，尤宜近伏天。',48,'全唐诗/poet.song.230000.json','["甘雨作豐年，尤宜近伏天。", "水無過大海，旱不救良田。", "六月茅簷滴，千村飯竈煙。", "山城秋意早，新粒市香秈。"]'),
('b1d3a0c4-d236-4f2f-98da-71ba98e7065f','六月二十日雨','方回','宋','宋诗','song-poetry','','[]','天憐野老饑，初不待人祈。',48,'全唐诗/poet.song.230000.json','["天憐野老饑，初不待人祈。", "雷與奔騰驟，煙兼映带微。", "已拚泥弊屣，更喜滴單衣。", "暗想田塍上，禾秋蚱蜢飛。"]'),
('62dcbeb1-7954-4249-ad0d-62e659d6157e','雨後','方回','宋','宋诗','song-poetry','','[]','重濕抖筠籠，追凉滌瓦鍾。',48,'全唐诗/poet.song.230000.json','["重濕抖筠籠，追凉滌瓦鍾。", "乏香嫌婢索，得酒頼兒供。", "紙潤剪彌鈍，墨膠書不濃。", "幽齋雨中詠，寄遠意還慵。"]'),
('c715d684-17fb-46e7-9ca5-6fe0e34a1f1d','次韻程以忠同飲  其一','方回','宋','宋诗','song-poetry','','[]','飲濕自嫌無聖酒，摘鮮猶幸有真茶。',64,'全唐诗/poet.song.230000.json','["飲濕自嫌無聖酒，摘鮮猶幸有真茶。", "艱危昔偶分侯竹，老病今還齕庶瓜。", "已約社鷗盟水石，尚驚征馬困風沙。", "醉人不管傍人笑，瘦影伶俜亂鬢髿。"]'),
('fc695d88-2b12-4416-b49a-0e5a19495b79','次韻程以忠同飲  其二','方回','宋','宋诗','song-poetry','','[]','風雲變化世常有，丘壑盤旋誰與同。',64,'全唐诗/poet.song.230000.json','["風雲變化世常有，丘壑盤旋誰與同。", "駕馭孟嘉真得勢，滑稽方朔浪言工。", "律嚴詩友何妨少，租薄秋田亦幸豐。", "兩手搔頭指欲禿，猶堪舉酒吸長虹。"]'),
('293a5110-038f-4345-b6e5-a46a631f29d4','三十年重到紫陽觀','方回','宋','宋诗','song-poetry','','[]','石路崎嶇喚渡船，松蘿穿盡望中煙。',64,'全唐诗/poet.song.230000.json','["石路崎嶇喚渡船，松蘿穿盡望中煙。", "繆爲白髪二千石，輕別紫陽三十年。", "洞冷斂心歸酒地，閣虛携眼上詩天。", "丹砂九轉猶多事，解飲能吟即是仙。"]'),
('e7adcb5a-e6f8-45af-a4e4-42ac310e3192','次韻張文煥慵庵萬山堂即事二首  其一','方回','宋','宋诗','song-poetry','','[]','張侯詩思湧如泉，吟榻橫陳翠麓巔。',64,'全唐诗/poet.song.230000.json','["張侯詩思湧如泉，吟榻橫陳翠麓巔。", "十雨五風今樂國，千村萬落幾人煙。", "賞心眺覽知何算，轉首音塵竟弗傳。", "句勒口碑天共遠，不虛佳月佐觥船。"]'),
('a3f2a1fa-848e-41e6-a660-371bedb92731','次韻張文煥慵庵萬山堂即事二首  其二','方回','宋','宋诗','song-poetry','','[]','新晴鐘鼓暮樓臺，人與清空兩不埃。',64,'全唐诗/poet.song.230000.json','["新晴鐘鼓暮樓臺，人與清空兩不埃。", "日已頓無宣子畏，雲應全爲退之開。", "夜凉河漢牛初渡，秋爽關山雁欲來。", "好向豐年作張主，未須松鼎煮丹胎。"]'),
('f8e37889-efaa-4db5-993a-78f76a81d6cc','次韻張慵庵立秋有懷','方回','宋','宋诗','song-poetry','','[]','西風一葉未爲稠，積雨寒添客思秋。',64,'全唐诗/poet.song.230000.json','["西風一葉未爲稠，積雨寒添客思秋。", "試以物情觀燕壘，可無心事寄菟裘。", "硯何堪辦三錢水，竹豈能踰十稔樓。", "真是先生有歸興，不應如我雪盈頭。"]'),
('a8869405-a938-4a2c-b3ff-fce11b6b8f34','次韻張慵庵言別就送','方回','宋','宋诗','song-poetry','','[]','屢陪幽話探玄關，虛往無何已實還。',64,'全唐诗/poet.song.230000.json','["屢陪幽話探玄關，虛往無何已實還。", "遠眺每窮千里外，佳吟時見一聯間。", "致身霄漢名方起，回首林泉意欲閒。", "聞說姑溪卜新築，會須容訪郭青山。"]'),
('c9ff8be3-b3c9-4de6-a261-9152ec7ee2a2','送慵庵不及用韻奉寄','方回','宋','宋诗','song-poetry','','[]','東城追迹過西關，橋上紛紛送客還。',64,'全唐诗/poet.song.230000.json','["東城追迹過西關，橋上紛紛送客還。", "携酒踟躕才水次，鳴珂躞蹀已雲間。", "摘茶貿食民尤窶，掘蕨燒畬土不閒。", "細爲明時問疲俗，往來亦足當游山。"]'),
('dc6d9852-c82c-4c3b-bd6d-d40bad0ba3f2','送李杍黟縣  其一','方回','宋','宋诗','song-poetry','','[]','黟縣小桃川，年來異昔年。',48,'全唐诗/poet.song.230000.json','["黟縣小桃川，年來異昔年。", "民間何所苦，兵後最堪憐。", "石墨湮深井，秋秔斸廢田。", "喜聞新令尹，清白有家傳。"]'),
('55b56ecf-7f1a-4cfe-b109-ba3ff0fe33ce','送李杍黟縣  其二','方回','宋','宋诗','song-poetry','','[]','邑貧風俗儉，君去共弦歌。',48,'全唐诗/poet.song.230000.json','["邑貧風俗儉，君去共弦歌。", "持己心宜肅，臨民色要和。", "寒儒尤可念，巨室已無多。", "好與諸耆舊，商量細撫摩。"]'),
('d51a8ba6-1cfb-4858-a516-8795e977e899','送張慵庵','方回','宋','宋诗','song-poetry','','[]','南望閩浙北望淮，山水江東此郡佳。',64,'全唐诗/poet.song.230000.json','["南望閩浙北望淮，山水江東此郡佳。", "眼有一塵辜眺覽，腹無千古費安排。", "剪刀鋒快雲裁句，練带溪長月繫懷。", "獨見張侯富才思，不同餘子醉金釵。"]'),
('f9397ef1-daeb-4dab-9810-78ec6d4c8ab8','次韻謝李寅之鄂渚見寄  其一','方回','宋','宋诗','song-poetry','','[]','龍沙象徼各行役，漢樹江雲頻寄詩。',64,'全唐诗/poet.song.230000.json','["龍沙象徼各行役，漢樹江雲頻寄詩。", "政爾一天心不隔，其如兩地夢相思。", "投簪得謝今無事，命駕尋盟會有時。", "未愛鏡湖矜敕賜，更能宣室對神釐。"]'),
('4cbc26fc-5ec6-4401-9d9b-ec3b803a7e9d','次韻謝李寅之鄂渚見寄  其二','方回','宋','宋诗','song-poetry','','[]','叩戶驚傳千里使，開緘快覩七言詩。',64,'全唐诗/poet.song.230000.json','["叩戶驚傳千里使，開緘快覩七言詩。", "古希年迫公猶健，不仕風高我所思。", "兒大知書聊慰意，家貧食粥亦隨時。", "邇來稍喜休兵革，賽社秋場醊祭釐。"]'),
('07c9f646-db9c-4493-9bac-aa8f65cab937','八月初一日','方回','宋','宋诗','song-poetry','','[]','秋風幾日尚無詩，政坐炎歊轉赫曦。',64,'全唐诗/poet.song.230000.json','["秋風幾日尚無詩，政坐炎歊轉赫曦。", "閒被貧爲魔攪撓，病須凉當藥醫治。", "薄田董穫收新粟，老圃開包獻巨梨。", "顧此亦差勝窮宦，迴頭何啻十年遲。"]'),
('c45c7ce0-f9a8-471a-b5d7-9c8c85ab6a3c','八月初二日','方回','宋','宋诗','song-poetry','','[]','蟬聲漸漸怯西風，閒撚青枝玩菊叢。',64,'全唐诗/poet.song.230000.json','["蟬聲漸漸怯西風，閒撚青枝玩菊叢。", "老去一身都是病，寤來萬夢總成空。", "喜分果餌小兒女，浪費薪蔬頑僕僮。", "嚴瀨家人報船至，更營樽酒惱衰翁。"]'),
('b7e17c80-7ecf-4e8a-9d6e-488532963a7b','次韻汪以南教授美康使君新政因及賤迹四首  其一','方回','宋','宋诗','song-poetry','','[]','吾州今歲得儒臣，坐鎮浮澆力萬鈞。',64,'全唐诗/poet.song.230000.json','["吾州今歲得儒臣，坐鎮浮澆力萬鈞。", "月榭風臺尋古迹，煙畦雨隴勞遺民。", "長庚往往詩無敵，子美云云筆有神。", "老懶未遑致三請，低回祇欲老垂綸。"]'),
('f0de3147-ac89-4c0f-8a2f-d7201dfeb1f5','次韻汪以南教授美康使君新政因及賤迹四首  其二','方回','宋','宋诗','song-poetry','','[]','潰蟻狂瀾拔地來，日多事變少人才。',64,'全唐诗/poet.song.230000.json','["潰蟻狂瀾拔地來，日多事變少人才。", "鼎鐘古篆盲誰識，布素輕縑拙易裁。", "夷甫風流空自命，子山詞賦有餘哀。", "邦侯博雅難酬對，且向筵前覆酒杯。"]'),
('713648ee-6772-4189-ac74-db1295ed46bd','次韻汪以南教授美康使君新政因及賤迹四首  其三','方回','宋','宋诗','song-poetry','','[]','漢廷久已推三傑，魯國終難致兩生。',64,'全唐诗/poet.song.230000.json','["漢廷久已推三傑，魯國終難致兩生。", "雲雨蛟龍真有勢，風霜草木易無情。", "小遲玉璽徵黄霸，定許青門老邵平。", "勇據臯比作歌頌，依稀駉駜似難賡。"]'),
('3f9a1033-0021-4c02-9f2c-2eacddfe548a','次韻汪以南教授美康使君新政因及賤迹四首  其四','方回','宋','宋诗','song-poetry','','[]','石壁峰前舊泮林，新培槐市綠成陰。',64,'全唐诗/poet.song.230000.json','["石壁峰前舊泮林，新培槐市綠成陰。", "川流决潰終歸海，木德迴環會守心。", "夷軌得朋殊未艾，長謠懷感抑何深。", "矧伊色笑逢民則，好續當年蹻蹻吟。"]'),
('5041bac1-d341-4eaf-8aa5-f9208ef8f3b9','八月十二夜對月','方回','宋','宋诗','song-poetry','','[]','胡牀正面紫陽山，淨掃晴階掩夜關。',64,'全唐诗/poet.song.230000.json','["胡牀正面紫陽山，淨掃晴階掩夜關。", "金氣漸寒風露下，冰輪欲滿斗牛間。", "衰懷突兀來千感，暮齒逍遥保一閒。", "天役萬形仍自役，何爲西墮又東還。"]'),
('654689ee-a51a-4fb8-b96c-0e83eb23fff5','八月十五夜對月','方回','宋','宋诗','song-poetry','','[]','散髪披襟一再窺，未甘兀兀守書癡。',64,'全唐诗/poet.song.230000.json','["散髪披襟一再窺，未甘兀兀守書癡。", "月圓照盡天圓處，秋半凉當夜半時。", "人世無燈方作夢，山翁有酒更能詩。", "此心除却嫦娥外，惟許崚嶒瘦影知。"]'),
('356c1a5e-5e06-4505-927b-63b321ca5347','次韻僧自文見贈四首  其一','方回','宋','宋诗','song-poetry','','[]','去思無德政，豈有吏民碑。',48,'全唐诗/poet.song.230000.json','["去思無德政，豈有吏民碑。", "家乏千頭橘，官羞七尺蓍。", "樵蹊談野史，茗榻和僧詩。", "是事山中好，歸來始得知。"]'),
('19af6d24-45c6-4cb8-b8e5-b09a2f1d306b','次韻僧自文見贈四首  其二','方回','宋','宋诗','song-poetry','','[]','浪說揚州鶴，居多薦福碑。',48,'全唐诗/poet.song.230000.json','["浪說揚州鶴，居多薦福碑。", "聽師無孔笛，棄我不靈蓍。", "冷閲人間事，閒題物外詩。", "修行真有力，肯被鬼神知。"]'),
('47cce6df-d508-44d9-9cd8-157e6355dbc2','次韻僧自文見贈四首  其三','方回','宋','宋诗','song-poetry','','[]','空庭風捲葉，壞廡雨淋碑。',48,'全唐诗/poet.song.230000.json','["空庭風捲葉，壞廡雨淋碑。", "起廢須成厦，占孚預擊蓍。", "紅樓追曩集，碧落待誰詩。", "非有鈎牽□，□□亦未知。"]'),
('526fcc40-508c-4322-8baa-487705251df5','次韻僧自文見贈四首  其四','方回','宋','宋诗','song-poetry','','[]','莫詫橫磨劍，寧爲沒字碑。',48,'全唐诗/poet.song.230000.json','["莫詫橫磨劍，寧爲沒字碑。", "問花驚兔麥，賦藥護羊蓍。", "今我都無事，非公不作詩。", "夜窗各堅坐，兩地月明知。"]'),
('92ea36a7-489c-4f03-b28a-f8700f4b8363','次韻康慶之見過醉歸讀予鄙作','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','飯顆山頭老面瘦，沈香亭北醉顔醒。',64,'全唐诗/poet.song.230000.json','["飯顆山頭老面瘦，沈香亭北醉顔醒。", "二豪詩骨已淪淵，誰能汲古出深井。", "康侯天筆雕風騷，一蹴已過廬山高。", "大鵬運海翔六翮，我豈能爲腹背毛。"]'),
('8cbb4a32-f358-4f32-8502-375bdce43299','次韻康慶之秋雨喜凉書懷五首  其一','方回','宋','宋诗','song-poetry','','[]','躁求慾火熾，寂守德宇凉。',48,'全唐诗/poet.song.230000.json','["躁求慾火熾，寂守德宇凉。", "斯人老世故，秋雨鋤驕陽。", "季郈雞浪鬬，臧穀羊俱亡。", "矢詩寫高懷，聳如見清揚。"]'),
('977b654e-35e3-4f4f-a651-b8c6084011eb','次韻康慶之秋雨喜凉書懷五首  其二','方回','宋','宋诗','song-poetry','','[]','少年健如虎，不信髪齒落。',48,'全唐诗/poet.song.230000.json','["少年健如虎，不信髪齒落。", "風雨凄其秋，衆葉失所託。", "深潜泉自滋，猛鍛石亦鑠。", "細思陶元亮，大勝王鎮惡。"]'),
('84605093-a0e9-441a-bbe0-bda82419525b','次韻康慶之秋雨喜凉書懷五首  其三','方回','宋','宋诗','song-poetry','','[]','補衮據鼎鼐，賜履銘旂常。',48,'全唐诗/poet.song.230000.json','["補衮據鼎鼐，賜履銘旂常。", "流汗每浹背，孰知北窗凉。", "協力誅楚新，見忌於高光。", "商山與富春，采釣庸何傷。"]'),
('b05ce293-9f6d-45ab-9e6e-a6094656aae4','次韻康慶之秋雨喜凉書懷五首  其四','方回','宋','宋诗','song-poetry','','[]','游子悲天涯，志士栖山阿。',48,'全唐诗/poet.song.230000.json','["游子悲天涯，志士栖山阿。", "少游一款段，何必減伏波。", "矍鑠豈不偉，末路終蹉跎。", "催科拙下考，當如陽城何。"]'),
('563bcd11-5d64-463f-b14b-b0a31b428a72','次韻康慶之秋雨喜凉書懷五首  其五','方回','宋','宋诗','song-poetry','','[]','雨隴秋告稔，風庭夜饒清。',48,'全唐诗/poet.song.230000.json','["雨隴秋告稔，風庭夜饒清。", "疲庶感幽念，未用思神京。", "矧茲九日近，亦足醉菊英。", "公暇一出野，細詢田父情。"]'),
('a03b46b3-8ebe-41ce-8467-e63fa4e8eff1','次韻康慶之題予桐江詩卷  其一','方回','宋','宋诗','song-poetry','','[]','每愧詩無古風調，背山樓閣曬花褌。',32,'全唐诗/poet.song.230000.json','["每愧詩無古風調，背山樓閣曬花褌。", "稍知海若吞河伯，敢眩蹄涔一勺渾。"]'),
('54cc0e73-9da4-4bcb-bdd3-e6a9f344e4a9','次韻康慶之題予桐江詩卷  其二','方回','宋','宋诗','song-poetry','','[]','小儒百窘似貧戶，薪及扊扅襦作褌。',32,'全唐诗/poet.song.230000.json','["小儒百窘似貧戶，薪及扊扅襦作褌。", "梓澤珊瑚許窺否，未多玉璞與金渾。"]'),
('93f9d26b-9d9b-49b8-9537-bf691e27c332','寄題馮君寧國夢堂','方回','宋','宋诗','song-poetry','','[]','六如第一伽陀字，堂扁剩傳彈鋏馮。',64,'全唐诗/poet.song.230000.json','["六如第一伽陀字，堂扁剩傳彈鋏馮。", "肖象謂當求傅弼，傷麟無復見姬公。", "發棺義已參坡老，札闥嘲猶憶醉翁。", "栩栩侯王熱人眼，渠知身落大槐宮。"]'),
('e3282c03-219b-4036-886a-61418b715515','次韻康慶之秋夜客懷自述','方回','宋','宋诗','song-poetry','','[]','遯肥久已遠罝羅，獨慨流年老易過。',64,'全唐诗/poet.song.230000.json','["遯肥久已遠罝羅，獨慨流年老易過。", "宦學向來千齟齬，功言竟復兩蹉跎。", "是山可隠在人耳，今雨不來如彼何。", "羣蟄閉關迫摇落，未須輕奮怒蠅戈。"]'),
('05158e45-8d2c-4b47-b832-13e2040bc2be','次韻康慶之催借所著及謝見過  其一','方回','宋','宋诗','song-poetry','','[]','聞道公家所著書，擔囊荷篋喘肩夫。',32,'全唐诗/poet.song.230000.json','["聞道公家所著書，擔囊荷篋喘肩夫。", "定應未肯輕傳借，良賈深藏有若無。"]'),
('db9c7b3f-7b97-4923-a365-c110fc14dd0c','次韻康慶之催借所著及謝見過  其二','方回','宋','宋诗','song-poetry','','[]','胸涵太古恐無鄰，面著微埃詎許親。',32,'全唐诗/poet.song.230000.json','["胸涵太古恐無鄰，面著微埃詎許親。", "顧肯城南訪窮巷，松風時煮一甌春。"]'),
('6b798351-02da-4204-8915-606fee5bc569','次韻康總管慶之和碑字韻二首  其一','方回','宋','宋诗','song-poetry','','[]','周頌岐陽鼓，秦銘泰岳碑。',48,'全唐诗/poet.song.230000.json','["周頌岐陽鼓，秦銘泰岳碑。", "覽觀明古鏡，推測妙神蓍。", "真復登三事，何如賦萬詩。", "江湖頻作郡，棠蔭有人知。"]'),
('cbbd1597-0db6-4d6f-aa77-6d9cead270f9','次韻康總管慶之和碑字韻二首  其二','方回','宋','宋诗','song-poetry','','[]','山游靈運屐，寺乞簡栖碑。',48,'全唐诗/poet.song.230000.json','["山游靈運屐，寺乞簡栖碑。", "歲計多栽菜，流年懶問蓍。", "醉眠書當枕，禪戲偈成詩。", "鬢白非今日，何勞曉鏡知。"]'),
('af55fae2-8ad1-40ea-b427-f0133e25e144','送張錄事誠二首  其一','方回','宋','宋诗','song-poetry','','[]','歙州江見底，錄事亦如之。',48,'全唐诗/poet.song.230000.json','["歙州江見底，錄事亦如之。", "休吏早封印，訪僧閒著棋。", "舊鞍羸馬出，矮屋破簾垂。", "行處與住處，官清人不知。"]'),
('8375b689-9572-4a6a-a6c8-7efea079cfc6','送張錄事誠二首  其二','方回','宋','宋诗','song-poetry','','[]','雖然精吏道，不肯失民心。',48,'全唐诗/poet.song.230000.json','["雖然精吏道，不肯失民心。", "但飲鄰牆井，猶償月俸金。", "舉家惟菜味，附邑更棠陰。", "久弄周昌印，臨文勿太深。"]'),
('9268526b-d696-44ba-9f6c-663308536cc8','九月初一日','方回','宋','宋诗','song-poetry','','[]','滿城風雨夜初長，曉徑衣單野圃荒。',64,'全唐诗/poet.song.230000.json','["滿城風雨夜初長，曉徑衣單野圃荒。", "秋著此寒欺老我，詩將何句待重陽。", "山容競爽穿疏樹，菊意高騫迓早霜。", "人事日非物良是，悲來誰辦鐵爲腸。"]'),
('db92477f-b048-4982-87de-4a8988837a65','次韻寄川無竭併送所撰旃檀林記二首  其一','方回','宋','宋诗','song-poetry','','[]','彭門不記舊樓黄，吟社參寥未肯忘。',64,'全唐诗/poet.song.230000.json','["彭門不記舊樓黄，吟社參寥未肯忘。", "更著雪添雙短鬢，早驚秋隔兩重陽。", "遥知剩種旃檀樹，便擬同焚艾納香。", "勉爲龜蚨驅兔穎，愧無雄健亢三長。"]'),
('43756181-023b-45d1-a7ed-9d599ed66323','次韻寄川無竭併送所撰旃檀林記二首  其二','方回','宋','宋诗','song-poetry','','[]','多生曾結短檠緣，埋沒書蟫不記年。',64,'全唐诗/poet.song.230000.json','["多生曾結短檠緣，埋沒書蟫不記年。", "左鬰右鄰窺奧藏，南浯北嶧問奇鎸。", "更饒曼倩三冬學，未抵天龍一指禪。", "絲盡繭成終有日，與公同作老蠶眠。"]'),
('7b1803f1-e14b-4027-af53-918af13c5b1b','次韻張耕道喜雨見懷兼呈趙賓暘','方回','宋','宋诗','song-poetry','','[]','疲氓多菜色，去守乏棠陰。',192,'全唐诗/poet.song.230000.json','["疲氓多菜色，去守乏棠陰。", "屬慮千峰旱，俄聞六月霖。", "麵灘船欲澀，茗務井還深。", "香潤迴瓜圃，聲酣起蔗林。", "炎官初恣肆，道暍稍侵尋。", "畏日方焦野，油雲忽冒岑。", "此凉甦萬病，厥價倍千金。", "解郡雖踰歲，留家尚至今。", "田登欣米賤，屋老懼書淋。", "遥念兒衣醭，兼虞婦竈沈。", "凄清傳古調，憂悶豁煩襟。", "拭汗紕綀帨，搔頭斷玉簪。", "却思穿石罅，共坐聽泉音。", "韭脆鮮鱗縷，梅芳煮醖斟。", "一江同照影，兩地隔論心。", "疑雪佳公子，輸君日對吟。"]'),
('8a6506a4-b796-4fa0-94f7-6fc970042f07','重陽吟五首  其一','方回','宋','宋诗','song-poetry','','[]','射蛇戲馬老劉郎，不爲乾坤減戰場。',32,'全唐诗/poet.song.230000.json','["射蛇戲馬老劉郎，不爲乾坤減戰場。", "三徑寒華空悵望，閒居無酒對重陽。"]'),
('818a8125-d05c-44d2-9465-53caeb878af0','重陽吟五首  其二','方回','宋','宋诗','song-poetry','','[]','心炎何處不南荒，瘴海煙深有玉堂。',32,'全唐诗/poet.song.230000.json','["心炎何處不南荒，瘴海煙深有玉堂。", "隨地著身無得喪，菊花開日即重陽。"]'),
('c9cab735-601b-4c62-9997-05613886800c','重陽吟五首  其三','方回','宋','宋诗','song-poetry','','[]','此身生死國興亡，摇落年年本是常。',32,'全唐诗/poet.song.230000.json','["此身生死國興亡，摇落年年本是常。", "無奈潘郎解悽怨，滿城風雨近重陽。"]'),
('7b123aba-858f-4880-942f-2b126ff887fd','重陽吟五首  其四','方回','宋','宋诗','song-poetry','','[]','衣冠南渡紫微郎，流落天涯事可傷。',32,'全唐诗/poet.song.230000.json','["衣冠南渡紫微郎，流落天涯事可傷。", "不是詩人終不會，亂山深處過重陽。"]'),
('ebd1534c-00de-4d0e-b724-30bde22ef88f','重陽吟五首  其五','方回','宋','宋诗','song-poetry','','[]','戰塵漠漠草荒荒，兵過村空菊自黄。',32,'全唐诗/poet.song.230000.json','["戰塵漠漠草荒荒，兵過村空菊自黄。", "死盡親知身偶在，干戈叢裏見重陽。"]'),
('6c423f42-3d3c-4f0f-88c4-d9213ef57481','哭肯堂趙公擬老杜八哀體','方回','宋','宋诗','song-poetry','','[]','飛鴻離魚網，玉石有俱焚。',288,'全唐诗/poet.song.230000.json','["飛鴻離魚網，玉石有俱焚。", "冥冥豈無志，鬼物妬璵璠。", "今代趙廣漢，誰歟哀王孫。", "粹然東南稟，頑薄推廉敦。", "悠悠桐江水，父老至今言。", "聽訟古楠下，審克恭且溫。", "郡將不解事，禍變生軍屯。", "婺米給濕腐，營壘朝無飧。", "出甲火府庫，僚吏爭潰僨。", "黄堂坐者誰，微服踰缺垣。", "公急叩府寺，衆涅忽自蹲。", "大呼好知縣，肩輿坐和轅。", "卒輩匪怙亂，猾刻專饕惛。", "各欲贍老幼，等死有本原。", "公急斥私橐，致米諸鄉村。", "稍撫以金帛，汝飽可無喧。", "頃刻事底定，闔城免屠燔。", "聲名由此起，褒語來天閽。", "就擢半刺史，遄又典大藩。", "東西浙河節，祥刑謹平反。", "芟亂保鄉郡，剿馘殲盜根。", "我時守馬目，鄰疆約相援。", "天地既翻覆，氣數難預論。", "箕子歌麥秀，邵平灌瓜園。"]'),
('3b17e9e8-3f75-49d6-86ca-5ab83bb72095','癸未九日','方回','宋','宋诗','song-poetry','','[]','芙蓉一雨爛枝繁，籬落紛披菊滿園。',64,'全唐诗/poet.song.230000.json','["芙蓉一雨爛枝繁，籬落紛披菊滿園。", "歲月少恩寒事迫，乾坤多難老身存。", "酒逢我輩何拘節，山在吾家不出門。", "高可常登亦常醉，獨能此日與銷魂。"]'),
('b1efd2f3-96a8-4ab8-b7f5-5905d13b31b4','九日有感再書','方回','宋','宋诗','song-poetry','','[]','荒山過雨薄寒新，洗盡西風扇底塵。',64,'全唐诗/poet.song.230000.json','["荒山過雨薄寒新，洗盡西風扇底塵。", "萍梗江湖今故國，干戈天地幾遺民。", "向來佳節都如夢，不謂衰年剩此身。", "草草兒曹一杯酒，誰歟可與話酸辛。"]'),
('ae86238b-56d3-4857-9c53-7d58804066c8','秋晚雜書三十首  其一','方回','宋','宋诗','song-poetry','','[]','煌煌鷄冠花，飛昂麗前軒。',96,'全唐诗/poet.song.230000.json','["煌煌鷄冠花，飛昂麗前軒。", "異物尚貴少，焉用此卉繁。", "翰音賦首飾，鳴將雄其羣。", "植物復肖之，天巧詎可原。", "細視足詭怪，惡多謂宜芟。", "嗟哉近霜草，十九已不蕃。", "獨茲峙榮豔，豈不勝枯樊。", "留以伴嘉菊，亦足華我園。"]'),
('988a2025-ce97-443e-aa73-30736ce302a3','秋晚雜書三十首  其二','方回','宋','宋诗','song-poetry','','[]','屈子悼芙蓉，胡於木末采。',96,'全唐诗/poet.song.230000.json','["屈子悼芙蓉，胡於木末采。", "誰歟變秋樹，水花儼高塏。", "本非蓮藕類，稍稍具姿彩。", "厥植亦匪貞，朝澤暮已痗。", "叔世尚浮卉，貌取實故萎。", "吾廬百昌戕，一二此根在。", "無奈兒女曹，愛之若芳茝。", "曾不如蕎穄，足用拯疲餒。"]'),
('d5b32163-2e0b-4d92-a600-ffa7a5f5246b','秋晚雜書三十首  其三','方回','宋','宋诗','song-poetry','','[]','酒爲萬有神，菊實百卉仙。',96,'全唐诗/poet.song.230000.json','["酒爲萬有神，菊實百卉仙。", "敢問神謂何，我腸苦愁煎。", "此味一濡唇，倏忽千憂捐。", "仙說又何謂，南陽有其泉。", "昔人飲芳潤，槁項足引年。", "閒居愛重九，二物心懷旃。", "秋熱寒華遲，家貧時醪慳。", "屯乖勿深嘆，古亦有斯賢。"]'),
('0f261b24-6312-45a8-9c73-cd5c11f2fc4a','秋晚雜書三十首  其四','方回','宋','宋诗','song-poetry','','[]','疇昔夏之夜，百蟲無不鳴。',96,'全唐诗/poet.song.230000.json','["疇昔夏之夜，百蟲無不鳴。", "侵尋迫秋杪，惟有蟋蟀聲。", "微物乏巨喙，寒翅厲酸清。", "露將化爲霜，欲鳴聲不成。", "瓦石有深縫，緘默逃汝生。", "不然且立死，焉問懶婦驚。", "天地布肅令，詎別物重輕。", "豈惟螻蟻蟄，神龍亦潜形。"]'),
('21a0eeca-0f5a-4a99-8d7c-692f80793dc8','秋晚雜書三十首  其五','方回','宋','宋诗','song-poetry','','[]','我觀滿囷粟，一粟之所充。',96,'全唐诗/poet.song.230000.json','["我觀滿囷粟，一粟之所充。", "海魚千百億，孕卵與粟同。", "春菊寸許芽，霜華秋叢叢。", "誤耘或失溉，槁死厥壤童。", "萬物生必成，塞天曾不容。", "殀閼盡屯厄，宇宙將無空。", "忍哉銳頭輩，不恤地上蟲。", "漢網非少寬，六合無人蹤。"]'),
('0be06576-f005-4357-b837-6f828a29b2af','秋晚雜書三十首  其六','方回','宋','宋诗','song-poetry','','[]','思詩夜無寐，佳句招不來。',96,'全唐诗/poet.song.230000.json','["思詩夜無寐，佳句招不來。", "不思忽有得，清晨視空階。", "昨日所未有，紅葉初可枚。", "小雨過庭菊，一夕粲然開。", "饑雀噪簷隙，紡車響林隈。", "百動各有爲，此復掛我懷。", "秋意美初寒，經營一銜杯。", "炊僕告薪盡，空庖風捲埃。"]'),
('e99190bf-ab71-426a-9ae3-18093ac34aca','秋晚雜書三十首  其七','方回','宋','宋诗','song-poetry','','[]','去年歸我廬，移菊於鄰家。',96,'全唐诗/poet.song.230000.json','["去年歸我廬，移菊於鄰家。", "今年灌我畦，百本餘秋華。", "閲時十二朔，暄凉更韭瓜。", "逋債之所叢，詆詬紛交加。", "燃頭復割腸，笑口仍呀呀。", "低價棄薄産，未辦充饞拏。", "憂端如箭來，惟有醉可遮。", "買酒賣書籍，匹如死天涯。"]'),
('333743ba-5b0c-4685-b63d-6dd7f4106d29','秋晚雜書三十首  其八','方回','宋','宋诗','song-poetry','','[]','今年初發春，主人飲我酒。',96,'全唐诗/poet.song.230000.json','["今年初發春，主人飲我酒。", "借問主人誰，是邦之太守。", "座中有上客，儼然八十叟。", "優伎何紛喧，觀者拄肱肘。", "于時梅始華，菊榮倏秋九。", "此主憤僕誣，逮對以疽踣。", "此客抱老病，亦復正丘首。", "人生會皆爾，曷不覆大斗。"]'),
('5b5e7f05-1b35-4fe6-8036-e108ffd02289','秋晚雜書三十首  其九','方回','宋','宋诗','song-poetry','','[]','何以知秋深，衾薄無濃夢。',96,'全唐诗/poet.song.230000.json','["何以知秋深，衾薄無濃夢。", "夢斷復不眠，寒氣夜已縱。", "幻虛成諸有，誰實神其用。", "積慘以消之，化工似好弄。", "東家生育喜，西舍哭泣痛。", "鴻荒考妣初，萬代幾賓送。", "釋氏寂滅樂，此理未必中。", "浩然思無涯，雨鳴鼓鐘動。"]'),
('2dc7a59d-9c94-4f42-8a23-90016dbdaed0','秋晚雜書三十首  其一○','方回','宋','宋诗','song-poetry','','[]','有金當報恩，有劍勿報讎。',96,'全唐诗/poet.song.230000.json','["有金當報恩，有劍勿報讎。", "忘讎不過辱，忘恩禽獸儔。", "雛烏哺其母，豺獺知獻羞。", "豈伊具人面，曾不畜産侔。", "魯叟造化心，筆底天春秋。", "如彼貨與魋，何足私怨尤。", "千里忽命駕，□予將焉求。", "爲言篤故誼，一飯敢不酬。"]'),
('29b160c7-025a-4a3a-9eb7-066b81d99935','秋晚雜書三十首  其一一','方回','宋','宋诗','song-poetry','','[]','周誥惡沈湎，禮設萍氏禁。',96,'全唐诗/poet.song.230000.json','["周誥惡沈湎，禮設萍氏禁。", "愚夫或敗德，賢者故克敬。", "上有朝廷燕，下有鄉黨飲。", "倍食與無算，豈聞起酗競。", "但此忘憂物，過嗜足致病。", "湯劑所不攻，朝窗卧若暝。", "雖然極困羸，亦未害性命。", "百病皆不可，病酒差獨勝。"]'),
('ce4b2294-1fa4-4aba-99fe-ee3ba75eaeef','秋晚雜書三十首  其一二','方回','宋','宋诗','song-poetry','','[]','世運日已季，帝王降而霸。',96,'全唐诗/poet.song.230000.json','["世運日已季，帝王降而霸。", "人品亦復然，窮極事狙詐。", "孟堅列九等，三三以相亞。", "聖有生而知，愚至不可化。", "吾謂上上人，老死守田舍。", "遠迹牛豕間，胼胝事耕稼。", "彼昏慕鼎食，厥價下之下。", "何待臨伏锧，然後發悲咤。"]'),
('a944ad6b-8965-48e4-a293-61cf2db5b1a0','秋晚雜書三十首  其一三','方回','宋','宋诗','song-poetry','','[]','昔聞有烈士，哀歌缺唾壺。',96,'全唐诗/poet.song.230000.json','["昔聞有烈士，哀歌缺唾壺。", "衰暮心不已，徇名殆忘軀。", "我老詎復爾，一壑不願餘。", "外物百無嗜，惟喜讀我書。", "空樽已絕瀝，寒庖僅微蔬。", "兒啼得非餒，塵編聊自娛。", "弊廬匪無山，猶茲寄城隅。", "車馬不至處，願言遷林居。"]'),
('cdc6bed2-70dc-4c22-9f72-6f765935bc0e','秋晚雜書三十首  其一四','方回','宋','宋诗','song-poetry','','[]','吾年志學初，故已嗜爲詩。',96,'全唐诗/poet.song.230000.json','["吾年志學初，故已嗜爲詩。", "三霜當六十，無復一黑髭。", "生事置墮甑，世故愕敗棋。", "獨喜五柳作，時時一哦之。", "□□其猶龍，隠見不可羈。", "道人結淨社，刺史遺酒貲。", "親狎□□□，亦不作岸崖。", "永言想遐𨅛，終老茅簷栖。"]'),
('d1474568-6534-4d35-b111-f39df5c918a7','秋晚雜書三十首  其一五','方回','宋','宋诗','song-poetry','','[]','賦詩學淵明，詩固未易及。',96,'全唐诗/poet.song.230000.json','["賦詩學淵明，詩固未易及。", "飲酒慕淵明，酒復罕所得。", "荒凉數畝園，卜築未成宅。", "此或類陶家，秋菊亦可摘。", "古稱士希賢，將無肖厥德。", "如我於柴桑，往往似其迹。", "儲粟既以缾，子尤不勝責。", "有時醉欲吟，坌集索逋客。"]'),
('5304de10-0323-48ca-8f93-e5196ba3198c','秋晚雜書三十首  其一六','方回','宋','宋诗','song-poetry','','[]','三歲出瘴嶺，弱冠歷吳楚。',96,'全唐诗/poet.song.230000.json','["三歲出瘴嶺，弱冠歷吳楚。", "晚涉大漠寒，遠弔長城古。", "失□得謗讟，少樂多辛苦。", "侵尋四十年，復此守環堵。", "松楸僅有存，骨肉化爲土。", "豈不登一名，貧甚於父祖。", "行行荒籬間，寒華粲可數。", "惟酒足解愁，錢盡不得酤。"]'),
('42466dd5-2727-48d3-a275-7727d49e6c1b','秋晚雜書三十首  其一七','方回','宋','宋诗','song-poetry','','[]','堂堂陳去非，中興以詩鳴。',96,'全唐诗/poet.song.230000.json','["堂堂陳去非，中興以詩鳴。", "呂曾兩從橐，殘月配長庚。", "尤蕭范陸楊，復振乾淳聲。", "爾後頓寂寥，草蟲何薨薨。", "永嘉有四靈，詞工格乃平。", "上饒有二泉，旨淡骨獨清。", "學子孰取舍，吾非私重輕。", "極玄雖有集，豈得如淵明。"]'),
('fb2d1595-973e-480c-8ece-4b56e223e49d','秋晚雜書三十首  其一八','方回','宋','宋诗','song-poetry','','[]','吾家一何奇，奇峰照南窗。',96,'全唐诗/poet.song.230000.json','["吾家一何奇，奇峰照南窗。", "是爲紫陽山，萬木青樅樅。", "上有出岫雲，下有見底江。", "江清雲無心，伴此眉宇厖。", "詩思忽飛來，時有白鳥雙。", "落日澹秋色，寒溝度枯杠。", "歸歟書屋夜，昏燈剔幽釭。", "懷人良未遠，遯翁生是邦。"]'),
('809070c9-e942-4d23-97ad-40b6131792ed','秋晚雜書三十首  其一九','方回','宋','宋诗','song-poetry','','[]','竊嘗評少陵，使生太宗時。',96,'全唐诗/poet.song.230000.json','["竊嘗評少陵，使生太宗時。", "豈獨魏鄭公，論諫垂至茲。", "天寶得一官，主昏事已危。", "脫命走行在，窮老拜拾遺。", "卒坐鯁直去，漂落西南陲。", "處處苦戰鬬，言言悲亂離。", "其間至痛者，莫若八哀詩。", "我無此筆力，懷抱頗似之。"]'),
('94550282-e2b4-424f-9dfb-3433d8590e59','秋晚雜書三十首  其二○','方回','宋','宋诗','song-poetry','','[]','人言太白豪，其詩麗以富。',96,'全唐诗/poet.song.230000.json','["人言太白豪，其詩麗以富。", "樂府信皆爾，一掃梁隋腐。", "餘編細讀之，要自有樸處。", "最於贈答篇，肺腑露情愫。", "何至昌谷生，一一雕麗句。", "亦焉用玉溪，纂組失天趣。", "沈宋非不工，子建獨高步。", "畫肉不畫骨，乃以帝閑故。"]'),
('21514f61-46a8-44cc-a06b-bea65705776a','秋晚雜書三十首  其二一','方回','宋','宋诗','song-poetry','','[]','六經天日月，諸子如四時。',96,'全唐诗/poet.song.230000.json','["六經天日月，諸子如四時。", "史自班以上，語奇文亦奇。", "踵武蔚宗輩，語有文無之。", "小宋刊新唐，不悟宵寐規。", "以藝傳李杜，待之無乃卑。", "他人有遺集，一覽不再窺。", "惟此與韓柳，咀嚼無厭期。", "儕彼楓落生，吾欲鎸此疵。"]'),
('c972d79a-420f-41ba-b27a-6dddf33c3056','秋晚雜書三十首  其二二','方回','宋','宋诗','song-poetry','','[]','道自漢魏降，裂爲文與詩。',96,'全唐诗/poet.song.230000.json','["道自漢魏降，裂爲文與詩。", "工詩或拙文，文高詩或卑。", "香甌假山序，不妨自一奇。", "鰣橘多骨核，乃至肆詆訾。", "恭惟陳無己，此事獨兼之。", "五七掩杜集，千百臻秦碑。", "四海紫陽翁，歸美豈其私。", "所以此虛叟，取爲晚節師。"]'),
('f3a53214-8f0d-442e-b13c-71da60226a1d','秋晚雜書三十首  其二三','方回','宋','宋诗','song-poetry','','[]','天地亙長有，山川無盡時。',96,'全唐诗/poet.song.230000.json','["天地亙長有，山川無盡時。", "人爲萬物靈，曾靡百年期。", "堯舜復安在，桀紂亦如茲。", "魂消骨已朽，是非焉得知。", "阿瞞營八極，羣雄略芟夷。", "分香何戀戀，終有西陵悲。", "俗眼乏遠矚，世議多偏私。", "蠅蚊不待霜，有酒聊自持。"]'),
('44a3b060-b4e8-4086-9d42-51da301b45f3','秋晚雜書三十首  其二四','方回','宋','宋诗','song-poetry','','[]','子雲性滑稽，寓意頌酒德。',96,'全唐诗/poet.song.230000.json','["子雲性滑稽，寓意頌酒德。", "鴟夷雖勝瓶，豈終無腐日。", "子反以此斃，孟公卒自賊。", "萬物有中道，盍少循軌則。", "唐用交州督，畏瘴避遠役。", "抵死坐不飲，如此固爲失。", "北齊有孫生，執筆老敕勒。", "一夕醉不起，彼亦豈爲得。"]'),
('201667bd-989d-4be1-98eb-f6c26f6b7465','秋晚雜書三十首  其二五','方回','宋','宋诗','song-poetry','','[]','君子食己德，小人食己力。',96,'全唐诗/poet.song.230000.json','["君子食己德，小人食己力。", "萬卷空自讀，一錢終不直。", "使此腹無書，詎可登仕籍。", "艱難一飯故，展轉百憂集。", "前臑不復夢，歸灌畦數席。", "芋首已足掘，豆莢亦可摘。", "所烹無不美，自我鋤上出。", "寄謝朵頤人，抱饑幸無戚。"]'),
('9205a91b-2acb-4c1d-89cb-ff3a05d2f880','秋晚雜書三十首  其二六','方回','宋','宋诗','song-poetry','','[]','我不識淵明，但以菊觀之。',96,'全唐诗/poet.song.230000.json','["我不識淵明，但以菊觀之。", "白露化爲霜，百草忽已萎。", "始見南山松，青青虬龍枝。", "睠此粲然英，凜有千尺姿。", "擷菊酹我酒，倚松哦我詩。", "二物足相配，彷彿齊與夷。", "遥遥襲世胄，豈無王謝兒。", "故是芙蓉花，亦得與同時。"]'),
('fec15dd8-2942-4c4d-a81c-e2f77d343588','秋晚雜書三十首  其二七','方回','宋','宋诗','song-poetry','','[]','世稱陶謝詩，陶豈謝可比。',96,'全唐诗/poet.song.230000.json','["世稱陶謝詩，陶豈謝可比。", "池草固未彫，階藥已頗綺。", "如唐號元白，白豈元可擬。", "中有不同處，要與分朴詭。", "鄭圃趙昌父，潁川韓仲止。", "二泉豈不高，顧必四靈美。", "鹹潮生薑門，蝦蜞以爲旨。", "未若玉山雪，空鐺煮荒薺。"]'),
('02513cdf-ba32-4bee-863a-ae2529632dda','秋晚雜書三十首  其二八','方回','宋','宋诗','song-poetry','','[]','獨吟不愧聲，獨立不愧影。',96,'全唐诗/poet.song.230000.json','["獨吟不愧聲，獨立不愧影。", "獨行不愧屐，獨卧不愧枕。", "昏昏十日醉，炯炯一夕醒。", "古瓶插殘菊，老碗貯凍茗。", "三嗅復三漱，浩然萬慮屏。", "節食甘獨饑，薄衣耐獨冷。", "狸膏肥粟栗，出穴落匕鼎。", "此事世接踵，夜坐試獨省。"]'),
('442f0ae9-8c6d-4745-998a-feb3ea8a4503','秋晚雜書三十首  其二九','方回','宋','宋诗','song-poetry','','[]','三月三十日，唐有窮詩人。',96,'全唐诗/poet.song.230000.json','["三月三十日，唐有窮詩人。", "惜春不肯拾，共坐夜達晨。", "此得守歲意，事愚意已神。", "寸陰以分計，一分直千囷。", "竊慮假寐頃，倏忽失我春。", "今此九月晦，虛叟尤酸辛。", "摇落始云悲，迴首忽復陳。", "詎忍棄菊舊，遽喜迎梅新。"]'),
('71ff2e54-ee63-4663-9319-b9c40de6d142','秋晚雜書三十首  其三○','方回','宋','宋诗','song-poetry','','[]','游山不必衆，邂逅三五人。',96,'全唐诗/poet.song.230000.json','["游山不必衆，邂逅三五人。", "酌酒不在多，淺深十許巡。", "高可登即登，不復拘日辰。", "可飲即與飲，無問芻牧民。", "九月向十月，丹楓日以新。", "城東有奇阜，霜寒出嶙峋。", "一眺鴻背上，嘯歌岸風巾。", "吾雖愧孟嘉，不作桓溫賓。"]'),
('da2072f8-054f-4674-9968-ee0927bf75a2','艮思臺秋眺','方回','宋','宋诗','song-poetry','','[]','風亭月榭欲爲之，十許年前已築基。',64,'全唐诗/poet.song.230000.json','["風亭月榭欲爲之，十許年前已築基。", "秋著碧山環作畫，天將白鳥點成詩。", "撫松已幸追陶徑，夢草無煩憶謝池。", "典午紀中摇落語，白頭洄泝不勝悲。"]'),
('69048053-28a9-4d52-bd9f-b553403b9e8e','甕圃新霽','方回','宋','宋诗','song-poetry','','[]','小園秋霽勝春暉，雨過林端葉未稀。',64,'全唐诗/poet.song.230000.json','["小園秋霽勝春暉，雨過林端葉未稀。", "紅錦芙蓉應萬蕚，雪衣蝴蝶忽雙飛。", "刀耕舊業聊從俗，甕汲餘生永息機。", "天與華腴慰蕭寂，可無佳句答煙霏。"]'),
('066b69aa-cad3-4b5c-b3f4-a03f8cb09c6c','用康慶之韻約同陸仁重游問政山','方回','宋','宋诗','song-poetry','','[]','落葉卷秋原，斜日照荒草。',124,'全唐诗/poet.song.230000.json','["落葉卷秋原，斜日照荒草。", "我所思兮山中人，餐松辟穀修仙道。", "將旄相印本無心，一蓑尚喜收身早。", "袖有長生度世方，玉杵玄霜倩誰搗。", "白雲三耳真人家，磵霜不死菖蒲華。", "笑挹諸公葛陂杖，同駕老龍穿碧霞。", "顛歌狂舞酒酣時，一洗萬古興亡悲。", "九萬里風排闔歸，茫茫六合黄塵飛。"]'),
('4f61446e-6622-4b36-bda3-a513ba86ecb1','游問政山次韻郡侯康慶之','方回','宋','宋诗','song-poetry','','[]','住山應是勝游山，矧此仙區異俗寰。',64,'全唐诗/poet.song.230000.json','["住山應是勝游山，矧此仙區異俗寰。", "幾度出城行十里，何時築屋就三間。", "化猿君子高難問，射虎將軍老合閒。", "祇慮家人猶粒食，水泉深冷石田慳。"]'),
('961edf60-53e6-4776-af69-2f82b75cb696','贈山翁','方回','宋','宋诗','song-poetry','','[]','箐果崖芝日足餐，賣薪時亦下雲端。',64,'全唐诗/poet.song.230000.json','["箐果崖芝日足餐，賣薪時亦下雲端。", "鄰家有酒常同醉，晚歲無衣不嘆寒。", "黑白石充棋子用，青黄樹當歷頭看。", "鬚眉不愧商山皓，可待爲人作羽翰。"]'),
('a0862f17-6f22-4900-acd1-53a2aee6fa52','過汪翔甫宅','方回','宋','宋诗','song-poetry','','[]','南紀干戈後，相逢皓首稀。',48,'全唐诗/poet.song.230000.json','["南紀干戈後，相逢皓首稀。", "草間翁仲在，華表令威歸。", "骨壽由心泰，身癯獨道肥。", "公松對吾菊，同閲幾芳菲。"]'),
('f536400a-ded6-4371-acb4-65ddf333d54e','過吳式賢宅','方回','宋','宋诗','song-poetry','','[]','君家梅最古，舉世少人知。',48,'全唐诗/poet.song.230000.json','["君家梅最古，舉世少人知。", "天地無吾黨，風霜自北枝。", "一痕新月外，數點小春時。", "肯爲援琴否，浮香更有詩。"]'),
('021d133d-a084-4abb-865a-b4250c140fd8','別汪翔甫吳式賢','方回','宋','宋诗','song-poetry','','[]','天寒歲云暮，策馬欲何之。',48,'全唐诗/poet.song.230000.json','["天寒歲云暮，策馬欲何之。", "叩戶元無事，開襟莫更疑。", "可輕千里別，不話一番詩。", "今代能吟者，吾曹外有誰。"]'),
('2594d1ea-b3f2-47aa-9a7b-ed4e2aa69e70','同曹清父西郊紀事五首  其一','方回','宋','宋诗','song-poetry','','[]','晴耕新種麥，破塊滿田間。',48,'全唐诗/poet.song.230000.json','["晴耕新種麥，破塊滿田間。", "詰曲隨牛路，周遭傍馬山。", "幾人鍾間氣，往歲聳朝班。", "黄卷今猶在，青雲未易攀。"]'),
('eef77faf-3064-45bf-a2b7-bbeb1cb102de','同曹清父西郊紀事五首  其二','方回','宋','宋诗','song-poetry','','[]','掛粟枯桑杪，籬門晝掩關。',48,'全唐诗/poet.song.230000.json','["掛粟枯桑杪，籬門晝掩關。", "晴霜開曠野，寒日曬荒山。", "指點村煙外，經行塚樹間。", "羣豪故貪愎，竊發亦愚姦。"]'),
('bcbb3545-cd9c-4639-9305-741d2ced8d9a','同曹清父西郊紀事五首  其三','方回','宋','宋诗','song-poetry','','[]','木脫秋聲盡，田空野鳥饑。',48,'全唐诗/poet.song.230000.json','["木脫秋聲盡，田空野鳥饑。", "時危羣盜慘，身老故人稀。", "所至猶堪醉，無求自合歸。", "寥寥天地內，古意一何微。"]'),
('0cbcadd0-e38d-4117-953e-e52c0182a911','同曹清父西郊紀事五首  其四','方回','宋','宋诗','song-poetry','','[]','風俗嗟頹落，文章委下陳。',48,'全唐诗/poet.song.230000.json','["風俗嗟頹落，文章委下陳。", "出郊聊快目，謀野豈關身。", "本爲搜詩去，徒成泥酒頻。", "胸中知此事，眼底似無人。"]'),
('6440123a-b941-433d-8d42-3b42171dccdf','同曹清父西郊紀事五首  其五','方回','宋','宋诗','song-poetry','','[]','朴略童蒙學，堆豗句讀師。',48,'全唐诗/poet.song.230000.json','["朴略童蒙學，堆豗句讀師。", "有能致卿相，或不贍妻兒。", "士故無他業，人誰此味知。", "公庭彼爲吏，日日醉歌姬。"]'),
('c79af796-4aa8-42db-b00c-13c1a9093c6a','題沈克己無名庵','方回','宋','宋诗','song-poetry','','[]','姓字人能說，無名意謂何。',48,'全唐诗/poet.song.230000.json','["姓字人能說，無名意謂何。", "厭稱窮學究，佯作老頭陀。", "宗炳疑相似，韓康定見訶。", "有來問誰某，祇是笑呵呵。"]'),
('16c00efb-7e59-4894-bd6f-81b8ec0cf3ff','霜晴','方回','宋','宋诗','song-poetry','','[]','霜晴暖意融，閒步日陰中。',48,'全唐诗/poet.song.230000.json','["霜晴暖意融，閒步日陰中。", "摘菊驚黄蝶，移葵墮碧蟲。", "不因機偶動，但見色俱同。", "天地詩人少，誰憐有此翁。"]'),
('d3ef298a-0500-468f-b76a-35c9e298990a','每旦聞鐘鼓諸聲','方回','宋','宋诗','song-poetry','','[]','鳥雀次第起，鼓鐘更迭鳴。',48,'全唐诗/poet.song.230000.json','["鳥雀次第起，鼓鐘更迭鳴。", "祇應迫人老，豈是報天明。", "隘巷喧喪事，遥風過市聲。", "有爲無不盡，何苦更刀兵。"]'),
('1371cb61-34e8-4568-9b05-a0def4ac8bd9','小雪日觀殘菊有感','方回','宋','宋诗','song-poetry','','[]','欲雪尋梅樹，餘霜殢菊枝。',48,'全唐诗/poet.song.230000.json','["欲雪尋梅樹，餘霜殢菊枝。", "每嫌開較晚，不道謝還遲。", "早慣饑寒困，頻禁盜賊危。", "少陵情味在，時諷浣花詩。"]'),
('163ef6fe-77a1-4eeb-94f0-75c44cda484a','聞軍過','方回','宋','宋诗','song-poetry','','[]','老膽堪多恐，焦脾更積憂。',48,'全唐诗/poet.song.230000.json','["老膽堪多恐，焦脾更積憂。", "軍聲時洶洶，債事日悠悠。", "西路危單騎，東灘乏便舟。", "情懷無一可，風雨五更頭。"]'),
('63ce774d-cd5f-4f9f-b3ad-f8eb59dc3fc1','久晴十月二十四日五日連雨程以忠來同飲','方回','宋','宋诗','song-poetry','','[]','侵尋小雪初，不雨五旬餘。',240,'全唐诗/poet.song.230000.json','["侵尋小雪初，不雨五旬餘。", "深井腥泥水，荒畦槁蛀蔬。", "牛災傳聚落，蛇出駭階除。", "巫詫瘟神王，官虞火政疏。", "淺流停碓磑，磽隴抗犁鋤。", "閩粵挻兵祲，江淮斷漕渠。", "訛言興委巷，穢氣集窮閭。", "市藥邀珍價，僮衣類臭帤。", "衰年今爾許，惡况又何歟。", "脚汗眠慵洗，頭風坐畏梳。", "捫多王猛虱，食謝孟嘗魚。", "半世空爲吏，平生誤信書。", "得閒真已幸，多懼復焉如。", "田不能倉廩，家纔有室廬。", "稍令逢小稔，亦足慰貧居。", "驟濕生朝礎，斜飄過晚墟。", "簷茅聲乍滴，檻藥色微舒。", "牟麥還堪望，蝗蝻想漸祛。", "良朋胥此會，憂抱與俱紓。", "斗酒適酤至，烹鷄漉韭菹。"]'),
('af1b6c5c-1072-4844-aefd-ad36059371f3','喜劉元煇至二首  其一','方回','宋','宋诗','song-poetry','','[]','荒園槁葉飄，薺菜已堪挑。',48,'全唐诗/poet.song.230000.json','["荒園槁葉飄，薺菜已堪挑。", "頗訝煎茶緩，元知汲水遥。", "日暄花迸蕾，霜過土生硝。", "小待謀新醖，詩朋一一招。"]'),
('04684d9c-6b4c-415c-bfb7-abc04c3f977d','喜劉元煇至二首  其二','方回','宋','宋诗','song-poetry','','[]','詩翁今雨來，同步上荒臺。',48,'全唐诗/poet.song.230000.json','["詩翁今雨來，同步上荒臺。", "草死元藏藥，花窮始到梅。", "南方酣戰急，北陸苦寒催。", "窮老情懷惡，因君得暫開。"]'),
('8289a210-9e33-42e7-8d30-a360be98d822','聞南盜','方回','宋','宋诗','song-poetry','','[]','試與呼蒼昊，云何鬨綠林。',48,'全唐诗/poet.song.230000.json','["試與呼蒼昊，云何鬨綠林。", "誰歟能受諫，吾欲告司箴。", "稍有偷生路，應無守死心。", "古書今不信，衰腐獨沈吟。"]'),
('6512d200-7823-4afb-ad16-30da8bf45189','艮思臺冬日','方回','宋','宋诗','song-poetry','','[]','晚臺閒一望，城盡古溪頭。',48,'全唐诗/poet.song.230000.json','["晚臺閒一望，城盡古溪頭。", "冬暖人多病，山深市早收。", "打門驚客至，乏酒遣兒謀。", "數蟹才堪擘，酣眠失百憂。"]'),
('cfeac371-3bb9-4a67-a779-4c452197efa7','喜劉元煇再至用前韻二首  其一','方回','宋','宋诗','song-poetry','','[]','吟袖與風飄，囊無錦可挑。',48,'全唐诗/poet.song.230000.json','["吟袖與風飄，囊無錦可挑。", "頻來閒話好，勿惜步行遥。", "煮淡蔬勝肉，燃枯草带硝。", "我心知此客，未易以旌招。"]'),
('e5daf65f-151f-4811-acc2-66c1528cd622','喜劉元煇再至用前韻二首  其二','方回','宋','宋诗','song-poetry','','[]','詩忙去復來，側睨笑輿臺。',48,'全唐诗/poet.song.230000.json','["詩忙去復來，側睨笑輿臺。", "未厭庖三韭，終難和八梅。", "親朋驚逝謝，租債迫徵催。", "不酌開懷酒，愁眉詎許開。"]'),
('38b7b1ba-2ca5-4260-8c78-c370d2adb7d3','再用前韻呈元煇二首  其一','方回','宋','宋诗','song-poetry','','[]','談拂風前豎，吟藤月下挑。',48,'全唐诗/poet.song.230000.json','["談拂風前豎，吟藤月下挑。", "是非姑且置，來往不爲遥。", "蟻甕營新漉，貂裘補舊硝。", "聊同小隠隠，未用大招招。"]'),
('a59158dd-7031-4668-ae0e-098658915462','再用前韻呈元煇二首  其二','方回','宋','宋诗','song-poetry','','[]','天寒鸜鵒來，望雪上山臺。',48,'全唐诗/poet.song.230000.json','["天寒鸜鵒來，望雪上山臺。", "髪少不重漆，眼昏猶識梅。", "醡槽呼旋製，窯盎買連催。", "新許民間釀，樽應日日開。"]'),
('79f8a10c-9b7c-4887-bae6-e46bc72860c1','聞汪昌宗訃','方回','宋','宋诗','song-poetry','','[]','四海舊知識，亂來俱白頭。',48,'全唐诗/poet.song.230000.json','["四海舊知識，亂來俱白頭。", "時聞一人死，身復幾年留。", "相遇長安市，頻驚□尉侯。", "胸中皂白事，夢逐杞天休。"]'),
('fe2a227c-75d7-4be9-9b9d-fab2050e6989','十一月初八日觀雨','方回','宋','宋诗','song-poetry','','[]','重陽晴過小春天，忽復蕭騷雨可憐。',64,'全唐诗/poet.song.230000.json','["重陽晴過小春天，忽復蕭騷雨可憐。", "響入竹林全似雪，濕蒸茅舍最宜煙。", "戰塵洗淨無傳箭，客路泥深亦著鞭。", "三月聚糧豈容易，臨風殊覺意茫然。"]'),
('c665f133-6a69-4eb7-8187-00da71727327','用前韻改一二語自釋','方回','宋','宋诗','song-poetry','','[]','南寒稍近折綿天，葵薺爭承小雨憐。',64,'全唐诗/poet.song.230000.json','["南寒稍近折綿天，葵薺爭承小雨憐。", "凍合遠峰應有雪，炊殘荒市更無煙。", "未妨夜畫爐中筯，何苦晨呵袖裏鞭。", "人事好乖行路惡，政應委順付怡然。"]'),
('b9fc7df8-84e2-4e20-b319-380c4983dedb','雨不成雪','方回','宋','宋诗','song-poetry','','[]','一雨疑當冷，旋爲暖所勝。',48,'全唐诗/poet.song.230000.json','["一雨疑當冷，旋爲暖所勝。", "南方難得雪，冬半尚無冰。", "餘菊香深釅，羣蔬意似矜。", "林疏石路細，遥見隔溪僧。"]'),
('80ba3aaa-42d8-4db8-baa9-7aecd19a4276','贈送鶴田李元暉','方回','宋','宋诗','song-poetry','','[]','一別九寒暑，乾坤事事新。',48,'全唐诗/poet.song.230000.json','["一別九寒暑，乾坤事事新。", "老身餘長物，故友盡窮人。", "汩汩猶羣盜，時時有戰塵。", "少陵詩眼在，試覓曲江春。"]'),
('8379f2d6-7e66-4c01-ae72-973173351d3e','別後讀鶴田李元暉新詩用其體','方回','宋','宋诗','song-poetry','','[]','菊悴蘭摧憶別離，雪邊重映十年詩。',64,'全唐诗/poet.song.230000.json','["菊悴蘭摧憶別離，雪邊重映十年詩。", "淚凝紫篠湘靈怨，血迸紅英蜀魄悲。", "曠野虎狼喧寇暴，長途魚雁隔親知。", "莊生浪說能齊物，堯桀彭殤詎可欺。"]'),
('36b00f8d-0a9c-4e43-b515-01375f6e26f0','異僧','方回','宋','宋诗','song-poetry','','[]','荒崖傳有虎，飛錫徑登危。',48,'全唐诗/poet.song.230000.json','["荒崖傳有虎，飛錫徑登危。", "衣槲紉枯葉，餐松嚼嫩枝。", "病人求咒水，野老施庵基。", "一夕緣何事，飄然失所之。"]'),
('607fe4ac-1eab-4046-bd02-d4b7064a2a2a','次韻劉元煇初寒夜坐','方回','宋','宋诗','song-poetry','','[]','山肩寒聳月隨歸，榾柮爐紅閉板扉。',64,'全唐诗/poet.song.230000.json','["山肩寒聳月隨歸，榾柮爐紅閉板扉。", "跨竈郎來溫課冊，齊眉人爲摺深衣。", "花傳喜信燈如語，草就佳篇字欲飛。", "舊日聲名劉夜坐，能傳家鉢似君稀。"]'),
('67e37500-80c1-4ee8-8100-1e7494e9bf03','偶亦夜坐用前韻','方回','宋','宋诗','song-poetry','','[]','林禽畏冷暮爭歸，水上荒城早闔扉。',64,'全唐诗/poet.song.230000.json','["林禽畏冷暮爭歸，水上荒城早闔扉。", "敲月會棋迎皂衲，斧冰供茗喚青衣。", "齕萁老馬廄中響，瞰燭癡蛾窗外飛。", "忽報樓頭禁鐘動，平生樂事歎今稀。"]'),
('cd4dfea5-6c88-4f70-b041-c6adc3335525','又用前韻賦夜坐','方回','宋','宋诗','song-poetry','','[]','酒醒招得醉魂歸，深護爐熏鍵夕扉。',64,'全唐诗/poet.song.230000.json','["酒醒招得醉魂歸，深護爐熏鍵夕扉。", "渴舌惡甜勤潄茗，癯肩耐凍懶添衣。", "頗聞空暗無星出，小待更深定雪飛。", "一字不圓終不寐，癖詩如我自應稀。"]'),
('6926073e-7f9c-4f01-b07c-7f2124cc9ad1','次韻劉元煇飛雪數片之作','方回','宋','宋诗','song-poetry','','[]','六幕垂同凍不埃，舞霙呼我燕窗開。',64,'全唐诗/poet.song.230000.json','["六幕垂同凍不埃，舞霙呼我燕窗開。", "已從衣上霏微見，未肯簷前汗漫來。", "就砌拾看呵指笋，隔簾迎數鬬妝梅。", "衰髯却怪全相似，且置閒愁撥蟻醅。"]'),
('7a1cb7e7-2940-4dc9-829d-d5c10e0ddb1e','再次韻賦飛雪數片','方回','宋','宋诗','song-poetry','','[]','雨收霰止絕纖埃，壓瘴迎豐兆已開。',64,'全唐诗/poet.song.230000.json','["雨收霰止絕纖埃，壓瘴迎豐兆已開。", "欲積忍將靴踏去，初飄喜著袖盛來。", "微微糝體尋生粟，稍稍粘枝輒亂梅。", "不解高樓辦歌舞，典衣亦合買新醅。"]'),
('51cadbe1-0d52-4a0c-85a1-7f0ac7d7b1b3','至前寫懷','方回','宋','宋诗','song-poetry','','[]','送分迎至苦匆匆，壁立蕭騷肯嘆窮。',64,'全唐诗/poet.song.230000.json','["送分迎至苦匆匆，壁立蕭騷肯嘆窮。", "四海交游存想外，十年奔走亂離中。", "生平不作今人調，爾輩焉知國士風。", "自覺近詩如死樹，傍無枝葉更心空。"]'),
('a8b8ef98-953e-4ad6-ac00-fa6287844e1a','小至日書','方回','宋','宋诗','song-poetry','','[]','誰知緹室動葭灰，總道陽從九地迴。',64,'全唐诗/poet.song.230000.json','["誰知緹室動葭灰，總道陽從九地迴。", "年近六旬愁裏過，身行萬里死邊來。", "詩存瘦骨全如我，花倚春風不是梅。", "偶有友朋仍有酒，看雲聊與釂深杯。"]'),
('ac4a4c2d-a0cc-49b2-a7e9-ae7bd1bae62c','所感','方回','宋','宋诗','song-poetry','','[]','生涯今爾許，心悔舊爲邦。',48,'全唐诗/poet.song.230000.json','["生涯今爾許，心悔舊爲邦。", "老合營埋穴，貧猶買釀缸。", "山行憐瘦馬，晝誦喜晴窗。", "忽欲翩然去，風帆泝九江。"]'),
('7da98853-d4eb-4252-836c-5f6a2a513e23','癸未至節以病晚起走筆戲書紀事排悶十首  其一','方回','宋','宋诗','song-poetry','','[]','遇節何其窘，治家乃爾難。',48,'全唐诗/poet.song.230000.json','["遇節何其窘，治家乃爾難。", "穀生舂苦碎，薪貴竈嫌寬。", "病體危狼狽，時情畏觸蠻。", "擁衾聞客至，强整舊衣冠。"]'),
('9ecce705-1711-4301-a4cb-f3f86eb55004','癸未至節以病晚起走筆戲書紀事排悶十首  其二','方回','宋','宋诗','song-poetry','','[]','屋少未成宅，地寬聊作園。',48,'全唐诗/poet.song.230000.json','["屋少未成宅，地寬聊作園。", "吾能甘菜食，或頗送花根。", "蒔喜陽坡暖，澆憐凍井溫。", "丁寧三徑客，緩步惜苔痕。"]'),
('8629c475-5b35-4f6b-be45-c97eb6555f5b','癸未至節以病晚起走筆戲書紀事排悶十首  其三','方回','宋','宋诗','song-poetry','','[]','忍事寧生癭，今誰似我能。',48,'全唐诗/poet.song.230000.json','["忍事寧生癭，今誰似我能。", "缺錢分竈婢，賒米乞庵僧。", "惡語聞皆恕，凡詩見亦稱。", "平生樓百尺，非復舊陳登。"]'),
('ded43c79-fa3e-4450-a079-7c3a9af18b1b','癸未至節以病晚起走筆戲書紀事排悶十首  其四','方回','宋','宋诗','song-poetry','','[]','此老誰能畫，蒙頭一破巾。',48,'全唐诗/poet.song.230000.json','["此老誰能畫，蒙頭一破巾。", "有杯常設客，無局不饒人。", "僕醉鄰翁怒，兒啼乳媼嗔。", "佯聾付一笑，莫漫耗精神。"]'),
('3c03da30-1150-4891-9392-3a2eafe260b9','癸未至節以病晚起走筆戲書紀事排悶十首  其五','方回','宋','宋诗','song-poetry','','[]','老子家風舊，從來節是常。',48,'全唐诗/poet.song.230000.json','["老子家風舊，從來節是常。", "糟薑三盞酒，桕燭一爐香。", "今歲適多病，吾兒猶異鄉。", "十分無意緒，簷雨曉淋浪。"]'),
('bfe9f168-72f4-4cc5-9bec-5ecfc2b8fe43','癸未至節以病晚起走筆戲書紀事排悶十首  其六','方回','宋','宋诗','song-poetry','','[]','貧家無節物，何况此荒城。',48,'全唐诗/poet.song.230000.json','["貧家無節物，何况此荒城。", "村妓聞來賀，山翁懶出迎。", "頭瘍連耳腫，夜雨雜風鳴。", "政爾堪高卧，牀香菊枕成。"]'),
('b3e801bc-aa22-4509-bbfb-8d4196223f65','癸未至節以病晚起走筆戲書紀事排悶十首  其七','方回','宋','宋诗','song-poetry','','[]','重報鶑花信，誰司鐵炭權。',48,'全唐诗/poet.song.230000.json','["重報鶑花信，誰司鐵炭權。", "更經三度節，即滿六旬年。", "豪動書千紙，窮難致一錢。", "不憂無穴葬，惟喜有詩傳。"]'),
('5fd5465e-3fc4-4a51-890e-eb73f1b8a77a','癸未至節以病晚起走筆戲書紀事排悶十首  其八','方回','宋','宋诗','song-poetry','','[]','家人簪珥舊，草草亦梳粧。',48,'全唐诗/poet.song.230000.json','["家人簪珥舊，草草亦梳粧。", "雪几茶花雅，風爐柿葉香。", "乃翁時自笑，此輩詎吾量。", "免賀俱休拜，新正一併償。"]'),
('b490f586-5965-498e-8a0a-61dee79b332c','癸未至節以病晚起走筆戲書紀事排悶十首  其九','方回','宋','宋诗','song-poetry','','[]','古道古君子，今於何處求。',48,'全唐诗/poet.song.230000.json','["古道古君子，今於何處求。", "每聞梔馬箠，不慮蘗馿鞦。", "賈藥全多僞，醫錢卒易酬。", "頭岑姑止酒，或恐自然瘳。"]'),
('bac6722f-f280-48a3-8f1b-95d57b60a3a7','癸未至節以病晚起走筆戲書紀事排悶十首  其一○','方回','宋','宋诗','song-poetry','','[]','雲無可書者，泥屨隔牆聲。',48,'全唐诗/poet.song.230000.json','["雲無可書者，泥屨隔牆聲。", "小市扃虛肆，荒庖絕美烹。", "流涎淮蟹紫，入夢海柑頳。", "莫殢閉關卦，兵戈商不行。"]'),
('7debf97d-8926-4144-be70-6aad189c1006','至後承元煇見和復次韻書病中近况十首  其一','方回','宋','宋诗','song-poetry','','[]','千金營可致，一句得應難。',48,'全唐诗/poet.song.230000.json','["千金營可致，一句得應難。", "積債真無奈，成詩且自寬。", "冰皸窮朔漠，火瘴度甌蠻。", "不似山中好，歸歟遂掛冠。"]'),
('14e97414-c2a8-446c-99e6-47d7e2f9271c','至後承元煇見和復次韻書病中近况十首  其二','方回','宋','宋诗','song-poetry','','[]','曾被卑辭誤，吾嘗笑綺園。',48,'全唐诗/poet.song.230000.json','["曾被卑辭誤，吾嘗笑綺園。", "共欺蛇帝醉，不保橘奴根。", "病起晴冰破，禪悠凍石溫。", "向來腐餘夢，拂拭了無痕。"]'),
('7d79dc4a-e445-4512-83ed-217d2bc88b41','至後承元煇見和復次韻書病中近况十首  其三','方回','宋','宋诗','song-poetry','','[]','昔可今惡可，人能我不能。',48,'全唐诗/poet.song.230000.json','["昔可今惡可，人能我不能。", "已無換馬妾，惟有打門僧。", "幼婦慚前作，愚公定別稱。", "少狂老方悔，焉用一科登。"]'),
('de992afd-ec7e-41dd-99aa-7c97f45b9ea3','至後承元煇見和復次韻書病中近况十首  其四','方回','宋','宋诗','song-poetry','','[]','往事付杯酒，殘生餘幅巾。',48,'全唐诗/poet.song.230000.json','["往事付杯酒，殘生餘幅巾。", "更須占大衍，久已玩同人。", "犒少傭奴懶，迎遲過客嗔。", "悔曾迷宦海，素不媚錢神。"]'),
('7cb18bf5-1bf6-4407-a737-235dc5ef1fe6','至後承元煇見和復次韻書病中近况十首  其五','方回','宋','宋诗','song-poetry','','[]','病無醫自愈，餐飯漸如常。',48,'全唐诗/poet.song.230000.json','["病無醫自愈，餐飯漸如常。", "懶剔書燈暗，閒挼藥紙香。", "就令窮有鬼，終愛醉爲鄉。", "輸與諸年少，從軍過樂浪。"]'),
('5ed1c239-c04c-47b2-8344-283f650b2954','至後承元煇見和復次韻書病中近况十首  其六','方回','宋','宋诗','song-poetry','','[]','閒居已三載，不憶舊專城。',48,'全唐诗/poet.song.230000.json','["閒居已三載，不憶舊專城。", "未暇憂饑凍，唯便免送迎。", "飛花棋上落，幽鳥枕前鳴。", "寒極如春月，新篘綠酒成。"]'),
('6d5e5602-3bd5-47bb-9d89-bf59ccbb9950','至後承元煇見和復次韻書病中近况十首  其七','方回','宋','宋诗','song-poetry','','[]','騷壇君肯將，吾敢與爭權。',48,'全唐诗/poet.song.230000.json','["騷壇君肯將，吾敢與爭權。", "風月三千首，江湖四十年。", "老思騎竹馬，窮笑惜苔錢。", "此味諸人會，遺燈或許傳。"]'),
('8388b122-71f2-4157-ae62-8444e1f02100','至後承元煇見和復次韻書病中近况十首  其八','方回','宋','宋诗','song-poetry','','[]','鄰人窺小圃，籬落倚村莊。',48,'全唐诗/poet.song.230000.json','["鄰人窺小圃，籬落倚村莊。", "雪屋晴窗淨，山爐燄火香。", "異花看又數，隙土步頻量。", "擬築新亭小，如山債未償。"]'),
('47ba5a2a-6622-4df0-98e4-1a2901e54b5a','至後承元煇見和復次韻書病中近况十首  其九','方回','宋','宋诗','song-poetry','','[]','病來諸事懶，於世百無求。',48,'全唐诗/poet.song.230000.json','["病來諸事懶，於世百無求。", "古帙蟫吞字，閒鞍鼠斷鞦。", "佳招差可謝，新詠决須酬。", "耳聵頭昏極，君詩到即瘳。"]'),
('ae9ba108-1a33-48d7-83e5-664cd36f35e2','至後承元煇見和復次韻書病中近况十首  其一○','方回','宋','宋诗','song-poetry','','[]','剩欲延諸彥，嚶嚶聚友聲。',48,'全唐诗/poet.song.230000.json','["剩欲延諸彥，嚶嚶聚友聲。", "尚堪紬古玩，祇愧乏珍烹。", "君健松髯碧，吾衰瓠頂赬。", "何當即勿藥，環席百杯行。"]'),
('75f6c870-ba09-4d8e-acf4-e01c0efcea43','行圃','方回','宋','宋诗','song-poetry','','[]','小圃無亭榭，心閒地自寬。',48,'全唐诗/poet.song.230000.json','["小圃無亭榭，心閒地自寬。", "好花書壁記，怪樹畫圖看。", "雪少先誇瑞，霜嚴諱說寒。", "貪嗔除已盡，唯要不癡難。"]'),
('8175f03c-aada-4372-b5c3-4d1b2c4eb2a6','細省','方回','宋','宋诗','song-poetry','','[]','細省浮生理，宜令寸地寬。',48,'全唐诗/poet.song.230000.json','["細省浮生理，宜令寸地寬。", "老兼無病少，閒欲不貧難。", "遠極山逾好，晴初雪更寒。", "聚奎幾卿相，誰解勝陳摶。"]'),
('873afe4a-9eb9-4027-bf38-6cf02e61162b','晚望','方回','宋','宋诗','song-poetry','','[]','萬事何堪挽，江流日夜東。',48,'全唐诗/poet.song.230000.json','["萬事何堪挽，江流日夜東。", "年華三戒後，心緒四愁中。", "待雪登危阜，觀星仰暗空。", "夜寒天地黑，幾室有爐紅。"]'),
('ec8d49bd-1731-42e5-a063-ca3729bc4154','贈滕君必紹','方回','宋','宋诗','song-poetry','','[]','之子有名父，何蕃合比肩。',96,'全唐诗/poet.song.230000.json','["之子有名父，何蕃合比肩。", "虞庠驚脫穎，孔壁妙忘筌。", "高第攽楓扆，長身掩薤阡。", "師亡鄉黨惜，人往歲時遷。", "達宦誰無死，遺文爾獨傳。", "客郵曾旅進，邑子例垂憐。", "衮語推真幅，絺詞激懦篇。", "善人宜有後，一見欲潸然。"]'),
('e86c052b-1ad8-43ce-9fc5-2aa2f9ea78a3','夏商','方回','宋','宋诗','song-poetry','','[]','牛下悲哀甯戚謳，捐湯置禹此何由。',64,'全唐诗/poet.song.230000.json','["牛下悲哀甯戚謳，捐湯置禹此何由。", "父初傳子風差薄，臣至干君德轉輶。", "歸啟舊家猶幾在，升陑衆旅已相仇。", "何人得似彭鏗壽，見夏爲殷復見周。"]'),
('f676b5cc-b3d6-4fc8-9c9b-d21830a98246','周','方回','宋','宋诗','song-poetry','','[]','七月陳王致太平，轉頭已聽黍離聲。',64,'全唐诗/poet.song.230000.json','["七月陳王致太平，轉頭已聽黍離聲。", "陪臣僣上三歸備，霸國邀君九鼎輕。", "釋氏談空端有理，詞人賦恨豈無情。", "燠年寒歲頻更換，未抵黄河一度清。"]'),
('7e8b04ca-4933-40b8-88dc-57743f633518','太公孔子','方回','宋','宋诗','song-poetry','','[]','禔身涉世謾多憂，運去時來不自由。',64,'全唐诗/poet.song.230000.json','["禔身涉世謾多憂，運去時來不自由。", "孔子三千難變魯，太公八十尚興周。", "星辰歲久常差度，江海潮生會倒流。", "萬有盈虧理如是，可須慳作醉鄉遊。"]'),
('278b48f1-36d5-4670-945e-08e1d179aa4b','漢','方回','宋','宋诗','song-poetry','','[]','燈前閒覆孟堅書，瞬息炎劉四百餘。',64,'全唐诗/poet.song.230000.json','["燈前閒覆孟堅書，瞬息炎劉四百餘。", "五聚井星才屬爾，一抔陵土竟何如。", "早誇發縱輕烹狗，終藉吞舟失漏魚。", "若使高皇爲晉獻，可須莽卓始丘墟。"]'),
('49169045-aff2-4de0-8f3e-e6470728f199','東晉','方回','宋','宋诗','song-poetry','','[]','劉琨勸進豈無聞，王猛臨終亦有云。',64,'全唐诗/poet.song.230000.json','["劉琨勸進豈無聞，王猛臨終亦有云。", "穢史汝能誣正統，老傖誰實蒞餘分。", "山陰禊事流觴帖，彭澤歸來植杖文。", "二物萬年終不泯，可能草木張吾軍。"]'),
('7e1f7495-7397-43e0-9128-11d7eb723f0e','陳','方回','宋','宋诗','song-poetry','','[]','倏忽還如晉滅吳，六朝宮殿永榛蕪。',64,'全唐诗/poet.song.230000.json','["倏忽還如晉滅吳，六朝宮殿永榛蕪。", "千嬌玉座酣醽醁，一命青絲繫轆轤。", "早使閣中無貴嬪，未應闕下有蠻奴。", "他時月夜逢楊廣，衣鉢相傳不早無。"]'),
('21e0c95e-74d6-4554-9d92-7d68b34b7c2a','唐明皇','方回','宋','宋诗','song-poetry','','[]','突虎衝蛇獻荔枝，冰皴霧瘴覆全師。',64,'全唐诗/poet.song.230000.json','["突虎衝蛇獻荔枝，冰皴霧瘴覆全師。", "豔妃有弟堪爲相，叛將無君懵不知。", "嗣后已成靈武篡，舊臣空復曲江思。", "太平可似花開易，羯鼓三聲喚得來。"]'),
('d824f542-04b4-4714-add8-c808bb6059c8','南唐','方回','宋','宋诗','song-poetry','','[]','中原赤氣已龍興，豈必橋江罪若冰。',64,'全唐诗/poet.song.230000.json','["中原赤氣已龍興，豈必橋江罪若冰。", "花不忍看春哭后，金何曾惜歲齋僧。", "失身亡國非無痛，保士全民尚可矜。", "復遇大梁愛文藝，餘臣往往與瀛登。"]'),
('4848ffd7-68a4-41c9-b95d-fe5edb9354d0','長安','方回','宋','宋诗','song-poetry','','[]','客從函谷過南州，略說長安舊日愁。',64,'全唐诗/poet.song.230000.json','["客從函谷過南州，略說長安舊日愁。", "仙隠有峰存紫閣，僧居無寺問紅樓。", "蘭亭古瘞藏狐貉，椒壁遺基牧馬牛。", "萬古不隨人事改，獨餘清渭向東流。"]'),
('0713c97b-9f81-4061-8701-b48bada5fa25','半山','方回','宋','宋诗','song-poetry','','[]','力引豺狼噬九州，貛郎於世果何仇。',64,'全唐诗/poet.song.230000.json','["力引豺狼噬九州，貛郎於世果何仇。", "青苗法令初爲祟，玉斧封疆半已休。", "紹聖南行多不返，靖康北狩欲誰尤。", "兒時曾讀前朝史，幾夜寒燈見淚流。"]'),
('5abbb1de-6bca-48a6-aa00-3162ecf0488d','老悔','方回','宋','宋诗','song-poetry','','[]','前世何知後世長，老年合悔少年狂。',64,'全唐诗/poet.song.230000.json','["前世何知後世長，老年合悔少年狂。", "即今安在凌煙閣，畢竟無非審雨堂。", "脚底東西南北路，樽前三萬六千場。", "謫仙落魄人誰識，終許詩名死後香。"]'),
('72f7dfd4-fc41-4bb7-b10d-5d4e4811dd4d','傍觀','方回','宋','宋诗','song-poetry','','[]','老檜長松玉立身，雪摧霜挫不爭春。',64,'全唐诗/poet.song.230000.json','["老檜長松玉立身，雪摧霜挫不爭春。", "但須處士杯中物，可用明公壁後人。", "自審詩肩無骨相，或稱書眼尚精神。", "南山射虎非吾事，亦復傍觀野水濱。"]'),
('e0540735-84ad-4fd4-a749-2dd6b83bc135','烏聊山廟登覽','方回','宋','宋诗','song-poetry','','[]','寒齋兀兀味殘書，一上崔嵬計未疏。',64,'全唐诗/poet.song.230000.json','["寒齋兀兀味殘書，一上崔嵬計未疏。", "下界喧卑離市井，平臯灑落見樵漁。", "斷鴻淮漢三江外，古樹隋唐五代餘。", "忽憶浮溪偃王句，顧瞻遺廟意躊躇。"]'),
('6f2bd730-1e14-4df1-8845-0152996a50d9','大雪約程以忠不至次日以詩問之','方回','宋','宋诗','song-poetry','','[]','禦寒時著火文武，等醉豈拘杯聖賢。',64,'全唐诗/poet.song.230000.json','["禦寒時著火文武，等醉豈拘杯聖賢。", "土潤春應萌有日，塵清野更潔於天。", "誰呵凍筆詩能畫，獨上高崗意欲仙。", "剩有籬根未消處，試裒枯篠取茶煎。"]'),
('db100efd-f4ef-4c74-8925-04d3c756c888','雪霽次韻以忠見和','方回','宋','宋诗','song-poetry','','[]','霽色寒光滉詩眼，謝家舊賦果誰賢。',64,'全唐诗/poet.song.230000.json','["霽色寒光滉詩眼，謝家舊賦果誰賢。", "無聲忽訝潮包地，不夜常疑月在天。", "溪上過橋僧似畫，樓頭把酒妓如仙。", "老夫幸有瓶笙在，更掃空階落葉煎。"]'),
('6ef3e1c9-0798-4a9d-a0ba-5e877fb59211','雪後小園','方回','宋','宋诗','song-poetry','','[]','紙色光新聳壞櫺，履聲鬆脆兀閒庭。',64,'全唐诗/poet.song.230000.json','["紙色光新聳壞櫺，履聲鬆脆兀閒庭。", "饑禽啐砌留奇迹，枯樹拏空失醜形。", "早與花根添麴糵，可容畫手著丹青。", "溪西凍瀑融晴滴，欲問巖僧借凈瓶。"]'),
('bf71879e-82e0-412f-9367-11f81c453b1f','次韻雪後','方回','宋','宋诗','song-poetry','','[]','簷澌餘滴濺風櫺，三日晴猶剩半庭。',64,'全唐诗/poet.song.230000.json','["簷澌餘滴濺風櫺，三日晴猶剩半庭。", "足使蝗蝻俱屏迹，未妨鶑燕尚潜形。", "調鹽凍字難爲墨，透瓦炊煙漸放青。", "共笑愛梅癡老子，夜深溫水換銅瓶。"]'),
('d68e7585-5319-4db0-9c8b-e5c2a0ce1284','甲申元日','方回','宋','宋诗','song-poetry','','[]','春光幾度九十日，人壽都盧一百年。',64,'全唐诗/poet.song.230000.json','["春光幾度九十日，人壽都盧一百年。", "老圃地寬花富貴，醉鄉天闊酒神仙。", "誰能晚節消閒福，時喜新詩得警聯。", "曉色欲紅拜元造，爐熏一炷鵲聲前。"]'),
('2c5c2d45-22ff-4937-9294-b72eba5d6820','正月初七日如江西以畏飲辭吳式賢宅宿向果市店','方回','宋','宋诗','song-poetry','','[]','殘雪西郊路，依稀已似春。',120,'全唐诗/poet.song.230000.json','["殘雪西郊路，依稀已似春。", "初程何必遠，相識况如親。", "久遠交宜淡，沉綿飲戒醇。", "故辭情話友，擬便穩眠身。", "販旅駢荒店，蠻音酗近鄰。", "霰穿疏瓦亂，風掠破巾頻。", "倦馬噴醒嚏，頑雞絕凍呻。", "謾誇爲客慣，却憶在家貧。", "老嫗言堪取，諸奴意勿嗔。", "近來軍過後，少有早行人。"]'),
('82bac82a-c090-430c-8498-7c9cc74f263f','雨過巖寺鎮','方回','宋','宋诗','song-poetry','','[]','凍濘滑如油，前驅雨未休。',48,'全唐诗/poet.song.230000.json','["凍濘滑如油，前驅雨未休。", "轉添行路惡，始覺別家愁。", "早市漁翁聚，靈祠嶽鬼幽。", "憩鞍寓吾目，有句亦堪搜。"]'),
('22d7d8eb-b8db-44d2-8fe7-8d8bfb58eb67','茅田汪王廟','方回','宋','宋诗','song-poetry','','[]','殿閣猶如許，兵戈豈不無。',48,'全唐诗/poet.song.230000.json','["殿閣猶如許，兵戈豈不無。", "終然香火在，直與子孫俱。", "緒德垂千古，全功保一隅。", "唐陵已煙草，誰作降神巫。"]'),
('487a1cd9-35b3-4b13-98f5-2601a08f85d4','宿曹西疇宅大雨','方回','宋','宋诗','song-poetry','','[]','竹樹環齋館，真宜聽雨聲。',48,'全唐诗/poet.song.230000.json','["竹樹環齋館，真宜聽雨聲。", "不堪終夜急，似欲阻人行。", "薄醉眠難熟，多思夢輒驚。", "漏牀正當面，移枕屢縱橫。"]'),
('7da8c867-77a8-4fb5-bd36-4adbefaf33b6','白茅道中','方回','宋','宋诗','song-poetry','','[]','世故時時異，年華物物新。',48,'全唐诗/poet.song.230000.json','["世故時時異，年華物物新。", "溪聲添夜雨，麥事待晴春。", "草棘扃空戶，巖崖伏凍人。", "問言何至此，征騎往來頻。"]'),
('74597337-939b-4275-8826-da7ffb047c40','溪漲','方回','宋','宋诗','song-poetry','','[]','立春猶二日，漲雨一何深。',48,'全唐诗/poet.song.230000.json','["立春猶二日，漲雨一何深。", "秀足明吟眼，危如撼旅心。", "僕愁前店閉，馬怯小橋臨。", "不見兵氛起，溪西好竹林。"]'),
('b2583b16-52ac-4e29-98a2-63903f78f99f','旅次感事','方回','宋','宋诗','song-poetry','','[]','溪港周遭曲，田原迤邐賒。',96,'全唐诗/poet.song.230000.json','["溪港周遭曲，田原迤邐賒。", "猿猱崖刻削，烏鳥樹槎牙。", "近水皆宜竹，先春已報茶。", "千村經劫火，萬境嘆虛花。", "破落餘神廟，荒殘少富家。", "見人唯欲避，問事只成嗟。", "俗異言難曉，程脩路恐差。", "前朝題壁士，往往字如鴉。"]'),
('d6f89643-fd12-4cee-870a-2a11cfd6feae','問雨','方回','宋','宋诗','song-poetry','','[]','煙爲火之氣，欲雨煙不散。',163,'全唐诗/poet.song.230000.json','["煙爲火之氣，欲雨煙不散。", "陽爲陰所遏，炎焰變舒緩。", "雲乃水之氣，欲雨雲乃浮。", "陰爲陽所爨，饙餾成波流。", "殘秋窮臘百餘日，小園不曾鞋底濕。", "東風欲動問行程，山中比夜雨連明。", "吾聞陰陽交媾，始生萬物。", "不蒸不發，不漬不茁。", "往者久晴，欲駕遄輟。", "今行而雨，咎天何說。", "然則紫陽山人老如此，夫豈得已有行役。", "皇天肯念行路難，豈不能頃刻之間一掃雲煙紅日出。"]'),
('e59f121d-4865-451e-905e-9290cdeb4cf2','舂磑吟','方回','宋','宋诗','song-poetry','','[]','槁木豈有情，頑石且無知。',192,'全唐诗/poet.song.230000.json','["槁木豈有情，頑石且無知。", "何術使之動，不假人力施。", "緯竹以爲車，堰水江之湄。", "湍流既迅急，樞軸爲斡移。", "朽杵輒雀躍，死磨猶驥馳。", "一日殆百斛，成功歸簸篩。", "吾聞往古初，冥冥若愚癡。", "火食尚未悟，人與禽獸嬉。", "聖智既有作，便利無不爲。", "機事至此極，機心開自誰。", "所以桔橰人，旁貽甕汲嗤。", "馬本齕草物，教之諳戰鼙。", "鐵若不入冶，焉有劍與錐。", "工械日以廣，生靈日以糜。", "平生子方子，拙直爲人欺。", "見巧終不喜，諷此舂磑詩。"]'),
('e81b8976-cb9a-410c-94d2-8363d6f435eb','喜雨晴','方回','宋','宋诗','song-poetry','','[]','驟雨送殘雪，山澗沒半膝。',144,'全唐诗/poet.song.230000.json','["驟雨送殘雪，山澗沒半膝。", "悠悠入深溪，想復高數尺。", "赤土流水紅，青土流水碧。", "寸步阻爛泥，詩眼返自德。", "維茲九江路，巴蜀通大驛。", "今事既不然，取道浮梁側。", "西偏數巨港，春漲輒泛溢。", "無橋復無船，僕曹爲予戚。", "老夫負膽氣，動爲萬里役。", "江河淮湖間，徑度無怖色。", "恭惟天所棐，豈不在正直。", "但行無所苦，前路皆晴日。"]'),
('0e956186-402b-48a0-8a4d-803d83fc002c','馬惜蹄','方回','宋','宋诗','song-poetry','','[]','家居豈不好，事此鞍與羈。',120,'全唐诗/poet.song.230000.json','["家居豈不好，事此鞍與羈。", "春前三日雨，僕夫畏深泥。", "江南萬山中，岡嶺互高低。", "踏土不踏石，馬亦惜其蹄。", "野逈暮有虎，村荒晨無雞。", "升斗安所糴，囊粟千里齎。", "身汝不自愛，茹荼甘旅栖。", "曰予匪得已，伐木詩有稽。", "交誼重金石，星霜悵分携。", "一覿庚夙願，投老歌歸兮。"]'),
('1c9356ee-e9b9-4e7d-91db-7ffea428661a','路傍草','方回','宋','宋诗','song-poetry','','[]','野火燎荒原，霜雪日皜皜。',144,'全唐诗/poet.song.230000.json','["野火燎荒原，霜雪日皜皜。", "牛羊無可噍，衆綠就枯槁。", "天地心不泯，根芽蟄深杳。", "春風一披拂，顔色還媚好。", "如何被兵地，黎庶不自保。", "高門先破碎，大屋例傾倒。", "間或遇茅舍，呻吟遺稚老。", "常恐馬蹄響，無罪被擒討。", "逃奔深谷中，又懼虎狼咬。", "一朝稍甦息，追胥復紛擾。", "微言告者誰，勸我宿須早。", "人生值艱難，不如路傍草。"]'),
('c4abe3aa-2993-48ec-b843-c17dad6806bc','古店','方回','宋','宋诗','song-poetry','','[]','古店看題壁，儒風豈易還。',48,'全唐诗/poet.song.230000.json','["古店看題壁，儒風豈易還。", "匪因登貢籍，即爲叩賢關。", "騰踏雲霄上，沉埋草莽間。", "其人俱已矣，遺跡尚斑斑。"]'),
('18863a06-6596-4c11-ad68-42e987b9c51b','魚亭驛','方回','宋','宋诗','song-poetry','','[]','黟縣魚亭驛，東萊閣老詩。',48,'全唐诗/poet.song.230000.json','["黟縣魚亭驛，東萊閣老詩。", "雨晴雲氣斂，峰古石形奇。", "老眼經題奬，高風費詠思。", "祇慚無密竹，不似紹興時。"]'),
('fdcdf7c7-b042-40d8-89d3-41a319ff257d','懷秋崖','方回','宋','宋诗','song-poetry','','[]','崖仙憶昔手予携，音響如鐘氣吐蜺。',64,'全唐诗/poet.song.230000.json','["崖仙憶昔手予携，音響如鐘氣吐蜺。", "槐國諸公千夢蟻，甕天餘子一醯雞。", "滿浮芳酒春梅動，朗誦新詩夜月低。", "倏三十年如一瞬，東坡門下愧雙溪。"]'),
('e979e334-1b5f-4df4-98d6-727b7b8d3be5','廢宅嘆','方回','宋','宋诗','song-poetry','','[]','茲爲何人宅，桂柏猶蒼蒼。',144,'全唐诗/poet.song.230000.json','["茲爲何人宅，桂柏猶蒼蒼。", "樓閣已傾卸，下有室與堂。", "窗戶半拆卸，髹漆留餘光。", "釜去存破竈，畫剝欹頹牆。", "想見全盛時，日夜崇豆觴。", "書塾在其左，子弟聲琅琅。", "問今安所往，豈不有死喪。", "死喪則不然，避兵移他鄉。", "他鄉亦不遠，深阻踰磵岡。", "自古有避地，兵來尚可避。", "惟有避役難，追逮窮所至。", "昔住大宅人，今爲忍凍民。"]'),
('86c16b45-d066-4598-8c89-4ce2f5494797','早見桃花','方回','宋','宋诗','song-poetry','','[]','離家四五程，所至盡堪驚。',48,'全唐诗/poet.song.230000.json','["離家四五程，所至盡堪驚。", "未許盜皆息，焉能軍不行。", "人移山裏住，春廢道傍耕。", "破屋知誰主，桃花照眼明。"]'),
('502bac00-cca7-44fa-8409-7eae0f39c1bd','立春日馬上遇黄國寶應犀  其一','方回','宋','宋诗','song-poetry','','[]','連宵好夢頻，二喜集佳辰。',48,'全唐诗/poet.song.230000.json','["連宵好夢頻，二喜集佳辰。", "曉霽逢春日，山深遇故人。", "立談詢近事，小酌叩荒鄰。", "暮宿東松寺，吟眸處處新。"]'),
('6debed59-cfda-43a9-a117-816197572ef7','立春日馬上遇黄國寶應犀  其二','方回','宋','宋诗','song-poetry','','[]','十載亂離頻，何知有此辰。',48,'全唐诗/poet.song.230000.json','["十載亂離頻，何知有此辰。", "翩躚果下馬，突兀眼中人。", "野店春盤共，僧房夜榻鄰。", "吾宗老仙伯，題墨尚如新。"]'),
('9a6d5ee4-18e3-44fb-a725-d380392efea4','宿東松寺','方回','宋','宋诗','song-poetry','','[]','一僧垂亂髪，杉閣夜寒饒。',48,'全唐诗/poet.song.230000.json','["一僧垂亂髪，杉閣夜寒饒。", "開鎖容鋪榻，求錢爲造橋。", "獼猴窗外嘯，鼯鼠燭前跳。", "岳筆親題壞，前朝恨未銷。"]'),
('5f93d70d-71f4-4454-9081-8a1a5b3eff00','牛頭嶺下老人','方回','宋','宋诗','song-poetry','','[]','九十前朝老，髯疏骨亦清。',48,'全唐诗/poet.song.230000.json','["九十前朝老，髯疏骨亦清。", "相形宜老壽，說夢憶昇平。", "田屋臨官道，孫男給遞兵。", "興州馘狂賊，曾見捷旗行。"]'),
('3c8e2f11-c885-41dc-b9c2-f6965e074ee1','題苦竹港寓壁','方回','宋','宋诗','song-poetry','','[]','三十年前此路行，來車去馬唱歌聲。',64,'全唐诗/poet.song.230000.json','["三十年前此路行，來車去馬唱歌聲。", "旗亭沽酒家家好，驛舍開花處處明。", "白羽宵馳四川道，青樓春接九江城。", "如今何事無人住，移向深山說避兵。"]'),
('6c1dc569-97c7-42e3-a312-561cff99cdb4','三十年吟','方回','宋','宋诗','song-poetry','','[]','三十年爲世，吾今迫六旬。',48,'全唐诗/poet.song.230000.json','["三十年爲世，吾今迫六旬。", "兒時前輩盡，亂後善人貧。", "未測前途闇，空追往迹陳。", "所親化埃土，猶入夢魂頻。"]'),
('fe44311b-f716-4ac9-8392-416c7c9ec717','山鷺鷥','方回','宋','宋诗','song-poetry','','[]','行行萬山頂，無復大陂池。',120,'全唐诗/poet.song.230000.json','["行行萬山頂，無復大陂池。", "小磵清且駛，時見白鷺鷥。", "有魚必不大，何况亦無之。", "聯拳一孤影，盡日沙邊窺。", "七澤足鮮食，曷不往彼爲。", "公子以臆對，羽族幸産茲。", "腹腸能幾何，少許可無饑。", "井鮒尚不顧，王鮪安所思。", "鸕鷀善攫捕，扼吭富漁師。", "雖貪亦不飽，孰若廉自持。"]'),
('f1fa3382-cc1b-4b80-ad0b-996dcd7f22f8','來去路','方回','宋','宋诗','song-poetry','','[]','後山路安來，前山路安去。',120,'全唐诗/poet.song.230000.json','["後山路安來，前山路安去。", "高中不無低，自有可通處。", "譬如澗谷水，日夜泉源注。", "但聞水流聲，不見來去路。", "避礙適其順，智本何所惡。", "後世窮梯航，乃以嗜欲故。", "漢武天馬歌，文采誠獨步。", "焉知十萬師，暴骨委秋露。", "我願四達衢，但行商與賈。", "一遇荷戈人，寸跬不可度。"]'),
('2270582c-8169-4c5a-9465-e2dba3768e56','雖然吟五首  其一','方回','宋','宋诗','song-poetry','','[]','林下機聲復碓聲，時時犬吠又雞鳴。',32,'全唐诗/poet.song.230000.json','["林下機聲復碓聲，時時犬吠又雞鳴。", "雖然此是尋常物，村落聞之即太平。"]'),
('a0a191f9-6bce-4ede-bc0d-76039e7cc346','雖然吟五首  其二','方回','宋','宋诗','song-poetry','','[]','沽酒人家短竹籬，門前三兩牧牛兒。',32,'全唐诗/poet.song.230000.json','["沽酒人家短竹籬，門前三兩牧牛兒。", "雖然此是尋常物，軍馬才過不見之。"]'),
('f94dd19f-81f8-4ae9-ad52-9c30679d1493','雖然吟五首  其三','方回','宋','宋诗','song-poetry','','[]','桑柘陰陰間苧麻，店前下馬便斟茶。',32,'全唐诗/poet.song.230000.json','["桑柘陰陰間苧麻，店前下馬便斟茶。", "雖然此是尋常物，亂後空村沒一家。"]'),
('caf68e4d-be64-4716-972f-7a63ac685673','雖然吟五首  其四','方回','宋','宋诗','song-poetry','','[]','大婦銀釵小綠裙，採茶洗菜踏溪雲。',32,'全唐诗/poet.song.230000.json','["大婦銀釵小綠裙，採茶洗菜踏溪雲。", "雖然此是尋常物，一旦無蹤爲過軍。"]'),
('8a5dd0e3-d659-4b24-8047-a704aa57e00b','雖然吟五首  其五','方回','宋','宋诗','song-poetry','','[]','屋上炊煙屋下燈，客來汲井具瓶繩。',32,'全唐诗/poet.song.230000.json','["屋上炊煙屋下燈，客來汲井具瓶繩。", "雖然此是尋常物，不是承平見不能。"]'),
('e1de7d5d-76d7-457b-9c63-34fbef529441','客中近元夕','方回','宋','宋诗','song-poetry','','[]','新晴春早暖，客裏上元天。',48,'全唐诗/poet.song.230000.json','["新晴春早暖，客裏上元天。", "輦路燈如夢，璇霄月欲圓。", "豈惟無酒酤，不復有床眠。", "歌舞愚兒輩，凄凉已十年。"]'),
('ebd9ec21-66f4-4922-a3ff-db95b997cb43','見梅','方回','宋','宋诗','song-poetry','','[]','翠竹陰森護槿籬，玉梅庭院粉牆欹。',32,'全唐诗/poet.song.230000.json','["翠竹陰森護槿籬，玉梅庭院粉牆欹。", "幾年避地無人住，猶有花開一兩枝。"]'),
('1f754869-c496-45da-98f9-a973812a31ca','野廟','方回','宋','宋诗','song-poetry','','[]','金甲朱衣畫壁昏，軍聲不到暫開門。',32,'全唐诗/poet.song.230000.json','["金甲朱衣畫壁昏，軍聲不到暫開門。", "數家祈福來澆奠，剪紙糊燈作上元。"]'),
('ac2afdd2-0c3d-4c3b-bfa5-2c1373a4658c','鄱陽分水嶺','方回','宋','宋诗','song-poetry','','[]','轉山五七里，涉磵十百所。',216,'全唐诗/poet.song.230000.json','["轉山五七里，涉磵十百所。", "碎石鐵蒺藜，銳石木齟齬。", "豈但行人難，亦復念我馬。", "水涸尚自可，况乃值過雨。", "正月春氣動，江南異北土。", "崖溜一已滴，奔湍怒如鼓。", "緬懷十載前，荆蜀及湓渚。", "大閫走鈴檄，雜遝混民旅。", "此驛既已廢，十步九榛莽。", "軍行不齎糧，所至頼鈔擄。", "中産得幾家，遷避入深塢。", "窮戶無一物，草棘障環堵。", "前岡二客來，望我百步許。", "意其爲武夫，疾走蔽險阻。", "人情既可見，避兵如避虎。", "矧肯治私道，築削費杵斧。", "叢篁鳴野鳥，黯黯天欲雨。", "老矣爲此遊，作詩記良苦。"]'),
('398e9da2-0477-4f1d-a862-441a300042d0','石頭田','方回','宋','宋诗','song-poetry','','[]','晝欲求一淘，有竈無竈煙。',240,'全唐诗/poet.song.230000.json','["晝欲求一淘，有竈無竈煙。", "夜欲求一榻，有屋無屋椽。", "歷歷數百里，無人居道邊。", "問言何至此，我亦爲恍然。", "江西走荆蜀，行行三十年。", "鈴卒遞羽檄，販夫駢擔肩。", "觀國上秀士，奉使驟達官。", "車馬或相遇，往往皆衣冠。", "後隴竹未斷，前坡花已妍。", "入肆欲美酒，既醉不問錢。", "是時鬢如漆，浩歌無憂端。", "豈謂再至此，滿頤霜雪攢。", "尋覓舊題壁，脫落迷榛菅。", "乾淳老前輩，間有數字完。", "昔時所見人，往往沉重泉。", "翕張孰移斡，隆替更變遷。", "雲曖淡竹嶺，雨昏石頭田。", "我僕既已惰，我馬復不前。", "慷慨一以思，古有行路難。", "難更莫如今，懷古空永嘆。"]'),
('7e8318b8-a064-4126-9707-912616e8fe59','甲子雨','方回','宋','宋诗','song-poetry','','[]','紫陽元日得晴日，曉鵲聲邊駢賀客。',160,'全唐诗/poet.song.230000.json','["紫陽元日得晴日，曉鵲聲邊駢賀客。", "玉梅爛漫照椒觴，盡我真珠紅一石。", "祁山山下初立春，馬上送迎逢故人。", "故人挈榼藉芳草，啼鳥遊絲天氣新。", "吟鞭轉入西江路，寶月欲圓碧霄暮。", "南方戰罷聞者喜，盡道上元仍甲子。", "卒然軍興由盜興，千里無煙况有燈。", "雞犬逃生且未暇，上元之雨吾何憎。", "萬馬還營速須早，放與田家蠶麥好。", "甲子之雨恐不可，聽彼謠言愁殺我。"]'),
('8f891fc6-a922-46e3-8742-62751fc62674','雨曉','方回','宋','宋诗','song-poetry','','[]','春空蒸小雨，漠漠復紛紛。',48,'全唐诗/poet.song.230000.json','["春空蒸小雨，漠漠復紛紛。", "枯石皆生水，平田亦出雲。", "氣溫衾暗覺，聲細枕微聞。", "今日迎人馬，西郊草欲薰。"]'),
('2ac0371b-115e-4a6c-98b8-0c40ee30adfe','細雨','方回','宋','宋诗','song-poetry','','[]','云無又有之，細亦不毫絲。',48,'全唐诗/poet.song.230000.json','["云無又有之，細亦不毫絲。", "未許迎眸數，才容灑面知。", "積能成樹滴，散忽被風吹。", "野燒痕初動，春鞭政要詩。"]'),
('535a83cd-baab-4c40-8e8b-c2d4f28dc8e6','石門市','方回','宋','宋诗','song-poetry','','[]','村村籬落似，慈竹密如雲。',48,'全唐诗/poet.song.230000.json','["村村籬落似，慈竹密如雲。", "鬨市千家聚，康莊五郡分。", "連門香白酒，倚戶粲紅裙。", "今日尋荒店，無薪給午饙。"]'),
('2d58e89d-de0f-4aed-b0d8-55534280f6f9','上元晚晴','方回','宋','宋诗','song-poetry','','[]','所謂上元者，俗以侈昇平。',168,'全唐诗/poet.song.230000.json','["所謂上元者，俗以侈昇平。", "漢用方士說，祠祭夜達明。", "爇炬或始此，游觀實何名。", "年登庶事遂，春早芳意萌。", "冶粧飾粉黛，豪奏喧絲笙。", "愚玩奪稚魄，淫窺蕩狂情。", "天寶覆唐都，宣和傾汴京。", "詞人麗唱在，物極良足驚。", "一隅頗完盛，四運遄代更。", "戍守列萬里，鎮防連百城。", "崛起間竊發，交馳事遐征。", "昏黑煙火滅，哭聲無歌聲。", "曉雨花信過，夜蟾桂輪清。", "時節既如此，焉問陰與晴。"]'),
('aa3ce336-4b13-4cbe-b995-20718cf13c3d','彭澤道中懷嚴陵','方回','宋','宋诗','song-poetry','','[]','人生千萬事，都不似歸來。',48,'全唐诗/poet.song.230000.json','["人生千萬事，都不似歸來。", "是澤魚堪釣，何田稻不栽。", "客行元亮邑，家寄子陵臺。", "緬想二賢迹，吾顔亦靦哉。"]'),
('c35e13eb-7a5f-41ef-8985-06ffb95d137e','梧桐嶺','方回','宋','宋诗','song-poetry','','[]','飛石危如墜，枯桐死不春。',48,'全唐诗/poet.song.230000.json','["飛石危如墜，枯桐死不春。", "霧深云有虎，茅動故愁人。", "破屋潜饑嫗，荒祠畫怪神。", "步行牽瘦馬，背汗浹寒身。"]'),
('6bb5b192-92d5-4ae3-9dbd-8a7e3963b313','梧桐嶺感舊','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶上梧桐嶺，江淮萬里開。',48,'全唐诗/poet.song.230000.json','["憶上梧桐嶺，江淮萬里開。", "匡廬天外畫，彭蠡地中杯。", "暖欲還燕雁，香應落庾梅。", "重來感時序，更覺子山哀。"]'),
('bf7a01bf-89e9-40cf-9aea-48eceb7554fb','望廬山懷舊','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夜入廬山路，開元萬柱宮。',48,'全唐诗/poet.song.230000.json','["夜入廬山路，開元萬柱宮。", "穿廊石渠水，凉座竹林風。", "羽客談霏雪，星郎氣吐虹。", "劫灰如可問，無復昔人同。"]'),
('8ed4b418-ca05-40f3-aab5-bd3b723c03cf','湖口寄方去言','方回','宋','宋诗','song-poetry','','[]','不見秋崖老，吾宗尚有人。',240,'全唐诗/poet.song.230000.json','["不見秋崖老，吾宗尚有人。", "十年疲遠夢，七尺記長身。", "醉月金陵曉，遨花輦路春。", "雁題盟未爽，鶴化事遄新。", "稍覺高閎改，徐行曲巷詢。", "應門才入謁，下榻愧爲賓。", "小閣書窗凈，芳筵飲斚醇。", "盡令諸子拜，更許大難親。", "積廡芻糧溢，堆盤果餌珍。", "和篇勤唾玉，枉教妙鈎銀。", "霽雨微膏野，和風早應辰。", "挈壺煩僕御，並轡出城闉。", "繾綣情何厚，殷勤意甚真。", "道傍分手暫，隴上轉頭頻。", "無復離懷惡，誰云古誼陳。", "長郎仍遠餞，羈客倍驚神。", "跋涉將千里，漂摇近一旬。", "二孤彭蠡外，五老大江濱。", "倦憩停征馭，遐思值便鱗。", "寄詩寓予感，衰老易譫諄。"]'),
('4737ebb5-6e7f-431d-a6ae-ec47fe05fb1a','旅况戲題','方回','宋','宋诗','song-poetry','','[]','行役亦何聊，聽予旅况謠。',48,'全唐诗/poet.song.230000.json','["行役亦何聊，聽予旅况謠。", "水須分嶺頂，路必過山腰。", "早問人求店，無輕馬度橋。", "衣袍不解带，側卧幾寒宵。"]'),
('32a1d662-ed78-4808-a799-573ca1b25d25','宿湖口縣','方回','宋','宋诗','song-poetry','','[]','江湖分合處，風水互東西。',48,'全唐诗/poet.song.230000.json','["江湖分合處，風水互東西。", "官禁收燈早，民居結葦低。", "二孤流俗誤，九派舊蹤迷。", "剩有登臨興，春霖滿路泥。"]'),
('1d0d42c0-b58b-48e8-a50b-1869e3b7b62f','過湖口渡','方回','宋','宋诗','song-poetry','','[]','峨峨臨峭壁，渺渺指寒洲。',48,'全唐诗/poet.song.230000.json','["峨峨臨峭壁，渺渺指寒洲。", "船壓萬鈞重，帆開一葉浮。", "雲沙連幾郡，雪浪舞中流。", "目快心還恐，吾行曷少休。"]'),
('c6f31a88-7aa1-4890-8ef4-d5d69b04cc99','次韻謝喻巖叟','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','妙年璧水播英辭，半世聞聲鬢未絲。',64,'全唐诗/poet.song.230000.json','["妙年璧水播英辭，半世聞聲鬢未絲。", "賜姓遠從梁武日，家風復見喻鳬詩。", "九霄空闊飛騰勢，萬卷縱橫講授師。", "重到廬山亦何喜，喜君知我我君知。"]'),
('0b4eec94-8a31-49c9-be31-17c8151c6301','次韻袁提學題皇甫真人清虛庵二首  其一','方回','宋','宋诗','song-poetry','','[]','清地虛天渺何許，芒鞋未往意先飛。',64,'全唐诗/poet.song.230000.json','["清地虛天渺何許，芒鞋未往意先飛。", "山中叱石初平隠，月下吹笙子晉歸。", "不死真人千劫在，無垠濁世一塵微。", "何當日嚥丹池水，長共寒猿嘯月霏。"]'),
('2db3191b-f661-4942-9de2-79e857a2bf30','次韻袁提學題皇甫真人清虛庵二首  其二','方回','宋','宋诗','song-poetry','','[]','猶憶清虛下雲漢，轉頭劫塹已灰飛。',64,'全唐诗/poet.song.230000.json','["猶憶清虛下雲漢，轉頭劫塹已灰飛。", "三山恍惚驚鼇動，千歲凄凉望鶴歸。", "風度羨君仙骨瑩，年華迫我世緣微。", "豈無道侶歌招隠，許脫紅塵卧碧霏。"]'),
('b36175bf-ad4c-468b-a62c-2ec8a9058ab6','寄呈呂道山于八桂','方回','宋','宋诗','song-poetry','','[]','朅從歙浦來湓浦，聞自全州入桂州。',64,'全唐诗/poet.song.230000.json','["朅從歙浦來湓浦，聞自全州入桂州。", "倚俟先生還北棹，定容小子到南樓。", "甘留旅瑣緣何事，積受恩私愧未酬。", "但願歲時一相見，萍蹤從昔慣漂浮。"]'),
('fa459199-141f-44ea-9b21-3ca4a751ff5a','寄彬州孫通守振武聞泝湘將至八桂','方回','宋','宋诗','song-poetry','','[]','南斗之南八桂林，携琴欲覓舊知音。',64,'全唐诗/poet.song.230000.json','["南斗之南八桂林，携琴欲覓舊知音。", "想君湘水花邊路，識我衡陽雁外心。", "偪側甲兵詢動靜，艱難書問畏浮沉。", "相煩爲報真消息，莫待春江柳色深。"]'),
('e473c470-92f8-4abb-b399-884298a2dd3d','寄劉伯宣南昌','方回','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','西浙東江昔袂分，洪都湓浦忽相聞。',64,'全唐诗/poet.song.230000.json','["西浙東江昔袂分，洪都湓浦忽相聞。", "才看陶令門前柳，却憶滕王閣上雲。", "何處魚蠻能避役，無邊鯨海尚行軍。", "詩書胸次堪籌國，定不專憑柱後文。"]'),
('2fa98b60-7877-4a79-abae-6c2b6779b546','望大江','方回','宋','宋诗','song-poetry','','[]','春草茫茫闊，春江渺渺流。',48,'全唐诗/poet.song.230000.json','["春草茫茫闊，春江渺渺流。", "斷魂欲誰訴，極目使人愁。", "更過天垂處，應無地盡頭。", "豪商似差樂，槌鼓發鹽舟。"]'),
('67fdb806-b2e9-47ba-8755-85d7b05295ac','琵琶亭感舊','方回','宋','宋诗','song-poetry','','[]','桑落洲前路，江流自北南。',48,'全唐诗/poet.song.230000.json','["桑落洲前路，江流自北南。", "美人何處在，劫火殆難堪。", "津吏苛魚稅，沙民賣席帆。", "情知白司馬，到此濕青衫。"]'),
('97981f25-eedf-453d-839d-632a1b1617cf','飲袁提學林亭','方回','宋','宋诗','song-poetry','','[]','古淡林縈沼，清輝日漏雲。',48,'全唐诗/poet.song.230000.json','["古淡林縈沼，清輝日漏雲。", "百梅先世植，一鶴舊侯分。", "天引吟懷遠，春供飲意醺。", "徐卿二雛者，已解聽論文。"]'),
('2a0f2b95-04cd-47f6-96eb-9e428d315ab0','次前韻謝袁提學及其弟府判二首  其一','方回','宋','宋诗','song-poetry','','[]','公家賢伯仲，似是晉機雲。',48,'全唐诗/poet.song.230000.json','["公家賢伯仲，似是晉機雲。", "黄卷丁年共，青燈午夜分。", "望風初魄動，飲德更心醺。", "自合登臺省，官猶類廣文。"]'),
('ca83b22c-5d63-49c5-9048-74f54cbbd1d1','次前韻謝袁提學及其弟府判二首  其二','方回','宋','宋诗','song-poetry','','[]','春亭前日聚，一徑入深雲。',48,'全唐诗/poet.song.230000.json','["春亭前日聚，一徑入深雲。", "水綠痕初漲，花紅蕾欲分。", "頻敲無好句，屢釂有餘醺。", "不減山陰勝，公宜作敘文。"]'),
('dd8e6ed6-e3de-4f8a-b907-77d3c6360dd1','次韻謝王君','方回','宋','宋诗','song-poetry','','[]','妙年富才藻，亹亹迫淵雲。',48,'全唐诗/poet.song.230000.json','["妙年富才藻，亹亹迫淵雲。", "逸勢波瀾闊，神功混沌分。", "百爲爭細故，一笑付微醺。", "天地江河在，終垂萬古文。"]'),
('43f73f69-f990-43d0-9137-5b803bdea754','梅魂次周斐然韻','方回','宋','宋诗','song-poetry','','[]','搜香索影夜凝神，楚些招還萼綠真。',64,'全唐诗/poet.song.230000.json','["搜香索影夜凝神，楚些招還萼綠真。", "月底似逢和靖老，風前恍見壽陽人。", "清寒不類巫山夢，素豔全非洛浦塵。", "尤物有靈生幻相，憑誰貌取補之春。"]'),
('7d63af8b-9236-4def-83c4-67006f15e8c5','次韻李太白','方回','宋','宋诗','song-poetry','','[]','太白配蘇黄，如松柏與竹。',96,'全唐诗/poet.song.230000.json','["太白配蘇黄，如松柏與竹。", "不受春風恩，勁氣尚可掬。", "詩名乃其餘，受命天地獨。", "間生五百年，相望若信宿。", "予老棲聖門，措辭愧言卜。", "一覽紫極題，三作白圭復。", "羣仙憫世頑，死生反乎覆。", "曷日從之游，神交道心熟。"]'),
('88078765-1e5b-4fb3-9949-684edc824d01','復次前韻四首呈二袁君併王君申祿  其一','方回','宋','宋诗','song-poetry','','[]','良辰古難得，歌吹遏行雲。',48,'全唐诗/poet.song.230000.json','["良辰古難得，歌吹遏行雲。", "豪意牛心割，清言獺膽分。", "予慚四皓老，公勝七賢醺。", "苦雨忽三日，垢衣生蘚文。"]'),
('a9166bf1-cd10-4b9c-bc16-9ae5eda48b04','復次前韻四首呈二袁君併王君申祿  其二','方回','宋','宋诗','song-poetry','','[]','卧雪名家彥，諸孫耳又雲。',48,'全唐诗/poet.song.230000.json','["卧雪名家彥，諸孫耳又雲。", "永懷玉筍立，肯放紫荆分。", "塤奏仍箎奏，賢醺復聖醺。", "高才能下問，所謂孔文文。"]'),
('32a95e5b-715a-4ef1-a7fc-8eb5faf3298b','復次前韻四首呈二袁君併王君申祿  其三','方回','宋','宋诗','song-poetry','','[]','今代王摩詰，詩機織錦雲。',48,'全唐诗/poet.song.230000.json','["今代王摩詰，詩機織錦雲。", "高棋饒算數，善射較毫分。", "泥屨難相過，殘樽愧獨醺。", "何時重握手，星聚應天文。"]'),
('a513aa4c-f3e9-4dc0-9b1f-3d09ee689895','復次前韻四首呈二袁君併王君申祿  其四','方回','宋','宋诗','song-poetry','','[]','老予尚行役，旅棹泛江雲。',48,'全唐诗/poet.song.230000.json','["老予尚行役，旅棹泛江雲。", "足迹更南北，時光幾至分。", "百年丁字誤，萬事卯杯醺。", "先漢功臣輩，惟宜戇少文。"]'),
('33134707-9423-4b4e-95df-749f7ad984dd','袁興國挽詞二首  其一','方回','宋','宋诗','song-poetry','','[]','憶昔予初筮，南樓丈席陪。',48,'全唐诗/poet.song.230000.json','["憶昔予初筮，南樓丈席陪。", "觀星憂世事，玩日嘆時才。", "稍訝無周夢，懸知有郢哀。", "魂今招不得，天尚鑒靈臺。"]'),
('412332a8-d446-48cf-a690-c1756adad5a9','袁興國挽詞二首  其二','方回','宋','宋诗','song-poetry','','[]','氣化神如在，名高志未伸。',48,'全唐诗/poet.song.230000.json','["氣化神如在，名高志未伸。", "文章坡老筆，丰度華陽巾。", "愷悌州符屢，旬宣閫畫頻。", "鼎台袖吾手，覆餗彼何人。"]'),
('942b4575-e75e-4a04-8638-8203ec0b063d','識山堂會飲','方回','宋','宋诗','song-poetry','','[]','醉筇斜倚杏花風，邂逅高堂六客同。',64,'全唐诗/poet.song.230000.json','["醉筇斜倚杏花風，邂逅高堂六客同。", "寓世常如超世外，識山何待到山中。", "去鴻新燕催春色，殘雪晴霞媚晚空。", "一筆寫成真面目，試憑華表問仙翁。"]'),
('00e12e9d-c64e-4787-8141-c43b48b23ad9','夢東坡先生','方回','宋','宋诗','song-poetry','','[]','夜夢東坡公，分我龍腦香。',144,'全唐诗/poet.song.230000.json','["夜夢東坡公，分我龍腦香。", "玉指撮冰雪，佩之鞶带囊。", "江湖衰老蹤，十度遊潯陽。", "始入紫極宮，勉和瓊田章。", "太白實首唱，繼以雙井黄。", "此詩豈容續，束緼儕朝陽。", "孺子可教歟，馭風來帝傍。", "跛鼈傅羽翼，恍惚追龍驤。", "文通五色筆，尚爲文字祥。", "公名蔽天壤，誰敢邀餘光。", "再拜眉山集，一上秋聲堂。", "殘馥果容丐，永流千古芳。"]'),
('6325bb8d-0eeb-43b5-9fad-5029043c2e99','湓城客思','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','客懷歷落事多違，嘆息流光似箭飛。',64,'全唐诗/poet.song.230000.json','["客懷歷落事多違，嘆息流光似箭飛。", "雪後蔞蒿初薦酒，花前蛺蝶欲穿衣。", "熟知江水磨今古，難向春風問是非。", "悵望廬山但愁絕，萬重雲鎖幾禪扉。"]'),
('441b3b56-994d-4aa0-ad09-ffda555288a3','晚登會真道堂望廬山大江作','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','春風燠江城，樓臺眩桃李。',276,'全唐诗/poet.song.230000.json','["春風燠江城，樓臺眩桃李。", "高堂一臨眺，傍觀謂予喜。", "予心實不然，俯視憫羣蟻。", "通衢鬨塵埃，委巷困泥滓。", "膏火煎熬間，樊牆限茅葦。", "溷處雜酸呻，清思何由起。", "別有天地寶，注此兩眸子。", "北拱五老峰，西傾九派水。", "冥冥淡烟外，烱烱殘雪裏。", "元氣所融結，萬古奠南紀。", "中有不死人，神遊常在此。", "安得月明夜，嘯風控赤鯉。", "導迎呵江神，殿護叱山鬼。", "脩靜無談玄，慧遠勿析理。", "亦不用湘靈，瑶瑟鼓葱指。", "稽首青蓮仙，大雅叩吟髓。", "前陶後蘇黄，相與奏宮徵。", "靈文九霄秘，玄關一時啟。", "怳兮發浩歌，洞見開闢始。", "迴謝人間世，日夜虱生蟣。", "腥膩纏臭帤，聞此穢或洗。", "黄冠似予知，具茗亦粲爾。", "歸卧不成眠，汲井漱寒齒。"]'),
('edd3f040-a8b1-416b-b17a-54692e8bbf01','用韻謝史山長德秀招飲醉甚','方回','宋','宋诗','song-poetry','','[]','日困公家酒，身浮似片雲。',48,'全唐诗/poet.song.230000.json','["日困公家酒，身浮似片雲。", "扶歸忘路遠，鼾卧過宵分。", "真是杯中聖，殊非鬲上醺。", "老饕何可數，合作送窮文。"]'),
('c188961a-081e-472c-8419-1dee4ef44728','次韻謝黎制幹','方回','宋','宋诗','song-poetry','','[]','壽垂登八十，落筆尚凌雲。',48,'全唐诗/poet.song.230000.json','["壽垂登八十，落筆尚凌雲。", "閲世千帆過，觀人一鑑分。", "黑知鬚未染，紅覺貌如醺。", "勿謂先生老，非熊或遇文。"]'),
('5033bf73-396c-46a5-b4db-8f350cc0223d','題會真道堂','方回','宋','宋诗','song-poetry','','[]','八客一道士，臨風舉茗盞。',240,'全唐诗/poet.song.230000.json','["八客一道士，臨風舉茗盞。", "孔老業不同，同具看山眼。", "其六惟坤珍，三實吳楚産。", "稟氣殊東西，粹美無可柬。", "景仙幻斯堂，土阜高𡾰嵼。", "飛來九疊雲，城闕不可限。", "泉貝似神助，草棘使鬼剗。", "有官頹厥府，視此得無赧。", "秘籙誦琅函，芳字紀玉版。", "他時千柱宮，咄嗟了鳩僝。", "吾儕昔英妙，文采炳虓虥。", "暮年閲世故，豪氣就磨鏟。", "願超栩栩夢，不受俗網綰。", "未信結鄰樓，尚隔劍門棧。", "壁間鬼谷像，怪睛一何睅。", "似與墮圯履，粉飾增著撰。", "滋長事爲心，予欲刊蠹簡。", "春色浮汀洲，荻笋初可饌。", "焉得逡巡手，百甕漉醴醆。", "醉魂遨太清，萬劫一笑莞。"]'),
('8e88ef0e-d44f-494c-970e-d2c498938bb1','次韻會真堂呈景高士','方回','宋','宋诗','song-poetry','','[]','夜卧月一枕，晨漱泉一盞。',240,'全唐诗/poet.song.230000.json','["夜卧月一枕，晨漱泉一盞。", "斯人世未識，廬阜乃具眼。", "片影下岷峨，辟穀謝常産。", "何樹不可巢，老鶴以意柬。", "岏岏九江城，九坡何嵼嵼。", "碧天落吾手，了無藩籬限。", "煙霞爭自獻，蛇鼠不待剗。", "空瓢無餘物，非病未足赧。", "山如缺一簣，城或少三版。", "汝畫古所譏，匠事誓終僝。", "愚生霧雨姿，皮毛惜文虥。", "紛華梯衝來，以道與鎸鏟。", "匣劍藏百鍊，帨巾解六綰。", "真游闢坦途，塵慮杜危棧。", "康董不可覿，覘睨費瞠睅。", "景叟無乃是，功行堪論撰。", "便堂請丹經，豈必詔青簡。", "饑從景叟遊，不顧八珍饌。", "渴聽景叟言，焉問九醖醆。", "我漫爾其聊，此粲彼亦莞。"]'),
('f79a35cd-3593-423e-910e-58fb397c0e3f','次韻謝余知郡和予識山會飲韻','方回','宋','宋诗','song-poetry','','[]','衣冠奇古舊儒風，湖海襟期臭味同。',64,'全唐诗/poet.song.230000.json','["衣冠奇古舊儒風，湖海襟期臭味同。", "七字不妨容我和，一樽酒欠與君中。", "春光是處饒生意，山色何曾礙太空。", "九疊雲屏三笑路，何當偕訪虎溪翁。"]'),
('cbbc0a72-8024-4e38-8b1d-b11cba73c13e','題觀妙軒','方回','宋','宋诗','song-poetry','','[]','前身恐是靖廬公，手擘崔嵬棟此宮。',64,'全唐诗/poet.song.230000.json','["前身恐是靖廬公，手擘崔嵬棟此宮。", "拔地三三屏特起，藏天六六洞潜通。", "淵明山氣忘言外，太白秋聲靜坐中。", "一洗丹玄童子眼，待看鸞鶴下晴空。"]'),
('d1646951-62db-41d2-bbda-41af38a76845','題金君重像雜言','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','譽之不喜，詆之不怒。',84,'全唐诗/poet.song.230000.json','["譽之不喜，詆之不怒。", "言無疾聲，行無闊步。", "青春日月儒冠誤，拂袖沙河塵土路。", "覓君不見今幾年，廬山道士房中住。", "不肥不瘦不精神，看盡鳶肩燕頷人。", "宅爲官屋骨爲塵，似我翛然雲水身。"]'),
('e957c764-7d39-490a-9eda-e1c8c6a525bd','醉醒','方回','宋','宋诗','song-poetry','','[]','酒所春歸暮，醒時已五更。',48,'全唐诗/poet.song.230000.json','["酒所春歸暮，醒時已五更。", "被驚橫蓋短，燈喜再挑明。", "小雨餘殘滴，羣蛙動暖聲。", "故園花正好，誰料客湓城。"]'),
('c856e992-8363-4e24-a2ea-3ef0877b85eb','次韻謝喻巖叟讀予近作二首  其一','方回','宋','宋诗','song-poetry','','[]','觀君於勢利，如箒掃絲窠。',48,'全唐诗/poet.song.230000.json','["觀君於勢利，如箒掃絲窠。", "閲世雲翻雨，持心濟貫河。", "端居冠必整，閒賦硯頻磨。", "我豈無新作，何堪對雅歌。"]'),
('c601d58e-797d-4ce9-ae52-bde8cae849e5','次韻謝喻巖叟讀予近作二首  其二','方回','宋','宋诗','song-poetry','','[]','鬢鬚全是雪，政坐癖於詩。',48,'全唐诗/poet.song.230000.json','["鬢鬚全是雪，政坐癖於詩。", "老不謀丹穴，貧猶泥墨池。", "今年逢旅卦，何日賦歸辭。", "得句求君訣，時容詣講帷。"]'),
('a95f2d1a-56c4-4e17-ae68-a6d8539e9e26','次韻謝呂君見寄二首  其一','方回','宋','宋诗','song-poetry','','[]','弱冠清脩更老成，詩來重慰故人情。',64,'全唐诗/poet.song.230000.json','["弱冠清脩更老成，詩來重慰故人情。", "向曾屢共阿戎語，今乃新聞侯喜聲。", "材大君當爲杞梓，器微吾僅比瓶罌。", "平生吟社彫零盡，合許忘年友與盟。"]'),
('6c73e129-fd25-44bf-b57f-15b15b0b3f81','次韻謝呂君見寄二首  其二','方回','宋','宋诗','song-poetry','','[]','鄂城未至客湓城，誰識惓惓欲見情。',64,'全唐诗/poet.song.230000.json','["鄂城未至客湓城，誰識惓惓欲見情。", "端肯寄書憑雁足，遥知求友認鶑聲。", "論心政願投膠漆，臨路良難渡水罌。", "江海一生今老矣，待來重結歲寒盟。"]'),
('030bae2e-9822-40db-9551-088784241c9d','夜大雷雨雹','方回','宋','宋诗','song-poetry','','[]','甲申春仲夜廿六，怪事可無詩史書。',64,'全唐诗/poet.song.230000.json','["甲申春仲夜廿六，怪事可無詩史書。", "星斗橫陳九霄上，風雷鼎沸一更餘。", "雹聲擊瓦疑皆碎，電影穿帷恍似虛。", "明日麥摧桃李仆，更驚無葉剩園蔬。"]'),
('212574f7-40ec-45b2-ae79-70d5aa6159b6','病酒良苦','方回','宋','宋诗','song-poetry','','[]','一醉幾於死，人疑嘔出肝。',72,'全唐诗/poet.song.230000.json','["一醉幾於死，人疑嘔出肝。", "渴燒唇舌破，毒攪胃腸酸。", "寢不知雷響，愁偏怯雨寒。", "狎徒聞必哂，醫叟療應難。", "冰水差能嚥，糜羹屢廢餐。", "從今對花處，止可啜茶看。"]'),
('ba54d861-7783-45d7-a3ce-e60a905d09cd','社日風雨病酒','方回','宋','宋诗','song-poetry','','[]','怱怱社燕時，此况豈前知。',48,'全唐诗/poet.song.230000.json','["怱怱社燕時，此况豈前知。", "道左家書斷，春蒸客舍卑。", "醉成難治病，悶賦不工詩。", "塊卧聽風雨，吾兒亦見思。"]'),
('346dc9a1-a2a6-49b4-b3d0-0c67eb0ab823','二月三十日','方回','宋','宋诗','song-poetry','','[]','酒病專欺老，詩材苦欠新。',48,'全唐诗/poet.song.230000.json','["酒病專欺老，詩材苦欠新。", "客窗廬阜雨，故圃洛花香。", "歲運江聲急，家人夜夢頻。", "遥知掃松處，笋茗正芳辛。"]'),
('1ca64f74-2327-42de-94b6-5dbcf6d0ed83','酒戒','方回','宋','宋诗','song-poetry','','[]','老身偶不飲，終夜不能眠。',96,'全唐诗/poet.song.230000.json','["老身偶不飲，終夜不能眠。", "客枕味最惡，客腸思欲穿。", "一夕飲踰量，終日不能起。", "雖非必死病，亦有可死理。", "愚者稟氣濁，賢者稟氣清。", "保此元神者，無以物喪精。", "惟酒足忘憂，無之固不可。", "少飲固自佳，過飲將殺我。"]'),
('c4d62864-15e0-4983-850b-fa2a11c74216','過社','方回','宋','宋诗','song-poetry','','[]','來時猶見雪飛花，花落今成雪委沙。',64,'全唐诗/poet.song.230000.json','["來時猶見雪飛花，花落今成雪委沙。", "旅舍燕聲春過社，禪窗蝶夢客思家。", "貓頭味薦廉泉笋，雀舌香分凈社茶。", "豈謂故園無此物，直煩博望泛仙槎。"]'),
('4fa10164-c60a-4ac7-8142-42cd09d340d5','曉枕','方回','宋','宋诗','song-poetry','','[]','春來何事客江城，欹枕懷人意屢驚。',64,'全唐诗/poet.song.230000.json','["春來何事客江城，欹枕懷人意屢驚。", "遥夜欲明風雨止，老人無睡鼓鐘清。", "苦難辭酒真成病，强欲酬詩曲徇情。", "竹密花濃歸去好，萬山深處聽鶑聲。"]'),
('845f4e45-5c1a-4122-b52f-5f596b97ef37','三月旦晚晴','方回','宋','宋诗','song-poetry','','[]','社雨彌三日，先之雹與雷。',48,'全唐诗/poet.song.230000.json','["社雨彌三日，先之雹與雷。", "已疑春色盡，忽逐晚晴迴。", "佳笋常遲出，奇花每後開。", "微寒勝驟暖，更莫十分催。"]'),
('6ab7316d-76c0-4beb-9074-fd24ebb84008','晚晴又賦','方回','宋','宋诗','song-poetry','','[]','疾風吹怒雨，天地閉青春。',48,'全唐诗/poet.song.230000.json','["疾風吹怒雨，天地閉青春。", "眼忽驚晴色，心如見故人。", "遷鶑元未老，戰馬漸無塵。", "黄鶴樓前路，輕帆好問津。"]'),
('17feeaf2-9c73-4866-9634-4c4575e8359c','初晴','方回','宋','宋诗','song-poetry','','[]','雨與花無怨，何其氣候乖。',48,'全唐诗/poet.song.230000.json','["雨與花無怨，何其氣候乖。", "寒於春不便，晴以晚爲佳。", "帆落北風舫，窗明西日齋。", "意行適鄰圃，可免汙吾鞋。"]'),
('bf4a401a-aa44-4265-84a9-df1382eaa267','復雨','方回','宋','宋诗','song-poetry','','[]','三月寒如臘，綿袍脫又添。',48,'全唐诗/poet.song.230000.json','["三月寒如臘，綿袍脫又添。", "摘花誰過戶，觀雨獨垂簾。", "伐病思奇劑，稽疑望吉占。", "客懷悶良極，晴暖亦何嫌。"]'),
('9e29e73b-ca9e-4809-bc67-7afbc5030054','李寅之招飲同登九江城  其一','方回','宋','宋诗','song-poetry','','[]','明年公七十，我老眉亦厖。',60,'全唐诗/poet.song.230000.json','["明年公七十，我老眉亦厖。", "一會豈易得，招呼酒盈缸。", "慷慨上高城，惻愴臨大江。", "雪水傾蜀峽，煙樹連淮邦。", "風景故不異，愁心私自撞。"]'),
('80f3c09f-035f-46cf-a344-65d395955f66','李寅之招飲同登九江城  其二','方回','宋','宋诗','song-poetry','','[]','契闊幾何時，六閏過如矢。',60,'全唐诗/poet.song.230000.json','["契闊幾何時，六閏過如矢。", "九歲十歲兒，婚娶見孫矣。", "皂隸忽鼎貴，王侯或橫死。", "前輩亡典刑，後生蕩廉恥。", "晤言何用多，感嘆不能已。"]'),
('d72a857e-1576-4eb8-93de-69a6c94c3d1d','李寅之招飲同登九江城  其三','方回','宋','宋诗','song-poetry','','[]','顧此昧陋質，昏冥蹈危機。',60,'全唐诗/poet.song.230000.json','["顧此昧陋質，昏冥蹈危機。", "一麾繆析土，三命空登畿。", "屢激馬援謗，終成馮衍歸。", "長騖厄道左，力耕逢歲饑。", "置之勿復道，觴來暫同揮。"]'),
('596204a2-49e6-4d51-855e-7a1c2a1b4ee7','李寅之招飲同登九江城  其四','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','清湍嚴子灘，僻塢任公寺。',60,'全唐诗/poet.song.230000.json','["清湍嚴子灘，僻塢任公寺。", "荒凉茅屋居，蹇淺石田蒔。", "危蹤璧偶完，暮景駕已稅。", "閒門幸常關，奧帙尚多味。", "遥遥匡廬山，久客果何謂。"]'),
('a7d47848-96e2-4998-a985-895f45589a8e','李寅之招飲同登九江城  其五','方回','宋','宋诗','song-poetry','','[]','覆却罔攸測，理亂非所任。',60,'全唐诗/poet.song.230000.json','["覆却罔攸測，理亂非所任。", "兀兀兔株意，哀哀鶑谷音。", "識驥伯樂眼，放麑西巴心。", "懷惠在夙昔，觀過匪斯今。", "頼公極忠厚，良用開我襟。"]'),
('9803dc58-4112-4723-a446-be3ff2d5fe52','李寅之招飲同登九江城  其六','方回','宋','宋诗','song-poetry','','[]','兄事一紀長，矩度竊願學。',60,'全唐诗/poet.song.230000.json','["兄事一紀長，矩度竊願學。", "智圓飽涉難，仁靜耐處約。", "厭事晚微聵，休官老深樂。", "遠追邴尚蹤，高謝耿鄧略。", "還觀鼎渥爻，何止萬夫怍。"]'),
('7c10b569-6b9f-4cb1-971e-bcd211cb0418','李寅之招飲同登九江城  其七','方回','宋','宋诗','song-poetry','','[]','恭惟天所賦，知命良獨難。',60,'全唐诗/poet.song.230000.json','["恭惟天所賦，知命良獨難。", "度索侈琛玩，蒸乳甘珍餐。", "小迷積巨悔，近逸生遐患。", "寡疾骨健壽，少營神閒安。", "若有物見畀，乃非彼能干。"]'),
('1d7eaecb-be85-4c37-ba99-ad7f6c72e669','李寅之招飲同登九江城  其八','方回','宋','宋诗','song-poetry','','[]','玄理本甚察，悟見獨何鮮。',60,'全唐诗/poet.song.230000.json','["玄理本甚察，悟見獨何鮮。", "請看小丙子，跪拜綵衣展。", "荻芽薦鮓脯，緩醉味豈淺。", "鞭轡慣馳奔，戈鎧覬息偃。", "我歸當復來，豈憚僕足繭。"]'),
('58654b8c-bc48-4db6-bd33-78d8d21bf645','虎渡亭觀江浪','方回','宋','宋诗','song-poetry','','[]','春風鼓大江，孰能度廣陿。',192,'全唐诗/poet.song.230000.json','["春風鼓大江，孰能度廣陿。", "似覺海東濤，頃刻上三硤。", "茲辰當改火，每歲已衣裌。", "豈意九派天，故絮未可匣。", "北顧馬當磯，西睨鴻宿夾。", "雪浪欲沃城，無復一鳬鴨。", "釘纜虞岸裂，閣舫懼崖壓。", "天吳政爾驕，水伯詎敢狎。", "津亭歎逝翁，衰鬢側烏幍。", "既昧昇天行，亦缺縮地法。", "故疇秧麥交，田事失鋤鍤。", "兒曹豈不思，杳不寄書劄。", "意所欲見人，久俟庚復甲。", "音問苦遼緬，貲用迫空乏。", "何當乘安流，平沙暮篙插。", "歸歟招白鷗，盟血尚可歃。"]'),
('220321ae-56d0-4537-a59a-0515202ed023','清明晝夜大風','方回','宋','宋诗','song-poetry','','[]','春來不住聽簷聲，日色何曾作好晴。',64,'全唐诗/poet.song.230000.json','["春來不住聽簷聲，日色何曾作好晴。", "縱有花應欺老病，偶無酒亦過清明。", "疾風惡浪摇孤壘，危枕昏燈寄此生。", "西上東歸皆未可，客懷端復向誰傾。"]'),
('05897b1e-7916-4eae-9563-b1c03c291939','登高臨大江','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','客思忽不樂，登高臨大江。',192,'全唐诗/poet.song.230000.json','["客思忽不樂，登高臨大江。", "風湍睇遥席，雲岫思幽窗。", "淮蔞昔未茁，廬瀑今已淙。", "我本休官人，曷爲栖是邦。", "中腸有所思，所思渺天末。", "戎徼融古雪，波浪日以闊。", "西從巴硤下，南與洞庭合。", "身無黄鵠翅，九疑不可越。", "宿負子錢急，歲收南畝稀。", "兒女望我還，豈不歌式微。", "彷彿漢陽樹，突兀吳王磯。", "佳音或跫然，未忍輕言歸。", "鄰牆善蓍翁，盍往决咎吉。", "鬼神素所昧，忠信詎云忒。", "聚糧別里門，業已掉臂出。", "小俟麥風凉，馬蹄患不疾。"]'),
('16fb9a98-b64a-4aec-b7f8-bab9ed9f30ec','客舍讀書','方回','宋','宋诗','song-poetry','','[]','客舍何所爲，流光坐飛騰。',240,'全唐诗/poet.song.230000.json','["客舍何所爲，流光坐飛騰。", "出遊足風雨，對晤乏友朋。", "書鴟幸輿致，歡言啟緘縢。", "拂拭蛛與蟫，曲此几上肱。", "暗眼閲細字，未覺如蚊蠅。", "刮土辨古鼎，理絲梳亂繩。", "領會劃有得，意色若自矜。", "芸香入漢室，竹簡發魏陵。", "勺飲一以醉，焉事誇如澠。", "幽窗卷且舒，倦榻卧復興。", "匪欲備顧問，詎將干召徵。", "濟物剗稚念，治生頹俗能。", "惟學足娛老，賢哲梯可升。", "忍窮定力見，返照浩氣增。", "童子未識察，招邀荒隴登。", "江之水浩浩，楚山何層層。", "歸思忽攪擾，腸肺攢鋒稜。", "行止分已定，大方無滯凝。", "一旦决雲漢，誰識天池鵬。", "且復挾我冊，掩關明孤燈。"]'),
('6cd4d7e5-50fd-4618-826d-34b37c938d50','送呂才甫之官合肥','方回','宋','宋诗','song-poetry','','[]','妙年半五十，分刺合肥城。',48,'全唐诗/poet.song.230000.json','["妙年半五十，分刺合肥城。", "楚俗雖尊武，淮鄉已息兵。", "草霜校秋獵，花雨課春耕。", "退食應多暇，書燈夜夜明。"]'),
('bc67daa9-c7e9-443a-9645-52d47650bb06','春江多大風','方回','宋','宋诗','song-poetry','','[]','春江多大風，每盛肯遽微。',180,'全唐诗/poet.song.230000.json','["春江多大風，每盛肯遽微。", "吹人雖不寒，崩浪良足唏。", "嗔讀揭几帙，妬夢摇齋扉。", "况乃駕艫栧，敢與爭狂威。", "鬰鬰羈思倦，寥寥遨侶稀。", "危陟據隄阜，遐眺窮灣圻。", "引雛鵲始大，長笋荻已肥。", "草遠安所極，絮殘猶自飛。", "睠此惜暮景，感愴將疇依。", "去國候屢改，懷人事多違。", "袍弊苦膚汗，藥覂懼脈痱。", "豈無一杯酒，脯茹與同揮。", "道契詎易致，心賞何可幾。", "天地身一蟻，舉動有是非。", "洶湧復洶湧，四顧吾安歸。"]'),
('01858894-176d-47bb-8075-3acb7b2b0e90','晚春客愁五絕  其一','方回','宋','宋诗','song-poetry','','[]','江外蘆芽老，城中柳絮飛。',24,'全唐诗/poet.song.230000.json','["江外蘆芽老，城中柳絮飛。", "春風猶幾日，誰與濯征衣。"]'),
('aa99be7c-b890-4dce-bfa7-84f3c72af382','晚春客愁五絕  其二','方回','宋','宋诗','song-poetry','','[]','春老魚苗動，江肥雪水來。',24,'全唐诗/poet.song.230000.json','["春老魚苗動，江肥雪水來。", "大孤山下路，何日泛舟迴。"]'),
('8fe894bb-0cc7-4524-b18f-97fb7d05d0e9','晚春客愁五絕  其三','方回','宋','宋诗','song-poetry','','[]','想歸歸未得，悔醉醉還頻。',24,'全唐诗/poet.song.230000.json','["想歸歸未得，悔醉醉還頻。", "不料湓江上，題詩送晚春。"]'),
('ee426f1d-ec83-4218-af14-286720028788','晚春客愁五絕  其四','方回','宋','宋诗','song-poetry','','[]','十載干戈後，辛勤蒔牡丹。',24,'全唐诗/poet.song.230000.json','["十載干戈後，辛勤蒔牡丹。", "豈知身是客，借與別人看。"]'),
('838cc188-179d-43ca-af29-eb2648b39028','晚春客愁五絕  其五','方回','宋','宋诗','song-poetry','','[]','老身何可病，客舍只宜晴。',24,'全唐诗/poet.song.230000.json','["老身何可病，客舍只宜晴。", "曉鼎催煎藥，窗間又雨聲。"]'),
('53e56abd-98d2-49d9-912c-b2b6470348ea','薄遊嘆','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','薄遊庾公樓，俯仰三十載。',120,'全唐诗/poet.song.230000.json','["薄遊庾公樓，俯仰三十載。", "觸目昔人非，惟有廬山在。", "巴峽挾洞庭，彭蠡注滄海。", "奔濤何時休，故道終不改。", "扁舟事如昨，緇鬢忽已皠。", "俗隘路方棘，體病氣未餒。", "春盡困旅瑣，此意果誰待。", "欲見湘南人，問之以蘭茝。", "川途恐寇暴，徒御鮮資賄。", "危腸日九迴，山茹且歸採。"]'),
('58e27f89-8854-4530-adab-86f6fb50231b','會真吟','方回','宋','宋诗','song-poetry','','[]','俗緣罥區中，幽意傒方外。',120,'全唐诗/poet.song.230000.json','["俗緣罥區中，幽意傒方外。", "茲坡一褰裳，萬事忽蟬蛻。", "心與江流遠，眼逐天宇大。", "小軒納空明，坐覺衆真會。", "獨樹表高原，遥峰淡微靄。", "倦喜牀座穩，渴賞茗味最。", "道人有神丹，一撮似可丐。", "愧我屋宅老，朽壁詎堪繪。", "思歸僮僕嗔，忍饑兒女慨。", "雲卧殊未可，當且還釣瀨。"]'),
('fa7cf4ff-9c7b-4f26-bcd0-5a95f90ce8d6','四月一日早聞鶑','方回','宋','宋诗','song-poetry','','[]','客裏花都盡，初聞曉樹鶑。',24,'全唐诗/poet.song.230000.json','["客裏花都盡，初聞曉樹鶑。", "鶑聲雖已老，畢竟是鶑聲。"]'),
('16ef5d1f-eeba-443b-ac34-8a44cc3a3084','江望','方回','宋','宋诗','song-poetry','','[]','晴江望不極，滉漾照愁人。',48,'全唐诗/poet.song.230000.json','["晴江望不極，滉漾照愁人。", "黄鳥聲初動，青梅味已新。", "越鄉慚古節，樂事負良辰。", "獨立高原上，霜毛颯墊巾。"]'),
('2fc62fe0-9795-4e62-a447-a28023237023','春殘歸思','方回','宋','宋诗','song-poetry','','[]','春殘江水匝江城，尚憶初來雪未晴。',64,'全唐诗/poet.song.230000.json','["春殘江水匝江城，尚憶初來雪未晴。", "果菜芳辛頻代謝，禽魚孕育各生成。", "晝長獨坐拍棋子，夜靜不眠欹柝聲。", "南望湘灕杳無耗，黟峰桐峴最關情。"]'),
('99c3fa66-ea18-4d10-a117-8510ca169fdb','四月十三日立夏','方回','宋','宋诗','song-poetry','','[]','百年春一年，四月月將圓。',48,'全唐诗/poet.song.230000.json','["百年春一年，四月月將圓。", "客邸淹長日，歸途逼暑天。", "鶑聲時一囀，蠶事欲三眠。", "節物還如舊，情懷自可憐。"]'),
('c397332d-3b9f-4fd8-b464-de8c2e42a9ea','牟德範題范石湖墨蹟次韻','方回','宋','宋诗','song-poetry','','[]','亨衢進補華蟲衮，暮景歸調姹女爐。',32,'全唐诗/poet.song.230000.json','["亨衢進補華蟲衮，暮景歸調姹女爐。", "此老筆端今或有，乾淳蹉了後來無。"]'),
('960bef86-de83-436f-b6ad-5e7e65b04c88','贈高相士二首  其一','方回','宋','宋诗','song-poetry','','[]','武安何謂銳頭將，貞觀才無福手民。',32,'全唐诗/poet.song.230000.json','["武安何謂銳頭將，貞觀才無福手民。", "世上封侯人不少，封侯人是殺人人。"]'),
('b31f1553-a88c-4451-b093-cd554aba7395','贈高相士二首  其二','方回','宋','宋诗','song-poetry','','[]','販商公事名才吏，鈔掠平人號戰多。',32,'全唐诗/poet.song.230000.json','["販商公事名才吏，鈔掠平人號戰多。", "相貌奇厖心慘刻，天生此輩欲如何。"]'),
('e8fbc944-7145-4e71-a6ff-08c3cfc84554','爲牟德範題石湖遺墨意有未盡復賦五首  其一','方回','宋','宋诗','song-poetry','','[]','青春日月羈塵鞅，朱夏乾坤熾暑爐。',32,'全唐诗/poet.song.230000.json','["青春日月羈塵鞅，朱夏乾坤熾暑爐。", "略對風簷紬古卷，閒愁吹得一星無。"]'),
('4cb14e59-f197-4954-96be-a9a37082b351','爲牟德範題石湖遺墨意有未盡復賦五首  其二','方回','宋','宋诗','song-poetry','','[]','漢陵往事餘金碗，湘步空名尚鐵爐。',32,'全唐诗/poet.song.230000.json','["漢陵往事餘金碗，湘步空名尚鐵爐。", "地下中郎今不作，典刑真屬虎賁無。"]'),
('566aeb44-bd96-4b03-bfc4-50ec875f37af','爲牟德範題石湖遺墨意有未盡復賦五首  其三','方回','宋','宋诗','song-poetry','','[]','不尋蓬島求仙藥，肯羨銅山侈賜爐。',32,'全唐诗/poet.song.230000.json','["不尋蓬島求仙藥，肯羨銅山侈賜爐。", "獨有平生嗜古癖，誰知東郭履全無。"]'),
('f1cd2dd6-3c6d-4ba2-ba22-eef9f9f39ffa','爲牟德範題石湖遺墨意有未盡復賦五首  其四','方回','宋','宋诗','song-poetry','','[]','傳道府中澆茗碗，靈堅隴畔炷薰爐。',32,'全唐诗/poet.song.230000.json','["傳道府中澆茗碗，靈堅隴畔炷薰爐。", "銀鈎繭紙閑舒卷，錐也無時未是無。"]'),
('04f3b4ed-2a97-4d1f-9c24-a48da4a2a68d','爲牟德範題石湖遺墨意有未盡復賦五首  其五','方回','宋','宋诗','song-poetry','','[]','日長饑雀窺鐺釜，雨過跳蛙上竈爐。',32,'全唐诗/poet.song.230000.json','["日長饑雀窺鐺釜，雨過跳蛙上竈爐。", "莫笑曬書亡玉軸，荆州還識半人無。"]'),
('cf39f281-7ccd-47da-9e4d-4511ef74dd9f','夢覺聞舂','方回','宋','宋诗','song-poetry','','[]','湖海餘生在，桑榆暮景閑。',48,'全唐诗/poet.song.230000.json','["湖海餘生在，桑榆暮景閑。", "祇堪娛老圃，焉用訪名山。", "鄰屋曉舂急，客牀鄉夢還。", "江天啼鴂處，殘月幾迴彎。"]'),
('92709207-f53f-4cc2-abb8-46a59d03b9a5','飲商氏普安堂','方回','宋','宋诗','song-poetry','','[]','仙家天地在壺中，誰到壺中識此翁。',64,'全唐诗/poet.song.230000.json','["仙家天地在壺中，誰到壺中識此翁。", "一念人人皆上壽，四時日日是春風。", "偶開古畫驚神品，頻換佳花玩化工。", "玉醑金釵香夢斷，歸來晴月掛梧桐。"]'),
('575e3d65-c363-4389-9c78-af4b1b882e1c','四月二十二日別江州謝送者','方回','宋','宋诗','song-poetry','','[]','出城煩送客，童稚亦相隨。',48,'全唐诗/poet.song.230000.json','["出城煩送客，童稚亦相隨。", "貌比初來老，行因共語遲。", "橋邊分手後，馬上轉頭時。", "欲識陽關曲，唯須誦此詩。"]'),
('5ad372f1-cf8c-438f-aa3d-f12235b1741a','唁織簑翁','方回','宋','宋诗','song-poetry','','[]','繫馬籬邊樹，春初此叩扉。',48,'全唐诗/poet.song.230000.json','["繫馬籬邊樹，春初此叩扉。", "行人求茗飲，老父售簑衣。", "忽已空無物，云何去不歸。", "杵亡石臼破，殘麥化蛾飛。"]'),
('e078b40b-7d13-414e-a965-48b3f9357fa9','湖口阻風','方回','宋','宋诗','song-poetry','','[]','濤江白雪噴蒼旻，晚日紅金緣翠雲。',32,'全唐诗/poet.song.230000.json','["濤江白雪噴蒼旻，晚日紅金緣翠雲。", "天著此奇刮詩眼，略須掇實張吾軍。"]'),
('593028f4-e2e4-4ea7-a921-1c71dfc26c3d','過湖口望廬山','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江行初見雪中梅，梅雨霏微棹始迴。',32,'全唐诗/poet.song.230000.json','["江行初見雪中梅，梅雨霏微棹始迴。", "莫道無人肯相送，廬山猶自過湖來。"]'),
('c0ab962c-e9d9-4607-adbe-edc59cba19cd','繅絲吟','方回','宋','宋诗','song-poetry','','[]','行役過桑野，適值絲事成。',84,'全唐诗/poet.song.230000.json','["行役過桑野，適值絲事成。", "繅者無勞色，繅車無怨聲。", "彼美冶容子，高樓吹玉笙。", "一夕缺儷偶，憤切含離情。", "被綺食珍鼎，迭慾生驕盈。", "蠶婦雖繿縷，君子未可輕。", "所以不可輕，能保秋霜貞。"]'),
('f4d19822-5924-494f-9222-3083758f7e45','彭湖道中雜書五首  其一','方回','宋','宋诗','song-poetry','','[]','一夜大雷電，神喧復鬼譁。',36,'全唐诗/poet.song.230000.json','["一夜大雷電，神喧復鬼譁。", "橫岡風折樹，漲路雨頹沙。", "小小閒籬落，依然自野花。"]'),
('0c951406-3020-443d-bc55-9259e33e272e','彭湖道中雜書五首  其二','方回','宋','宋诗','song-poetry','','[]','近傳羣盜息，稍免大軍興。',36,'全唐诗/poet.song.230000.json','["近傳羣盜息，稍免大軍興。", "閉戶聞村學，挑包遇野僧。", "籬間犬見客，狂吠極堪憎。"]'),
('d9737ecc-de89-432e-9599-8d09eb5cc39e','彭湖道中雜書五首  其三','方回','宋','宋诗','song-poetry','','[]','陰風號亂樹，薄日照荒原。',36,'全唐诗/poet.song.230000.json','["陰風號亂樹，薄日照荒原。", "古堠泥埋字，空廬棘障門。", "無人天欲暮，誰謂不銷魂。"]'),
('9bee0fe4-137f-4256-beac-3bc3c9e1e6ff','彭湖道中雜書五首  其四','方回','宋','宋诗','song-poetry','','[]','四月農家雨，新晴冷似秋。',36,'全唐诗/poet.song.230000.json','["四月農家雨，新晴冷似秋。", "炊煙籠屋潤，田水破塍流。", "老父携孫子，牽耕教小牛。"]'),
('5d3ca6bb-0e16-4ca9-b761-b8646eff4adc','彭湖道中雜書五首  其五','方回','宋','宋诗','song-poetry','','[]','每逢田野老，定勝市廛人。',36,'全唐诗/poet.song.230000.json','["每逢田野老，定勝市廛人。", "雖復語言拙，終然懷抱真。", "如何官府吏，專欲困農民。"]'),
('6616af95-4a58-4785-b769-cb88fe23b34b','泥行嘆','方回','宋','宋诗','song-poetry','','[]','一彀十石弩，一吸三斗醋。',132,'全唐诗/poet.song.230000.json','["一彀十石弩，一吸三斗醋。", "叵堪寧可耐，莫行爛泥路。", "江臯一夜雨，田水縱橫注。", "深泥三尺餘，淺泥沒草屨。", "大似叱犁耙，濺面涴袍袴。", "今年命大乖，十事九謬誤。", "昨日湖口西，欲渡不得渡。", "今日湖口東，一步成十步。", "最念荷擔夫，馬上屢迴顧。", "我馬亦虺隤，臨危更多怖。", "誰使汝爲客，可嘆不可怒。"]'),
('3fa09277-975a-4358-b469-fd2074f67cea','陳家岡','方回','宋','宋诗','song-poetry','','[]','倦馬鞍韉破，傭奴糗茹陳。',48,'全唐诗/poet.song.230000.json','["倦馬鞍韉破，傭奴糗茹陳。", "不爲終老計，猶作遠行身。", "惶惑逢岐路，遲留俟過人。", "經時無可問，極目盡荆榛。"]'),
('1f8d294a-8a83-479b-a80d-19eb64333103','鄱陽道中','方回','宋','宋诗','song-poetry','','[]','舟楫仍鞍馬，年年事遠征。',48,'全唐诗/poet.song.230000.json','["舟楫仍鞍馬，年年事遠征。", "長禁波浪惡，罕見道途平。", "詩酒唯疏放，乾坤尚甲兵。", "吾衰甘已矣，正爾負平生。"]'),
('ebb269c9-b773-47e7-98a1-656a15b73c02','淡竹嶺農家','方回','宋','宋诗','song-poetry','','[]','茅塢石巉巖，無雲亦有嵐。',48,'全唐诗/poet.song.230000.json','["茅塢石巉巖，無雲亦有嵐。", "紙材槌稚竹，泉筧穴枯杉。", "跣足何曾襪，赬肩或不衫。", "鄰家石茶磨，婦借自能擔。"]'),
('da89d773-94f7-4405-a0e7-12f6df3629c4','牛觸馬','方回','宋','宋诗','song-poetry','','[]','誰家一大樹，繫者水牯牛。',108,'全唐诗/poet.song.230000.json','["誰家一大樹，繫者水牯牛。", "我馬過其側，道狹還無由。", "牛輒奮雙角，直前舂馬喉。", "傷馬已不可，傷人吾何仇。", "鼻繩忽迸决，驚墮荒泥陬。", "我急策馬去，牛尚瞠怒眸。", "事有出不意，君子焉所尤。", "古來行路難，曷不偃舊丘。", "歸歟偃舊丘，無爲牛所摟。"]'),
('dd209bbf-e80d-4c19-a79f-ac727fd919ad','店紿嘆','方回','宋','宋诗','song-poetry','','[]','均爲橫目民，賢否天壤異。',180,'全唐诗/poet.song.230000.json','["均爲橫目民，賢否天壤異。", "苟懷長者心，必徇君子義。", "道途分兩岐，書木立標識。", "行人免顛迷，豈不亦一惠。", "大澤陷項王，亡楚固天意。", "奈何效田父，動以紿爲智。", "軍旅比騷動，所至盡遷避。", "有屋空無人，有人門亦閉。", "隔籬繆云云，前有佳店肆。", "荒榛狼虎間，日暮竟無詣。", "嘻其孰使然，險薄乃至是。", "試嘗評往冊，匪敢立怪議。", "友或失之初，絕交宜早計。", "臨危乃賣之，吾終罪酈寄。", "嗚呼今之人，此輩殆滿世。"]'),
('e1bb3578-2a97-4ca4-893a-d57f0983be08','祁門界','方回','宋','宋诗','song-poetry','','[]','辛苦營花圃，他鄉過一春。',48,'全唐诗/poet.song.230000.json','["辛苦營花圃，他鄉過一春。", "馬兼人並老，僕笑主何貧。", "尚憶桃符改，俄驚麥飯新。", "吾州才入望，山色碧無塵。"]'),
('6f0e8063-20fe-4fd9-8b94-ee0bb6735669','大北早行','方回','宋','宋诗','song-poetry','','[]','重霧鬚髯濕，深林草樹香。',48,'全唐诗/poet.song.230000.json','["重霧鬚髯濕，深林草樹香。", "山中人未起，馬上曉偏凉。", "晴屋懸新麥，寒田蒔晚秧。", "近來兵事息，煙火漸微茫。"]'),
('ecdb9f6b-4e68-4a1f-8247-3316c7e418b2','早過牛頭嶺','方回','宋','宋诗','song-poetry','','[]','吾行十餘里，未有一人行。',48,'全唐诗/poet.song.230000.json','["吾行十餘里，未有一人行。", "不見炊煙起，唯聞野水鳴。", "日輪山罅出，露點草頭明。", "處處防豺虎，田家晏始耕。"]'),
('253f7ea3-e233-4a6d-a46d-3411b3264e54','魚亭觀山','方回','宋','宋诗','song-poetry','','[]','人間第一歙州山，絕妙魚亭古道間。',32,'全唐诗/poet.song.230000.json','["人間第一歙州山，絕妙魚亭古道間。", "描取此奇入詩句，西遊端的不虛還。"]'),
('48e382eb-1360-4bdb-8a29-522dfa21c000','魚亭再賦','方回','宋','宋诗','song-poetry','','[]','山好如斯極，吾歸亦可遲。',48,'全唐诗/poet.song.230000.json','["山好如斯極，吾歸亦可遲。", "人間好吟者，馬上細看之。", "莫訝迴頭數，端能具眼誰。", "不隨時事改，三嘆紫微詩。"]'),
('2d0bdda6-ea35-4777-becc-bb958d19391a','五月旦抵舊隠','方回','宋','宋诗','song-poetry','','[]','柳萌整征鞍，杏熟卸歸馱。',204,'全唐诗/poet.song.230000.json','["柳萌整征鞍，杏熟卸歸馱。", "風帆輟湘遊，雲屋返黟卧。", "天暑室人瘦，地荒園叟惰。", "長男近弄瓦，累重詎足賀。", "次男久投筆，學廢不堪課。", "阿高兄子之，性剛未少剉。", "阿明垂四齡，語遲無可奈。", "一事獨慰意，添竹踰百箇。", "碧玉韻凉颸，我倡此君和。", "鄰友各有携，野僧亦見過。", "陶門故常關，孔客復滿座。", "微言訂近役，何苦觸塵堁。", "筋骸已衰老，蹤迹尚奔播。", "八字馬交馳，一生蟻旋磨。", "晚節休官心，悼猛就新愞。", "豈其尚有求，未甘忍寒餓。", "神魂倘可收，焉俟賦招些。"]'),
('ede931fa-4b87-4d48-9184-5b81ad5dbbeb','甲申生日','方回','宋','宋诗','song-poetry','','[]','劬勞永感正關情，厚意殷勤荷友生。',64,'全唐诗/poet.song.230000.json','["劬勞永感正關情，厚意殷勤荷友生。", "隔日移庖成劇醉，終朝欹枕困餘酲。", "略加芎煮香蘇飲，少著鹽庖苦蕒羹。", "數首詩詞懶酬和，杜門止酒始神清。"]'),
('f1e54bc2-a75b-4656-ab33-5331f13bb785','生日戲歌','方回','宋','宋诗','song-poetry','','[]','予生寶慶之三歲，五月十一日己未。',222,'全唐诗/poet.song.230000.json','["予生寶慶之三歲，五月十一日己未。", "五十有八甲申年，其日己未亦復然。", "天支地干標六秀，四柱得一文且壽。", "陽火在天爲太陽，陰火爲月受日光。", "將望之前四日夕，十分圓光已八七。", "常聞人生不滿百，何幸七十且八十。", "文章學問七八分，亦勝愚夫老無聞。", "古之五月而生者，後有胡廣前田文。", "予賤不敢望漢相，貧亦不能孟嘗君。", "借使時人不比數，自有詩名照千古。", "垂弧之月至于今，適逢前五仍後五。", "稚女簪榴花，小兒著艾虎。", "宿酲困不解，依舊醉起舞。", "不妨一年兩度作生朝，更造菖蒲酒，飲過閏端午。"]'),
('d98eed82-e016-4fee-b590-4b22139f3675','虛谷志歸十首  其一','方回','宋','宋诗','song-poetry','','[]','聞我解征鞍，相看喜復歎。',48,'全唐诗/poet.song.230000.json','["聞我解征鞍，相看喜復歎。", "主貧奴僕傲，兵起道途難。", "藥許求鍾乳，花先問牡丹。", "親朋聊共醉，老幼幸俱安。"]'),
('ea42a3be-898e-463a-8a15-0c3750b6c700','虛谷志歸十首  其二','方回','宋','宋诗','song-poetry','','[]','足欲周寰宇，心終喜故鄉。',48,'全唐诗/poet.song.230000.json','["足欲周寰宇，心終喜故鄉。", "溪居晨漱潔，山卧暑絺凉。", "村酒時時醉，園花日日香。", "高曾先壠在，死即葬其傍。"]'),
('aaee60f0-f785-402e-a7b2-866492ce3783','虛谷志歸十首  其三','方回','宋','宋诗','song-poetry','','[]','奔走真何謂，衰頹恐不應。',48,'全唐诗/poet.song.230000.json','["奔走真何謂，衰頹恐不應。", "灸瘢疼怕雨，渴卧夢思冰。", "端午宜觴客，生辰欲飯僧。", "乍歸兩皆省，自笑一無能。"]'),
('fbe0e270-872c-476f-9ab7-a2c967677474','虛谷志歸十首  其四','方回','宋','宋诗','song-poetry','','[]','浪走千山外，乾忙四月餘。',48,'全唐诗/poet.song.230000.json','["浪走千山外，乾忙四月餘。", "隔籬分濁蟻，共座擘枯魚。", "婢瘦慵施粉，兒頑失寄書。", "少陵亦曾爾，來往浣花居。"]'),
('bd31099f-d7d4-431d-92cb-950696c87b80','虛谷志歸十首  其五','方回','宋','宋诗','song-poetry','','[]','園林百種花，更著竹交加。',48,'全唐诗/poet.song.230000.json','["園林百種花，更著竹交加。", "徑別君臣藥，畦連子母瓜。", "老夫元是我，長息最憐他。", "擬賣嚴州宅，歸來共一家。"]'),
('95418d36-b9fd-4d4f-863a-6720d4c6426f','虛谷志歸十首  其六','方回','宋','宋诗','song-poetry','','[]','共道歸何晚，猶能喜欲狂。',48,'全唐诗/poet.song.230000.json','["共道歸何晚，猶能喜欲狂。", "幼兒初拜揖，癡女僅梳粧。", "有筆修花譜，無錢闢草堂。", "新添竹踰百，風徑細尋香。"]'),
('b97a53c6-3d68-4d4b-bf9f-4172a58bc30d','虛谷志歸十首  其七','方回','宋','宋诗','song-poetry','','[]','餽篚承先問，吟牋辱暗投。',48,'全唐诗/poet.song.230000.json','["餽篚承先問，吟牋辱暗投。", "駟車端肯顧，貳缶尚能謀。", "官妓呼難至，家姬出似羞。", "但令賓客喜，吾亦可忘憂。"]'),
('f2eb1cc5-8265-4109-a7f1-c25ef6a47220','虛谷志歸十首  其八','方回','宋','宋诗','song-poetry','','[]','一出春連夏，新詩幾首成。',48,'全唐诗/poet.song.230000.json','["一出春連夏，新詩幾首成。", "多因書土俗，稍亦記途程。", "刪削猶無暇，傳抄未可輕。", "近來多少俊，何敢與爭名。"]'),
('18d02884-19bf-44c1-b9e3-5bad479ac2b5','虛谷志歸十首  其九','方回','宋','宋诗','song-poetry','','[]','月旦須終定，陽秋豈易評。',48,'全唐诗/poet.song.230000.json','["月旦須終定，陽秋豈易評。", "麈毛空自落，牛耳可誰盟。", "好惡不相似，是非無太明。", "客來倦酬對，堅坐聽松聲。"]'),
('dbbdeb87-9daf-4939-907e-59c88af8a0ca','虛谷志歸十首  其一○','方回','宋','宋诗','song-poetry','','[]','衰晚真當戒，疏慵竟未能。',48,'全唐诗/poet.song.230000.json','["衰晚真當戒，疏慵竟未能。", "病專從酒得，謗輒爲詩興。", "每悔居城市，常思絕友朋。", "誰來敲竹戶，又見醉吟僧。"]'),
('fa37d648-39b6-4589-80f8-c97ff6cb5247','次韻志歸十首  其一','方回','宋','宋诗','song-poetry','','[]','遠望舒長嘯，幽跧發永歎。',48,'全唐诗/poet.song.230000.json','["遠望舒長嘯，幽跧發永歎。", "能詩今不少，得句古云難。", "涉世顛毛白，希賢寸腑丹。", "他鄉仍故國，何處可求安。"]'),
('d84de559-ff35-49fd-a3e1-e713ef56f178','次韻志歸十首  其二','方回','宋','宋诗','song-poetry','','[]','老不任時棟，窮猶宅士鄉。',48,'全唐诗/poet.song.230000.json','["老不任時棟，窮猶宅士鄉。", "端能甘澹泊，未覺厭荒凉。", "古井深泉冷，閒庭異草香。", "田翁來問字，略爲說偏傍。"]'),
('db383e9b-ab78-4de5-8ade-363662df3df7','次韻志歸十首  其三','方回','宋','宋诗','song-poetry','','[]','癡與狂皆有，貧兼病亦應。',48,'全唐诗/poet.song.230000.json','["癡與狂皆有，貧兼病亦應。", "屢嘗三斗醋，不夢一條冰。", "買藥憑船賈，分茶謝冢僧。", "短衣射猛虎，老矣竟無能。"]'),
('ec32ce67-b149-4378-bf75-ca2181899645','次韻志歸十首  其四','方回','宋','宋诗','song-poetry','','[]','還家五月初，倏忽又旬餘。',48,'全唐诗/poet.song.230000.json','["還家五月初，倏忽又旬餘。", "凉劑醫羸馬，塵編磔蠹魚。", "小遲延客飲，作急報兒書。", "歙睦頻來往，何時永定居。"]'),
('8eccb55e-0561-4091-8b68-76f74e230b19','次韻志歸十首  其五','方回','宋','宋诗','song-poetry','','[]','添竹復添花，清陰一倍加。',48,'全唐诗/poet.song.230000.json','["添竹復添花，清陰一倍加。", "病身思灼艾，暑節近浮瓜。", "晚景今如許，初心豈有他。", "甘貧仍守拙，肯羨五侯家。"]'),
('a16e7da2-f07c-4164-a92e-d32715303779','次韻志歸十首  其六','方回','宋','宋诗','song-poetry','','[]','解語鶑能巧，交飛蝶許狂。',48,'全唐诗/poet.song.230000.json','["解語鶑能巧，交飛蝶許狂。", "苔紋深碧毯，榴靨競紅粧。", "粗已成幽圃，猶當築小堂。", "未妨無暑藥，熟水紫蘇香。"]'),
('ec1a3f39-0851-4f6d-a190-683e3c92483e','次韻志歸十首  其七','方回','宋','宋诗','song-poetry','','[]','楸局堪誰對，銅壺擬共投。',48,'全唐诗/poet.song.230000.json','["楸局堪誰對，銅壺擬共投。", "高軒能坐致，濁酒豈難謀。", "林鳥供歌吹，園蔬當饌羞。", "謂無憂不可，聊以此消憂。"]'),
('693c73b8-9aba-48a7-acae-a13f5ab767ae','次韻志歸十首  其八','方回','宋','宋诗','song-poetry','','[]','譙國資深入，彭門納晚成。',48,'全唐诗/poet.song.230000.json','["譙國資深入，彭門納晚成。", "至今爲癖習，自幼有常程。", "朽老寧孤瘦，飛揚勿剽輕。", "懸知千載士，肯競一時名。"]'),
('05b5048a-f918-4077-a4be-1a7ffcf002da','次韻志歸十首  其九','方回','宋','宋诗','song-poetry','','[]','書盍多多讀，詩須細細評。',48,'全唐诗/poet.song.230000.json','["書盍多多讀，詩須細細評。", "後生才染指，半道遽寒盟。", "直取珊瑚出，寧爭熠燿明。", "伯牙弦已絕，舉世喜箏聲。"]'),
('5f5c908b-8922-4745-9a9e-5bb3f6c6c7dd','次韻志歸十首  其一○','方回','宋','宋诗','song-poetry','','[]','近城一耕叟，僅有使牛能。',48,'全唐诗/poet.song.230000.json','["近城一耕叟，僅有使牛能。", "人似愚偏壽，家由儉故興。", "不知求仕宦，未省結交朋。", "笑我儒冠誤，今如退院僧。"]'),
('c0c9c3ea-dc71-4afc-a68a-a8b7701a8048','次韻謝俞山長見贈','方回','宋','宋诗','song-poetry','','[]','年衰才盡懶揮毫，定有移文責魯臯。',64,'全唐诗/poet.song.230000.json','["年衰才盡懶揮毫，定有移文責魯臯。", "學到紫陽今欲絕，詩如清老子能高。", "棲遲矮屋官猶冷，傲睨芳樽氣自豪。", "試遣俚音辱聰聽，未應堪比鬰輪袍。"]'),
('bb1df4bf-8093-4520-a217-86cc91d38a5f','賀陳正之得男','方回','宋','宋诗','song-poetry','','[]','初喜明珠入掌中，良由善念與天通。',64,'全唐诗/poet.song.230000.json','["初喜明珠入掌中，良由善念與天通。", "吉祥預報長庚夢，福德應臨長子宮。", "急寫賀書端不錯，濫叨佳集顧何功。", "此詩特爲高門慶，大似麟經記魯同。"]'),
('961b50cc-f026-4aaf-a01d-67e602908132','復如嚴陵就省先墓','方回','宋','宋诗','song-poetry','','[]','暮景能幾何，行役復行役。',264,'全唐诗/poet.song.230000.json','["暮景能幾何，行役復行役。", "薄命不由人，豈不願休息。", "江鄂訪知舊，不遇悔浪出。", "子舍寓嚴瀨，逋負日夜迫。", "老夫匪親往，未易紓此急。", "買舟更東下，貲糧費捃拾。", "是時梅雨已，巨浪百谷集。", "深江水氣凉，古岸樹陰密。", "壯觀足忘憂，飛泉落奇石。", "晚拜先子墓，舊廬化榛礫。", "惡鄰肆焚燎，用意甚寇賊。", "大木幸俱全，不至損塋域。", "其人偶遇赦，罰不毫毛一。", "予亦持恕心，詎敢太刻覈。", "村民陸續至，樵茗弛擔笠。", "杯酒先癃耄，幼稚與果核。", "一僧獨霑醉，座間具紙筆。", "索詩苦不已，佳句豈易得。", "松風雜灘聲，睡醒殘月白。", "明發鼓征棹，矯首望青壁。", "山川信佳哉，紆餘繞崷崒。", "何當即歸來，於此築書室。"]'),
('28789b02-9559-4c57-8577-07b94a7bcfdb','出歙港入睦界','方回','宋','宋诗','song-poetry','','[]','嵐氣濕征衣，千灘落翠微。',48,'全唐诗/poet.song.230000.json','["嵐氣濕征衣，千灘落翠微。", "懸崖樵屋小，破廟祭人稀。", "岸犬看船立，溪禽貼水飛。", "鄉心與客思，向晚重依依。"]'),
('8d5b85fb-4689-4cd8-95cf-d88bb932a624','舟中觀馬目烏龍山','方回','宋','宋诗','song-poetry','','[]','一從爲郡後，來往十年間。',48,'全唐诗/poet.song.230000.json','["一從爲郡後，來往十年間。", "自笑成何事，猶容看此山。", "舊人多粗給，老子願常閒。", "今晚歸書屋，溪僧定叩關。"]'),
('c7f659b4-b9b6-48ff-a55f-8051945191e2','將至嚴陵','方回','宋','宋诗','song-poetry','','[]','汀洲渺渺長，野牧縱牛羊。',48,'全唐诗/poet.song.230000.json','["汀洲渺渺長，野牧縱牛羊。", "島寺林間塔，溪船郭外檣。", "得詩真是畫，聞酒忽能香。", "新屋誰家者，高樓四面凉。"]'),
('b6db758a-0d5d-4030-8d3c-990ba5bafc54','送趙仁則官滿西歸三首  其一','方回','宋','宋诗','song-poetry','','[]','稼軒賢帥有甥氏，梅野倫魁之里人。',64,'全唐诗/poet.song.230000.json','["稼軒賢帥有甥氏，梅野倫魁之里人。", "春水江湖寬度量，秋天霜月瘦精神。", "三年郡政彌縫密，四海詩朋燕笑頻。", "題浣花牋當折柳，預愁船鼓轉東津。"]'),
('2bb1fa08-bf4e-46b7-b839-fe3bf7822acd','送趙仁則官滿西歸三首  其二','方回','宋','宋诗','song-poetry','','[]','妙年意氣日方中，致有前賢長者風。',64,'全唐诗/poet.song.230000.json','["妙年意氣日方中，致有前賢長者風。", "言未始輕常簡潔，飲雖甚醉愈溫恭。", "此邦小屈爲通守，吾老相逢已禿翁。", "自笑全家歸未得，悵然寥廓羨冥鴻。"]'),
('07e73a14-2bf1-4fff-a943-3e174b994cac','送趙仁則官滿西歸三首  其三','方回','宋','宋诗','song-poetry','','[]','宇宙今年氣數新，不愁無地著閒身。',64,'全唐诗/poet.song.230000.json','["宇宙今年氣數新，不愁無地著閒身。", "西成稼穡占魚夢，南紀干戈息馬塵。", "隨分田園勝仕宦，及時兒女了婚姻。", "細思便合從君去，龍虎山中作道人。"]'),
('cbbcf146-5ec2-44cb-b0b1-88de64ed77b3','移具飲賓暘宅次韻二首  其一','方回','宋','宋诗','song-poetry','','[]','垂門老柳繫青驄，夢裏先曾訪此翁。',64,'全唐诗/poet.song.230000.json','["垂門老柳繫青驄，夢裏先曾訪此翁。", "謝朓遠窗分絕景，郝隆幽腹對晴空。", "偕來衆客無官位，拱立諸郎有父風。", "我寓秀山十年矣，草堂始得一樽同。"]'),
('8e5798d8-d60a-4702-81fd-e502d4767168','移具飲賓暘宅次韻二首  其二','方回','宋','宋诗','song-poetry','','[]','六橋花絮驟嘶驄，豈料如今兩鬢翁。',64,'全唐诗/poet.song.230000.json','["六橋花絮驟嘶驄，豈料如今兩鬢翁。", "痛飲竹林真得計，望塵金谷總成空。", "吾廬寂靜專雲岫，公屋寬凉傲暑風。", "東下西還俱未定，不妨時許笑言同。"]'),
('be815d13-0208-4637-9255-686359acc627','次韻謝夏自然見寄四首  其一','方回','宋','宋诗','song-poetry','','[]','與子俱逢掖，寒瓢共碧流。',48,'全唐诗/poet.song.230000.json','["與子俱逢掖，寒瓢共碧流。", "歙今全似魯，睦亦盛於鄒。", "竹屋南溪外，風帆古渡頭。", "相尋欠相遇，遄復墮音郵。"]'),
('c9ba39b7-da65-4c7c-b42b-2acb695f2adc','次韻謝夏自然見寄四首  其二','方回','宋','宋诗','song-poetry','','[]','門人浮小艇，不比舊專城。',48,'全唐诗/poet.song.230000.json','["門人浮小艇，不比舊專城。", "自愧頻來往，何煩數送迎。", "病身緣畏飲，去路似貪程。", "別後君詩進，他時定有名。"]'),
('8974d557-0421-4571-994a-0343110703ab','次韻謝夏自然見寄四首  其三','方回','宋','宋诗','song-poetry','','[]','通經聞大道，餘事始爲詩。',48,'全唐诗/poet.song.230000.json','["通經聞大道，餘事始爲詩。", "初或無人識，終須有己知。", "真能深造否，孰謂晚成遲。", "小袖朱弦手，何憂乏子期。"]'),
('f86eed86-92d4-4d01-8b4b-eecda180c9eb','次韻謝夏自然見寄四首  其四','方回','宋','宋诗','song-poetry','','[]','士氣兼文脈，湮微復幾年。',48,'全唐诗/poet.song.230000.json','["士氣兼文脈，湮微復幾年。", "淺膚專徇俗，高亢類談禪。", "春動霆聲起，雲開月體全。", "古人方冊在，達者以心傳。"]'),
('cd97a37a-017c-4b72-aaee-599ae62931b3','次韻謝魏公輔二首  其一','方回','宋','宋诗','song-poetry','','[]','之子如天馬，終歸十二閑。',48,'全唐诗/poet.song.230000.json','["之子如天馬，終歸十二閑。", "相期作名士，不厭坐窮山。", "師席摳趨際，親庭定省間。", "鶴仙門戶冷，今喜一珠還。"]'),
('a23ca17a-98e7-4519-ab83-96281673a8cf','次韻謝魏公輔二首  其二','方回','宋','宋诗','song-poetry','','[]','男兒初嗜學，如日曉行天。',48,'全唐诗/poet.song.230000.json','["男兒初嗜學，如日曉行天。", "意氣無餘子，詩書有夙緣。", "果能知此道，深欲候吾船。", "夢寐心常在，孤燈可不傳。"]'),
('7a928b97-0956-4354-b8dc-8905f66e4c8b','登秀山至半而還有懷賓暘','方回','宋','宋诗','song-poetry','','[]','擁書終日汗如漿，試上崔嵬覓晚凉。',64,'全唐诗/poet.song.230000.json','["擁書終日汗如漿，試上崔嵬覓晚凉。", "忽喜孤煙支拄杖，偶逢平石寘繩床。", "十年世事頭鬚白，六月江城草樹蒼。", "莫盡山顛且山半，待携詩友共清觴。"]'),
('a6545e8f-c4ab-490b-8961-1e8c2f53708e','賓暘來飲秀山予醉小跌次韻爲吳體','方回','宋','宋诗','song-poetry','','[]','無冰爲水柘爲漿，深入醉鄉心自凉。',64,'全唐诗/poet.song.230000.json','["無冰爲水柘爲漿，深入醉鄉心自凉。", "微官誤身魚中餌，俗士縛禮龜搘床。", "未妨賣書笑杜甫，寧能食乳羨張蒼。", "顛崖仆樹幸無損，當復與君浮萬觴。"]'),
('1253d126-8eeb-4c0d-8d20-8647ac5898c3','次韻謝董君讀予詩稿  其一','方回','宋','宋诗','song-poetry','','[]','少年客洛走緇塵，自倚詩才敵萬人。',64,'全唐诗/poet.song.230000.json','["少年客洛走緇塵，自倚詩才敵萬人。", "嶽聳河奔爭氣勢，霜嚴月朗借精神。", "鏡中顔狀驚非昔，筆底工夫苦不新。", "辜負桐江好山水，花開葉落十秋春。"]'),
('b82e0387-5f19-4732-8f47-b93650ec7237','次韻謝董君讀予詩稿  其二','方回','宋','宋诗','song-poetry','','[]','宇宙茫茫戰馬塵，中原文獻不無人。',64,'全唐诗/poet.song.230000.json','["宇宙茫茫戰馬塵，中原文獻不無人。", "詩裁綵筆天公妬，書擁青燈夜氣神。", "簁雨簸風六月冷，磔雲裂霧千峰新。", "何當君病早勿藥，共倒松陰百甕春。"]'),
('40919d82-8eb8-4ee6-a096-fe7f3cb98ab3','夏夜聞雨','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','可以逃袢暑，征徒盍少休。',48,'全唐诗/poet.song.230000.json','["可以逃袢暑，征徒盍少休。", "病多全爲老，醉極暫無愁。", "雨氣昏燈夜，蛬聲古屋秋。", "錢塘湖上路，到日與誰遊。"]'),
('a1988a7f-38db-4942-a134-d15499e21b8a','讀書遇難字','方回','宋','宋诗','song-poetry','','[]','癡癖好冥搜，忘憂亦解愁。',48,'全唐诗/poet.song.230000.json','["癡癖好冥搜，忘憂亦解愁。", "劃逢難字窘，遍取韻書求。", "忠恕聞何博，昌朝辨亦優。", "孚尹能進業，燠休勿包羞。"]'),
('50420d9a-b90a-47d2-a11f-380874309374','雨凉曉思','方回','宋','宋诗','song-poetry','','[]','一榻凉如水，空山夜雨聲。',48,'全唐诗/poet.song.230000.json','["一榻凉如水，空山夜雨聲。", "病身筋骨在，往事夢魂驚。", "老壽知何益，憂危半此生。", "吾窮終不怨，稍已竊詩名。"]'),
('e699948c-9890-4c2e-bd47-3f3749b43550','立秋久無詩','方回','宋','宋诗','song-poetry','','[]','三伏厭厭病欲萎，可能秋後尚無詩。',64,'全唐诗/poet.song.230000.json','["三伏厭厭病欲萎，可能秋後尚無詩。", "連宵急雨凉如洗，貪寐衰翁醉不知。", "藥餌誰精寸關尺，文章空說斗牛箕。", "西齋池上堪逃暑，木落吾將信所之。"]'),
('a0e7f147-8f6f-43c1-aecd-58f518c855de','典秀山宅半','方回','宋','宋诗','song-poetry','','[]','半宅分僚友，門開別向西。',48,'全唐诗/poet.song.230000.json','["半宅分僚友，門開別向西。", "送書人未識，歸舍犬猶疑。", "老喜吟窩窄，廉從典價低。", "餘山兼剩沼，亦足杖吾藜。"]'),
('c6d007a3-8cd9-4ab6-a2e5-f95ffd2816e8','再賦典半宅','方回','宋','宋诗','song-poetry','','[]','屋以多爲貴，思之亦太愚。',48,'全唐诗/poet.song.230000.json','["屋以多爲貴，思之亦太愚。", "燈膏徒重費，庖膳卒難呼。", "榻外知何用，杯中不可無。", "質錢分客住，得醉且頻沽。"]'),
('4a415cfa-2610-4165-b5ea-965980bb4100','七月三日朱用和羅弘道同訪南山無竭師','方回','宋','宋诗','song-poetry','','[]','振騎出喧闠，榜舟浮廣川。',288,'全唐诗/poet.song.230000.json','["振騎出喧闠，榜舟浮廣川。", "冠蓋二三子，謂我揚先鞭。", "翳翳杉漆塢，膴膴禾黍田。", "籬闖擁稚髻，擔觀駢旅肩。", "是日告秋朔，暑絺稍輕便。", "矚遠喜野曠，討幽忘道綿。", "維南孤崒嵂，中有西方仙。", "鐵幹萬樹古，金界千柱堅。", "濕蘚滑側磴，密荔凉深泉。", "道人瘦如臘，不見今三年。", "翠琰壁奇刻，丹塗架穹椽。", "脩竹洗人心，焉知紅塵天。", "謔劇酒若失，機捷詩易圓。", "致爽瀟灑閣，俯視烏龍顛。", "過帆倏滅沒，聚市常熬煎。", "臨軒十八公，老壽藤蘿纏。", "與語若未對，風至忽粲然。", "斗牛之所蒞，吳越封疆連。", "自泰伯勾踐，以至衣錦錢。", "成敗亦屢矣，變化若浮煙。", "嗟哉聲利徒，羣蟻爭微羶。", "吾儕方寸中，皎月澄寒淵。", "少迷逐衆嗜，晚悟羞前愆。", "會當擺俗鞅，來此禪窗眠。"]'),
('a45e4149-4e45-4730-9297-26e9cbb4f4c7','朱用和用予南山舊韻次韻謝併呈羅弘道','方回','宋','宋诗','song-poetry','','[]','妙論劇談逢大敵，深林蔭樾尾清遊。',64,'全唐诗/poet.song.230000.json','["妙論劇談逢大敵，深林蔭樾尾清遊。", "柳州先記知非偶，陸相荒莊愧不秋。", "似舅遠尋昆弟好，老生猥與介賓謀。", "凄其廿載龍門夢，墊角曾登李尹舟。"]'),
('0b54e40a-de16-48e8-9df9-0c3a2c4286a8','送羅架閣弘道','方回','宋','宋诗','song-poetry','','[]','六籍討雅奧，百家窮怪奇。',288,'全唐诗/poet.song.230000.json','["六籍討雅奧，百家窮怪奇。", "江沱馬塵合，毛釐無所施。", "不自我後先，逢此澤火時。", "固已殛來惡，尚乃存微箕。", "黼哻裸于京，越吟亦凄其。", "冠冕垂纓紞，履屨飾純綦。", "褒博士服制，揖讓公食儀。", "前輩略已盡，後進漸不知。", "老夫愧每生，骨立雙鬢絲。", "十年日夜醉，萬里南北馳。", "休官此山中，可與語者誰。", "堂堂朱荆州，遺恨浮鴟夷。", "有甥何其賢，酷似劉牢之。", "貞元舊朝士，顧肯文學爲。", "出蜀賦八陣，遊吳歌五噫。", "酹月客星閣，吟風桐川湄。", "湖海有此士，始見詩人詩。", "惜往節誼鮮，嘆今文獻衰。", "論議吐一二，已覺餘子卑。", "宇宙不一姓，牛山空漣洏。", "後周庾子山，北齊顔之推。", "斯文天未泯，終古清名垂。", "年可里社老，行足鄉黨師。", "書癡俗所哂，各且教其兒。"]'),
('610bf183-47e9-4579-a7da-d6e2b4674df8','送周府尹三首  其一','方回','宋','宋诗','song-poetry','','[]','瀟灑名州吏事門，公餘應已盡躋攀。',64,'全唐诗/poet.song.230000.json','["瀟灑名州吏事門，公餘應已盡躋攀。", "鍾魚寺寺藏深樹，樓閣家家見好山。", "幾許煙雲藜杖外，無邊風月錦囊間。", "俸錢節縮餘多少，只買奇書數種還。"]'),
('f008cebc-f5b7-4b5d-a234-4541db24d6a6','送周府尹三首  其二','方回','宋','宋诗','song-poetry','','[]','樂土豐年舊觀還，使君心事最相關。',64,'全唐诗/poet.song.230000.json','["樂土豐年舊觀還，使君心事最相關。", "祇因標致清於水，便有聲名重若山。", "一室爐香書史畔，萬家杯酒管弦間。", "漢庭選表虛公府，白玉鳴珂未許攀。"]'),
('c4a24644-1789-40a2-bad7-06a46d113463','送周府尹三首  其三','方回','宋','宋诗','song-poetry','','[]','詩家周賀與方干，三載同吟七里灘。',64,'全唐诗/poet.song.230000.json','["詩家周賀與方干，三載同吟七里灘。", "晚節我惟甘豹隠，妙年公合快鵬摶。", "昔叨舊尹迎新尹，今愧前官送後官。", "朔野炎陬天地闊，寄書會面兩應難。"]'),
('09263fde-5a0a-4fc3-b976-38e34302fbc9','西齋秋日雜書五首  其一','方回','宋','宋诗','song-poetry','','[]','居城近城門，前市後山郊。',60,'全唐诗/poet.song.230000.json','["居城近城門，前市後山郊。", "質明沸柩鼓，徹夜喧僧鐃。", "暑病人死多，當此秋夏交。", "鹽米鬨賈販，杖絰酸哀號。", "倏忽異存歿，所爭常毫毛。"]'),
('8595bb93-f877-4530-84a7-312d8d5180e1','西齋秋日雜書五首  其二','方回','宋','宋诗','song-poetry','','[]','高樹夕影疏，老荷秋氣馥。',60,'全唐诗/poet.song.230000.json','["高樹夕影疏，老荷秋氣馥。", "雨餘絢斜照，寓此池上目。", "鳴蟬一何厲，坐嘆白日速。", "東家失其兒，忽駭鄰婦哭。", "歸兮空山中，幽嘯抱吾獨。"]'),
('0f990f47-8357-4d22-acac-419c47da0b62','西齋秋日雜書五首  其三','方回','宋','宋诗','song-poetry','','[]','閑閑閉園門，默默坐書室。',60,'全唐诗/poet.song.230000.json','["閑閑閉園門，默默坐書室。", "幽幽絕來人，寂寂度長日。", "苦桃何纍纍，秋顆壓枝密。", "桃苦不可食，熟爛未忍摘。", "時聞落地聲，詩思若有得。"]'),
('8f329a00-8be7-4b03-ae5a-c1e19fdae25d','西齋秋日雜書五首  其四','方回','宋','宋诗','song-poetry','','[]','百間以買屋，萬卷以買書。',60,'全唐诗/poet.song.230000.json','["百間以買屋，萬卷以買書。", "書多讀不既，屋寬住有餘。", "彼索子錢者，日夜號庭除。", "勇銳割此物，煎迫姑少紓。", "老勿費眼力，村墟亦可居。"]'),
('34926fd3-7cfe-49fb-8b0e-2d44938ab9bc','西齋秋日雜書五首  其五','方回','宋','宋诗','song-poetry','','[]','對奕不如觀，觀不如聽聲。',60,'全唐诗/poet.song.230000.json','["對奕不如觀，觀不如聽聲。", "獨坐無來客，小軒秋雨晴。", "思之有百憂，不思了無情。", "萬有皆外物，世重我所輕。", "默數前死者，愧茲今獨生。"]'),
('917c6f21-c4db-4966-8282-3d083e08ac53','存心具飲','方回','宋','宋诗','song-poetry','','[]','朝雨復暮雨，暑氣日已微。',144,'全唐诗/poet.song.230000.json','["朝雨復暮雨，暑氣日已微。", "凉軒水□爽，幽坐延秋暉。", "孤抱無一愜，前事有百非。", "可讀書本少，能言士尤稀。", "積倦蠹帙翻，久輟犀柄揮。", "吾兒忽具飲，山茹薑葖肥。", "青甆古茗器，十觴聯若飛。", "此生老且死，所幸歲不饑。", "似聞吳中潦，米價良足唏。", "東遊豈不快，何如且言歸。", "一醉未易得，家貧今典衣。", "典衣亦常事，冥心甘息機。"]'),
('d636a810-166f-48c6-b035-368d859751de','釋臨邛記方物戲作','方回','宋','宋诗','song-poetry','','[]','昔人註爾雅，大儒以爲誚。',288,'全唐诗/poet.song.230000.json','["昔人註爾雅，大儒以爲誚。", "學詩貴多識，聖言厥有詔。", "下博梯上約，後進曷克劭。", "矧於點𪑮間，懵弗省體要。", "俗喙僅能□，古吭略未剽。", "四聲故㩈拘，六書本幻妙。", "嘑姓駭厙暨，辯義謔篤笑。", "往訛足可戒，夙是政宜肖。", "郊霓縱劣約，窗岫寧蹈眺。", "鯫也缺茲析，寸抱踏𧇠𠿕。", "探架獲塵帙，偶幸脫斯燎。", "壁蟫蝕心胸，不受俞扁療。", "糲食忘調饑，微膏戀殘照。", "幽暗發蒙篰，乖剌合券約。", "稍免杕杜辱，敢倚陬隅俏。", "虛空了無味，强作吳牯噍。", "稅駕如還鄉，舍爵欲告廟。", "一方筆千名，擬謨貯深嶠。", "桑榆老禿翁，廊肆付周召。", "詎思玉豉餌，豈羨金鹽釂。", "庶異速朽子，霜原委荒燒。", "眼前黄口兒，曲踴詫壯少。", "但喜觥醽醁，靡肯囊熠燿。", "吾衰□□苦，汝健騁輕趬。"]'),
('39fc84a3-3c99-4d23-b69f-0bf8212728a9','池亭秋思','方回','宋','宋诗','song-poetry','','[]','憶昨困炎蒸，衣單猶欲臝。',252,'全唐诗/poet.song.230000.json','["憶昨困炎蒸，衣單猶欲臝。", "秋氣□□凉，飲可讀亦可。", "稍久罄瓶罌，猝難致肴果。", "亦欲理蠹卷，未易啟澀鎖。", "剛腸惡充飫，病骨嗜慵惰。", "饑渴已兩忘，豈較立與坐。", "前除水滿池，有亭窄如舸。", "頹然一釣翁，照影媿巾裹。", "魚負密萍行，蛙升側荷墮。", "蛬蚻韻凄鏘，螽蜢跳細瑣。", "函靈各肖形，品物一何夥。", "氣動不自由，孰非大專播。", "沮洳伏汙濕，糞壤孕么麽。", "詔以南面王，豈復知忖揣。", "私獨念橫目，識性異螟蠃。", "何謂等逍遥，弗更諏坎軻。", "市斛𨺗翔踴，旅郵欠貼妥。", "門楗敬逋籬，岸閣子美柂。", "鈞天奏萬舞，遑恤下民癉。", "排閶宜一叩，有客答曰叵。", "腐儒叢百憂，曷不自憂我。"]'),
('cba9e158-598b-4117-a26c-c3527e81d690','次韻寄題堪上人雲外軒','方回','宋','宋诗','song-poetry','','[]','萬重雲外一蘧廬，想見降龍長者居。',64,'全唐诗/poet.song.230000.json','["萬重雲外一蘧廬，想見降龍長者居。", "溪上過橋誰覓路，峰頭飛錫已凌虛。", "漢臺列像焉知許，陶岫吟歸孰起予。", "儻憩夜爐煨芋處，可能更讀鄴侯書。"]'),
('df3c9d45-ac87-451a-92c1-efc3a0fa2586','冰崖楊明府德藻携紅酒殽果來飲歸舟獨坐熊皮索筆作字且出示篋中書爲賦吳體','方回','宋','宋诗','song-poetry','','[]','有美一人升秋堂，木犀花中清言香。',64,'全唐诗/poet.song.230000.json','["有美一人升秋堂，木犀花中清言香。", "熊皮端坐雪衣潔，兔穎疾揮葱指長。", "琥珀味濃酒溢□，□□價重書盈箱。", "炰羔剪韭兒輩問，此豈拜石米元章。"]'),
('d31e7cef-f2ff-4ca3-a9b0-d515f684c143','三日□陪楊明府飲次前韻','方回','宋','宋诗','song-poetry','','[]','閴其禪老居西堂，豈有門人拈瓣香。',64,'全唐诗/poet.song.230000.json','["閴其禪老居西堂，豈有門人拈瓣香。", "葛巾漉酒笑元亮，石室紬書輸子長。", "勿嫌臨邛家四壁，猶堪樊川月一箱。", "寄書麒麟閣上客，我自蓑衣君金章。"]'),
('48e796a5-120f-4d8a-bd48-049aa321b7b8','八月二十日曉起','方回','宋','宋诗','song-poetry','','[]','夜闌不能寐，雞鳴垂欲三。',216,'全唐诗/poet.song.230000.json','["夜闌不能寐，雞鳴垂欲三。", "起步秋月影，寒髪何毿毿。", "斗柄落山北，參旗掛庭南。", "三五忽四五，蛙蚓衆喙緘。", "獨有絡緯聲，催織何喃喃。", "祿仕心已息，愧未任桑蠶。", "昨暮缺薪米，質以衾及縑。", "七年爲此郡，忍人所難堪。", "焉知窘至此，不給石與甔。", "獨坐老樹下，暗撚霜鬚髯。", "牆外行人動，喪事簫鼓酣。", "生之必有死，如歲代凉炎。", "但頗訝薄俗，不復甄廉貪。", "鄙誚采芝餒，歆羨膾肝饞。", "想見攫奪子，櫪馬已就銜。", "豈識有幽人，茹苦如飴甘。", "念雖乏智計，識度終不凡。", "兒女亦可割，深山建茅庵。"]'),
('1588ad37-6b33-4e46-b07f-49e3e4eed76c','是日天明復書','方回','宋','宋诗','song-poetry','','[]','一夕不飲酒，至曉不能眠。',168,'全唐诗/poet.song.230000.json','["一夕不飲酒，至曉不能眠。", "無瘡體自癢，若有蟲嚙然。", "黠鼠肆侮慢，鳴鬬窺餘饘。", "書燈稍已暗，一螢窗隙穿。", "我興視星斗，行行空庭間。", "□樹寂無風，斜月□缺環。", "寓此百餘日，寒迫暑已還。", "門有索逋客，無日不煩□。", "□是窮骨健，兼亦苦節堅。", "比所讀何書，高堂十七篇。", "最□□服傳，纂抄續殘編。", "此物付兒子，將來汝謹旃。", "儻我壽七十，不過十二年。", "人豈有不死，但有傳不傳。"]'),
('7ed9cb55-c76b-480e-8ef6-9acf4a3ffcb6','示長兒存心','方回','宋','宋诗','song-poetry','','[]','我家歙山下，不滿五頃田。',288,'全唐诗/poet.song.230000.json','["我家歙山下，不滿五頃田。", "捐棄已過半，豈不爲子錢。", "兵甲跨江海，喧豗踰十年。", "零落殆萬卷，荒凉餘數椽。", "借使盡售之，事亦關諸天。", "平生鄙貨殖，黄金散如烟。", "孰知兩鬢雪，枯腸幾不饘。", "無憂恐難老，故遣百慮煎。", "樂者未必壽，死返在我先。", "屬有客語我，法當營塚阡。", "兒曹勿過計，葬穴自有緣。", "隻雞可以祭，故絮亦足纏。", "但戒傚俚俗，佛事徒喧闐。", "文公有家禮，夙已書諸篇。", "父貧至累子，能不心惻然。", "揣量內無愧，視世差獨賢。", "囊中了無物，積稿詩三千。", "詎敢望放翁，至有萬首傳。", "嚴陵所寓屋，稍已割東偏。", "鄰翁覓菜地，更當乞西壖。", "今我欲裹糧，一汎濤江船。", "永謝麟閣夢，寧垂黿鼎涎。", "故人儻相濟，匪伊歸棹旋。", "紫陽政自佳，携汝追羣仙。"]'),
('51191657-a206-4c65-a93a-4c6addf27d7c','秀亭秋懷十五首  其一','方回','宋','宋诗','song-poetry','','[]','高臺何巍巍，遠眄千里道。',84,'全唐诗/poet.song.230000.json','["高臺何巍巍，遠眄千里道。", "長夏絕游朋，荒徑豐茂草。", "菑翳一以剪，秋意豁幽抱。", "能賦昔爲誰，今死骨已槁。", "魂兮果何之，言語空媚好。", "我欲有所酌，適值樽中燥。", "焉得瓢天漿，伊人共傾倒。"]'),
('4c541e08-f47f-461c-a15e-400816484204','秀亭秋懷十五首  其二','方回','宋','宋诗','song-poetry','','[]','癡癡誰氏子，晝夜安以偷。',84,'全唐诗/poet.song.230000.json','["癡癡誰氏子，晝夜安以偷。", "其人一何樂，惟我攢百憂。", "憂者謂速朽，頑骨病復瘳。", "樂當必老壽，顧已歸山丘。", "饑生支牀龜，飽死豺虎儔。", "天道匪易測，人事諒難籌。", "生死吾不知，及辰爲茲遊。"]'),
('bf8759da-cc41-4995-8d98-91167950f0a4','秀亭秋懷十五首  其三','方回','宋','宋诗','song-poetry','','[]','天欲興蒼姬，一家三聖人。',84,'全唐诗/poet.song.230000.json','["天欲興蒼姬，一家三聖人。", "扶持用禮樂，行葦於焉臻。", "有國八百年，終亦化爲秦。", "末俗誇神仙，吐故以納新。", "彭門訖有塚，瀛洲浩無津。", "羽衣還緱山，舉家不得親。", "君幸有美酒，何不頻沾唇。"]'),
('3a7b400b-fd18-4921-8f58-95ecfab590a4','秀亭秋懷十五首  其四','方回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','秋風西北來，一夕幾萬里。',84,'全唐诗/poet.song.230000.json','["秋風西北來，一夕幾萬里。", "湛湛長江楓，落葉逝流水。", "自非貞勁草，顔色槁欲死。", "時當蟄蛟龍，么麽況螻蟻。", "塞墐非不可，旨蓄焉所恃。", "空褚乏裳衣，敝絮誰與理。", "陽春何日還，悲哉遠遊子。"]'),
('1c154488-8068-4be0-a20e-931bbafdb441','秀亭秋懷十五首  其五','方回','宋','宋诗','song-poetry','','[]','一室局戶牖，古籍勤討刪。',84,'全唐诗/poet.song.230000.json','["一室局戶牖，古籍勤討刪。", "鬰鬰忽不樂，扶杖登東山。", "莽蒼何所極，秋色天地間。", "我欲出塵世，黄鶴無由攀。", "憂端從空來，嵂矹未易宣。", "意闊步武窄，四顧盡險艱。", "不如復我所，陶此靈府閑。"]'),
('d56d4a37-2a5f-4916-8090-ec9aa15b6469','秀亭秋懷十五首  其六','方回','宋','宋诗','song-poetry','','[]','宣父老于行，苦辛定六藝。',84,'全唐诗/poet.song.230000.json','["宣父老于行，苦辛定六藝。", "至今峨冕旒，萬國奉蒸祭。", "當時困在陳，粒粟不能致。", "宰割諸侯王，重瞳氣蓋世。", "燒紀不啻虱，烹周僅若彘。", "焉知千金首，乃爲馬童利。", "此口酒可澆，是事可以置。"]'),
('901e8fa8-85a9-47f5-ac02-38e585c506dd','秀亭秋懷十五首  其七','方回','宋','宋诗','song-poetry','','[]','一針落大海，萬古無還期。',84,'全唐诗/poet.song.230000.json','["一針落大海，萬古無還期。", "纖纖刺繡女，斷腸終爾思。", "物重干將去，心願精衛爲。", "鄰嫗適有此，殷勤來獻之。", "銛鋒貫綵縷，縫紉實所宜。", "匪妾舊時物，愴然雙淚垂。", "如何大丈夫，忘恩忽如遺。"]'),
('2d5ab3c2-6726-46d7-a1c3-41be49fd8dec','秀亭秋懷十五首  其八','方回','宋','宋诗','song-poetry','','[]','積悶何可遣，高峰上雲端。',84,'全唐诗/poet.song.230000.json','["積悶何可遣，高峰上雲端。", "水南彼何所，縹渺浮孤烟。", "鬰塞樹木古，深幽窗戶妍。", "一楫往從之，豈無凌波船。", "絕景未易寫，良朋求亦難。", "獨往或興盡，空叩林下關。", "不若遥相望，聊寄吾意焉。"]'),
('4b291981-ce7c-4268-9240-a23ac207d36a','秀亭秋懷十五首  其九','方回','宋','宋诗','song-poetry','','[]','登高見佳句，意會無非詩。',84,'全唐诗/poet.song.230000.json','["登高見佳句，意會無非詩。", "顧視不即收，頃刻已失之。", "老樹踞崖石，腹空猶有皮。", "顧此有何好，愛玩頻嗟咨。", "侍者一童子，髧如枯髪垂。", "從我僅一飽，萬事無所知。", "豈不亦怪我，徘徊將奚爲。"]'),
('f103349d-cff6-4668-a5af-b26f6d769e00','秀亭秋懷十五首  其一○','方回','宋','宋诗','song-poetry','','[]','樂莫樂登高，亦復悲莫悲。',84,'全唐诗/poet.song.230000.json','["樂莫樂登高，亦復悲莫悲。", "樂兮携佳人，樽酒相追隨。", "慘慘古戍暮，煙寒秋角吹。", "悲從此中起，孤遊偶臻茲。", "城南百尺樓，前是未有之。", "城外兩三塚，新葬復是誰。", "往者已足鑒，百世懸可知。"]'),
('cedee375-06de-4d7c-ab8f-0519fbd80c24','秀亭秋懷十五首  其一一','方回','宋','宋诗','song-poetry','','[]','家富敵萬乘，吾嘗見其人。',84,'全唐诗/poet.song.230000.json','["家富敵萬乘，吾嘗見其人。", "生死握國柄，不復如人臣。", "自謂磐石安，掃滅隨埃塵。", "豈不恃狙詐，政用禍爾身。", "爾身一腐鼠，原野何足陳。", "歌姬事別主，畫堂生荆榛。", "我嘆匪爲此，遺禍殃齊民。"]'),
('1f70b4d9-eefc-4f15-93df-cea524549594','秀亭秋懷十五首  其一二','方回','宋','宋诗','song-poetry','','[]','去年醉家山，有菊餘千本。',84,'全唐诗/poet.song.230000.json','["去年醉家山，有菊餘千本。", "客中今亡是，所至草苯䔿。", "凉風迫九月，暇日上崖巘。", "野芳一二卉，亦足擷婉娩。", "焉所得美酒，慰此歲年晚。", "市荒苦貴糴，庖凊强疏飯。", "薄暮歸空齋，聊與蠹帙偃。"]'),
('32976543-d88f-4fbb-8e69-2a67e6ba3988','秀亭秋懷十五首  其一三','方回','宋','宋诗','song-poetry','','[]','茫茫六合間，孰是身自由。',84,'全唐诗/poet.song.230000.json','["茫茫六合間，孰是身自由。", "貧賤不遑安，故迫口腹謀。", "萬事已云足，心火炎不休。", "朝服寒食散，夜夢鬰儀樓。", "鄙哉齊公子，淚下雍門周。", "萬世一陶叟，浩歌歸故丘。", "有酒醉即眠，無酒亦不求。"]'),
('da87e43b-9ec3-4396-b3cd-a66d83620c20','秀亭秋懷十五首  其一四','方回','宋','宋诗','song-poetry','','[]','薜荔絡奇石，芙蓉艷荒垣。',84,'全唐诗/poet.song.230000.json','["薜荔絡奇石，芙蓉艷荒垣。", "寓目信所之，行行陟秋原。", "南州八九月，已凉仍復暄。", "林樹略改色，沙湍才減痕。", "憶在朔漠日，疲馬風塵奔。", "夜汲長城窟，曉涉灤河源。", "老身凍欲死，其勞不可言。"]'),
('88760c12-f3f3-4dd7-bc3d-bf66e1856df9','秀亭秋懷十五首  其一五','方回','宋','宋诗','song-poetry','','[]','老懷幸無事，何用知秋風。',84,'全唐诗/poet.song.230000.json','["老懷幸無事，何用知秋風。", "團團烏桕樹，一葉垂殷紅。", "爲此有所感，長吟敲虛空。", "城市了在目，心隔雲萬重。", "燕席鼓吹急，游騎呵殿雄。", "亦各適爾適，擾擾塵堁中。", "焉知天地外，有此頹然翁。"]'),
('caa7b97a-d6fc-4d70-b2b8-96471e2d388e','八月二十四日賓暘華父同登秀亭二首  其一','方回','宋','宋诗','song-poetry','','[]','垂垂三徑晚香開，二妙端能爲我來。',64,'全唐诗/poet.song.230000.json','["垂垂三徑晚香開，二妙端能爲我來。", "老瓦尚堪沽濁酒，破鞋何惜上高臺。", "十年心事霜髯短，萬□秋聲畫角哀。", "海內詩人有公等，懸崖待與斸蒼苔。"]'),
('5d40c87e-460b-4aa1-a630-2549ec9eb0e8','八月二十四日賓暘華父同登秀亭二首  其二','方回','宋','宋诗','song-poetry','','[]','兩公詩思欲飛揚，頗似繁臺俯大梁。',64,'全唐诗/poet.song.230000.json','["兩公詩思欲飛揚，頗似繁臺俯大梁。", "瀟灑道裝衣袖闊，昂藏壽相耳毫長。", "持身未慣全隨俗，玩世何嫌略放狂。", "我有平生八叉手，興來舉酒尚洋洋。"]'),
('88b23b9a-b377-429e-ac0a-103395235292','九月八日賓暘携酒西齋晚登秀亭次前韻  其一','方回','宋','宋诗','song-poetry','','[]','深箝笑口似難開，頓喜詩仙載酒來。',64,'全唐诗/poet.song.230000.json','["深箝笑口似難開，頓喜詩仙載酒來。", "此道孰爲今老筆，吾廬適有古荒臺。", "焉知晚節逢陳厄，忽聽高歌類郢哀。", "倚石自憐吟不就，頻將拄杖劃莓苔。"]'),
('ebde94fa-bd8f-475c-bb7a-2a2518078748','九月八日賓暘携酒西齋晚登秀亭次前韻  其二','方回','宋','宋诗','song-poetry','','[]','楚調悠然抑更揚，四愁平子五噫梁。',64,'全唐诗/poet.song.230000.json','["楚調悠然抑更揚，四愁平子五噫梁。", "身同落葉常無定，□比寒花似較長。", "但喜有鄉頻得醉，不知何藥號爲狂。", "芬香臭腐俱塵土，莫問桑田與海洋。"]'),
('9170a287-f5f8-41d4-9b1e-ea5d9817a5e1','九日北山寺二首  其一','方回','宋','宋诗','song-poetry','','[]','松陰佳處路宜遲，裹袖寒鞭馬上垂。',64,'全唐诗/poet.song.230000.json','["松陰佳處路宜遲，裹袖寒鞭馬上垂。", "邂逅同傾九日酒，凄凉暗誦十年詩。", "試迴白首思前事，未覺青山減舊時。", "節後騷英應好在，煮茶更與野僧期。"]'),
('9ed5a4ab-ad6b-4fad-911a-2267fd845f1d','九日北山寺二首  其二','方回','宋','宋诗','song-poetry','','[]','白雲蒼蘚尚知心，野徑荒泉許重尋。',64,'全唐诗/poet.song.230000.json','["白雲蒼蘚尚知心，野徑荒泉許重尋。", "一馬出城元近近，萬松藏寺已深深。", "同遊似覺無先到，半醉誰知政獨吟。", "十度重陽如瞬息，足知往古與來今。"]'),
('5636c703-86de-4a0c-9350-59d58aaea804','秋晚感懷','方回','宋','宋诗','song-poetry','','[]','脫絺著褐事如何，嗇暖饒寒歲易過。',64,'全唐诗/poet.song.230000.json','["脫絺著褐事如何，嗇暖饒寒歲易過。", "□喜晚芳憐早謝，細看園菊驗塘荷。", "風霜天地秋聲急，老病心情醉日多。", "讀破少年三萬卷，枉將身世墮南柯。"]'),
('9e7f4fea-6f55-499d-a14e-54d5580fbb7c','和陶淵明飲酒二十首  其一','方回','宋','宋诗','song-poetry','','[]','生死乃常理，興亡殊似之。',60,'全唐诗/poet.song.230000.json','["生死乃常理，興亡殊似之。", "火烏化王屋，鼎遷亦有時。", "驪山發金雁，漢陵復如茲。", "丹成云得仙，虛塚令人疑。", "杯酒幸到手，無螯亦當持。"]'),
('8d82053f-d0e2-4ba9-84a5-17a9ab3c3f96','和陶淵明飲酒二十首  其二','方回','宋','宋诗','song-poetry','','[]','康廬插南斗，其西柴桑山。',48,'全唐诗/poet.song.230000.json','["康廬插南斗，其西柴桑山。", "我往挹風竹，如聽淵明言。", "作歌以自挽，於今垂千年。", "有口可與飲，公心誰其傳。"]'),
('cbd46aa7-6fd2-4066-9ff1-b0d524ffb254','和陶淵明飲酒二十首  其三','方回','宋','宋诗','song-poetry','','[]','立功亦云可，於世能無情。',60,'全唐诗/poet.song.230000.json','["立功亦云可，於世能無情。", "屈體喪厥節，寧若埋我名。", "極不過餒死，餒死勝飽生。", "是翁醉中語，細味足歎驚。", "寄奴復典午，吾其無目成。"]'),
('639a1015-0dca-4f73-b975-cb4ebf343abf','和陶淵明飲酒二十首  其四','方回','宋','宋诗','song-poetry','','[]','黄雀啐野田，見人輒驚飛。',72,'全唐诗/poet.song.230000.json','["黄雀啐野田，見人輒驚飛。", "飛飛一不早，恐有虞羅悲。", "瞇目饕餮子，繆謂得所依。", "豈不知必爾，甘往終無歸。", "志士餒欲死，未覺勁氣衰。", "手口自斟酌，勿令心事違。"]'),
('a16268f3-8ca6-4120-b809-710bf970b347','和陶淵明飲酒二十首  其五','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','羊車一失馭，天地兵甲喧。',60,'全唐诗/poet.song.230000.json','["羊車一失馭，天地兵甲喧。", "中國不自正，王業東南偏。", "運甓有貽厥，卧龍康廬山。", "使處王謝位，大物豈不還。", "千載飲酒詩，醉吻謠醒言。"]'),
('41a3026d-874f-4613-9962-31226f7a6e19','和陶淵明飲酒二十首  其六','方回','宋','宋诗','song-poetry','','[]','子雲草太玄，萬言無一是。',48,'全唐诗/poet.song.230000.json','["子雲草太玄，萬言無一是。", "唯有鴟夷篇，千古不可毀。", "太上立酒德，餘事徒爲爾。", "酤盡捐我衣，繿縷勝繒綺。"]'),
('ad09c5e9-11d3-47bf-a3a2-af986351e624','和陶淵明飲酒二十首  其七','方回','宋','宋诗','song-poetry','','[]','九日戲馬臺，二謝詞翰英。',60,'全唐诗/poet.song.230000.json','["九日戲馬臺，二謝詞翰英。", "良辰各有句，得無差過情。", "元嘉事其子，不救巢卵傾。", "淵明東籬下，焉識笳鼓鳴。", "兀坐把寒菊，竟亦了一生。"]'),
('019ae93a-b850-492c-8217-46d0ab04cdbb','和陶淵明飲酒二十首  其八','方回','宋','宋诗','song-poetry','','[]','華鬢極老態，醜面乏妍姿。',60,'全唐诗/poet.song.230000.json','["華鬢極老態，醜面乏妍姿。", "插花已不可，可插唯菊枝。", "□□偶有酒，此事竟大奇。", "連作數日飲，詩亦未暇爲。", "忽思往日過，何事馬受羈。"]'),
('06165f57-ad5d-4fb5-9c81-7f2e5b3bba8d','和陶淵明飲酒二十首  其九','方回','宋','宋诗','song-poetry','','[]','高臺翳榛棘，荷鍤岡路開。',96,'全唐诗/poet.song.230000.json','["高臺翳榛棘，荷鍤岡路開。", "振衣陟雲端，朗然豁秋懷。", "言念半死樹，類我晚節乖。", "風雷劈半腹，葉落禽不栖。", "幸不爲薪槱，燒之化塵泥。", "謂可材爲琴，於調恐不諧。", "醉抱作此感，暝色南北迷。", "下山不可急，小僮扶我迴。"]'),
('38b28305-7001-41ab-ac61-813576d32cc5','和陶淵明飲酒二十首  其一○','方回','宋','宋诗','song-poetry','','[]','此邦最佳處，乃在城北隅。',60,'全唐诗/poet.song.230000.json','["此邦最佳處，乃在城北隅。", "野田蕎麥傍，松下復問塗。", "酷愛古石峙，故緩羸驂驅。", "一生能幾許，於茲十載餘。", "夜榻醉卧穩，何殊故園居。"]'),
('2114d749-2728-496f-a8c1-210db96b3842','和陶淵明飲酒二十首  其一一','方回','宋','宋诗','song-poetry','','[]','明年五十九，早歲已聞道。',72,'全唐诗/poet.song.230000.json','["明年五十九，早歲已聞道。", "憶昔初遠遊，豈信今遽老。", "暇日一醉娛，往事萬念槁。", "懸知身死後，豈無數詩好。", "心欲刊晉史，罪匪一靈寶。", "陶翁焉得作，細與問江表。"]'),
('3b5333bc-6be9-415f-9e86-f42707537329','和陶淵明飲酒二十首  其一二','方回','宋','宋诗','song-poetry','','[]','行樂忽有感，當此窮秋時。',72,'全唐诗/poet.song.230000.json','["行樂忽有感，當此窮秋時。", "吾生會亦爾，落葉與樹辭。", "田父屋頗寬，生理僅存茲。", "積逋既已迫，悉售不復疑。", "寧免世人笑，且復相輕欺。", "兒輩勿戚戚，酒至姑飲之。"]'),
('3333db48-c2e8-4782-b77d-2c9ac489815b','和陶淵明飲酒二十首  其一三','方回','宋','宋诗','song-poetry','','[]','士本不畏貧，所畏迫老境。',60,'全唐诗/poet.song.230000.json','["士本不畏貧，所畏迫老境。", "百憂無一樂，可醉不可醒。", "寒風頗欲霜，縫補闕袍領。", "酒膽一何大，和陶效坡潁。", "詩成間亦佳，未忍一炬炳。"]'),
('efab1d99-c459-4152-b44a-cd8aefadce4b','和陶淵明飲酒二十首  其一四','方回','宋','宋诗','song-poetry','','[]','重五去未遠，重九倏已至。',60,'全唐诗/poet.song.230000.json','["重五去未遠，重九倏已至。", "不論家與客，遇節必爛醉。", "前日朝未興，有謁入客次。", "病酒不遑肅，匪敢挾長貴。", "知我□□我，草木故有味。"]'),
('7f42a8e7-5980-486a-985c-8d362c414f45','和陶淵明飲酒二十首  其一五','方回','宋','宋诗','song-poetry','','[]','秋風吹古城，亂山繞荒宅。',60,'全唐诗/poet.song.230000.json','["秋風吹古城，亂山繞荒宅。", "樹影日以疏，沼落見萍迹。", "客來觴我菊，獻酬殆至百。", "斜照未云夕，草端露已白。", "遷化每如此，不飲真可惜。"]'),
('bae3ca98-49a7-40f7-8c85-9ca7640cd6ae','和陶淵明飲酒二十首  其一六','方回','宋','宋诗','song-poetry','','[]','早省宦徑惡，荷鋤寧带經。',72,'全唐诗/poet.song.230000.json','["早省宦徑惡，荷鋤寧带經。", "豈不嘗守郡，生涯百無成。", "一夕偶不飲，鰥枕聽遥更。", "殘燈暗虛牖，落葉鏘空庭。", "鼠囓叱不止，呼奴效貓鳴。", "孰與醉卧熟，萬事忘吾情。"]'),
('46c6505c-a48c-4d2e-902f-340878e728ab','和陶淵明飲酒二十首  其一七','方回','宋','宋诗','song-poetry','','[]','一日不舉酒，即患偏頭風。',48,'全唐诗/poet.song.230000.json','["一日不舉酒，即患偏頭風。", "明日忽不患，乃在酒一中。", "人言飲致疾，此理恐未通。", "杯我自酌我，壁間幸無弓。"]'),
('154e7bd5-a446-44d2-b9d7-09a1b2152116','和陶淵明飲酒二十首  其一八','方回','宋','宋诗','song-poetry','','[]','三戒二已亡，所戒惟在得。',60,'全唐诗/poet.song.230000.json','["三戒二已亡，所戒惟在得。", "大道闢我前，幸無兩岐惑。", "誰歌返招隠，口待穢襪塞。", "身爲葛天民，宅在建德國。", "努力築糟丘，萬感付一默。"]'),
('2269a83f-2ade-438e-b0d8-ebe55e9d85c9','和陶淵明飲酒二十首  其一九','方回','宋','宋诗','song-poetry','','[]','氣豪心未平，三已復三仕。',84,'全唐诗/poet.song.230000.json','["氣豪心未平，三已復三仕。", "毫髪志不伸，所至但屈己。", "屢觸炙眉怒，詎啻折腰耻。", "七年困江國，脫身走故里。", "欲著藏山書，實錄立傳紀。", "往事邈難問，毫簡遽云止。", "不如一杯酒，此亦焉足恃。"]'),
('b4ce1598-2015-4165-8556-27705c777a15','和陶淵明飲酒二十首  其二○','方回','宋','宋诗','song-poetry','','[]','天命孰爲之，萬有凝精真。',120,'全唐诗/poet.song.230000.json','["天命孰爲之，萬有凝精真。", "變氣間龐雜，未嘗泯其淳。", "風雨驟冥晦，暘烏出還新。", "聖孔昔云沒，楊墨仍儀秦。", "復生一辯孟，掃之如游塵。", "諸老自有宗，鑽研患不勤。", "彼以頓自詫，所見特未親。", "月晦有死魄，潦涸無迷津。", "天定盍少俟，屨□□於巾。", "不飲但多憂，無乃真癡人。"]'),
('0e08d98e-0959-404a-a089-eb002bcc940e','憶我二首各三十韻  其一','方回','宋','宋诗','song-poetry','','[]','憶我幼時事，南歸自番禺。',288,'全唐诗/poet.song.230000.json','["憶我幼時事，南歸自番禺。", "三邊已澒洞，內郡猶無虞。", "故居山城間，四面闤闠區。", "東西萬貨集，朝暮百賈趨。", "諸父領賓客，衣冠一何都。", "觴豆日談笑，往往皆文儒。", "比屋有高樓，其上娉婷姝。", "俠少喜酒賤，歌呼間笙竽。", "無何鬰攸作，一夕化爲墟。", "朝廷易楮幣，百姓駢嘆吁。", "物價漸踴貴，饑剽多流俘。", "我家衆長上，生近乾淳初。", "曰此風俗降，歲歲有不如。", "老者遷化去，少者分馳驅。", "生理益艱窘，口腹各自圖。", "書囊裹筆硯，扁舟落江湖。", "苟且祿仕齒，荏苒歲月徂。", "乍得返鄉里，驚怛心若刳。", "前輩盡黄壤，小兒皆白鬚。", "屢火不一火，坊巷非舊閭。", "上塚享亭仆，訪寺詩壁污。", "向之紅粉面，蟻穴髑髏枯。", "乃知宇宙內，萬有皆空虛。", "我生逼六十，偶幸全頭顱。"]'),
('6d66640f-50ef-49e3-859a-f4b726913378','憶我二首各三十韻  其二','方回','宋','宋诗','song-poetry','','[]','憶我弱甫冠，束書如錢塘。',288,'全唐诗/poet.song.230000.json','["憶我弱甫冠，束書如錢塘。", "中興百廿載，行都滋浩穰。", "雖已劣乾淳，尚可云小康。", "巴蜀駭破碎，淮襄傳擾攘。", "腹心輦轂地，按堵如故常。", "于時數萬士，雲集升上庠。", "草茅起窮谷，拭目觀國光。", "出門不識路，天街何其長。", "俠士劇燕趙，佳人□姬姜。", "五鼓夜燈燭，萬樓春絲簧。", "吳米白如雪，奚啻千斯倉。", "縹緲湖山間，畫船嬌紅粧。", "六橋楊柳岸，荷花雲水鄉。", "四時無不宜，莫若僧夏凉。", "小儒苦乏貲，冷眼看豪强。", "託迹朝士館，竊睨鵷鷺行。", "臺評或非是，廟論有不臧。", "相與讀邸報，憤悶填中腸。", "僥倖江漢靜，姦凶殛炎荒。", "禮闈采芻言，始得伸名場。", "豈謂邊功相，曾不監彼狂。", "驕淫無比倫，虐毒尤披猖。", "未聞古天子，買田自置莊。", "羣小附鬼蜮，國脈內已戕。"]'),
('ed02a659-254a-4ba7-be25-383775337067','次韻賓暘梅氏山居訪茱萸','方回','宋','宋诗','song-poetry','','[]','癖習嗜幽討，剛氣負殊稟。',120,'全唐诗/poet.song.230000.json','["癖習嗜幽討，剛氣負殊稟。", "寂寥荒山中，十載賦招隠。", "偶逢梅尉孫，漠事一暗省。", "斯人縱非仙，英概故不泯。", "是日秋□霽，村塢足清景。", "葉脫高木疏，雲淨遠岑逞。", "田家竟收穫，豈復有遺秉。", "芳萸摘併空，戍卒亦太甚。", "懷古兼嘆今，野老僅能茗。", "此心誰當知，應有月中影。"]'),
('c61ea0cd-37df-48e2-9ed4-6647dc05e05a','次韻賓暘某氏墳庵','方回','宋','宋诗','song-poetry','','[]','讀君古墓作，因之懷抱縈。',120,'全唐诗/poet.song.230000.json','["讀君古墓作，因之懷抱縈。", "老夫九年前，小雛憐寧馨。", "一夕病弗起，殤車出北城。", "卜兆鄰古寺，守訶乏村氓。", "去歲罹發掘，盜蹤無由明。", "跋馬近往視，壞垣環枳荆。", "藏中本無物，□至睨茲塋。", "玉匣患不侈，宜爾巢鼯猩。", "楊生昔臝葬，漢傳留佳評。", "世事可以鑒，悲哉聊此吟。"]'),
('2032d7b6-6cf8-49d8-b283-31cd754e3e5e','次韻賓暘桂枝塘','方回','宋','宋诗','song-poetry','','[]','吳越茲上游，一江貫千山。',120,'全唐诗/poet.song.230000.json','["吳越茲上游，一江貫千山。", "山峻江更急，力耕雲霧間。", "民窮實可憫，俗儉無與班。", "甕灌既已拙，斗糴彌足歎。", "十日天不雨，魃也肆厥姦。", "吾昔忝長吏，郡圖朝夕看。", "水源淺易涸，無地施防關。", "此陂築千所，歲事或苟完。", "幽人採荷衣，隄岸窮躋攀。", "更覺滄浪篇，萬頃吹波瀾。"]'),
('9d20b886-d19a-4cdb-a8d0-c60679f60a88','次韻賓暘觀陸右丞王葆真二像','方回','宋','宋诗','song-poetry','','[]','出城挾一兒，策杖極幽邃。',120,'全唐诗/poet.song.230000.json','["出城挾一兒，策杖極幽邃。", "村俗諗父老，古跡按圖志。", "平生丘園心，賁趾遠朝市。", "行行墟墓間，是亦有何味。", "陸家三太守，此邦榮世仕。", "舊祠附學宮，緣情頗應義。", "奈何埤雅公，像於王氏置。", "君不平其然，似欲刪厥位。", "俚舛聊舉隅，諂媚□觸類。", "一一口舌爭，何事如人意。"]'),
('3451c102-4d04-434e-b02c-3c0fab9ed10f','次韻賓暘張氏山園紅菊','方回','宋','宋诗','song-poetry','','[]','惟菊可配松，受命天地正。',120,'全唐诗/poet.song.230000.json','["惟菊可配松，受命天地正。", "吾家植千本，朝耘暮灌潤。", "未言制頹齡，且用樂野性。", "嚴霜百草死，后皇布肅令。", "始知貞勁節，老硬異脆嫩。", "俗圃蒔紅卉，頼君古道振。", "斥謂非其類，一洗靈均恨。", "騷人昔所餐，此輩何敢競。", "惡紫如惡莠，魯叟遯無悶。", "世眼重脂粉，君子故安命。"]'),
('3776cb48-90dd-45bd-adf1-b94d71d86f1c','次韻賓暘張考塢觀茶花','方回','宋','宋诗','song-poetry','','[]','頭上漉酒巾，吹風行欹斜。',120,'全唐诗/poet.song.230000.json','["頭上漉酒巾，吹風行欹斜。", "野徑政自穩，世途殊未涯。", "禮能致商皓，勢足屈孟嘉。", "君身獨自由，時到山人家。", "播植話禾稻，績紡詢桑麻。", "側聞此一塢，村酤亦易賒。", "芙蓉萬紅萼，錦綉紛交加。", "掉頭不肯顧，特往觀茗葩。", "嗅芳摘苦葉，咀嚼香齒牙。", "榷利至此物，誰爲疲氓嗟。"]'),
('1a08765b-61d2-43c2-8a73-ac3146023b9a','次韻賓暘龍泉','方回','宋','宋诗','song-poetry','','[]','小國號瘠土，根據千岩隈。',120,'全唐诗/poet.song.230000.json','["小國號瘠土，根據千岩隈。", "泉味天下最，莫許他郡偕。", "寧當飲此清，饑腸鳴如雷。", "廣斥豈不富，鹹濁良可咍。", "謂茲大龍窟，無乃由齊諧。", "患不甘且冽，榛莽能久埋。", "心惻或不食，汲路荒蒼苔。", "蒙養內自充，何嫌世好乖。", "君子有本性，勿問塞與開。", "成功故偶耳，隠德彌佳哉。"]'),
('efaa51e1-6ff3-4cb3-aa88-7d82d554e35d','同楊明府華父夜宿鸕鷀源','方回','宋','宋诗','song-poetry','','[]','桐廬楊明府，高誼有緩急。',240,'全唐诗/poet.song.230000.json','["桐廬楊明府，高誼有緩急。", "凌江每見訪，爛醉必旬日。", "知我欲東遊，相拉過其宅。", "城南登小舟，僅闊六七尺。", "岸人觀不退，莫知孰主客。", "西風篙工喜，布被當帆席。", "青蔬煮豆乳，灘轉竈釜仄。", "更覺氣象古，酌酒甆盞碧。", "千山霜葉紅，綿綺天組織。", "郊坰有此奇，闤闠苦未識。", "明府眼力高，心賞寄絕壁。", "指似掛篰岩，茅屋擬便葺。", "老夫今十年，往來釣臺側。", "汗顔不敢登，人品霄壤隔。", "夜宿鸕鷀源，犖確陟危石。", "吾家三拜公，晚唐老詩伯。", "衣冠世不墜，奕葉紹桂籍。", "避地館者誰，一僧年八十。", "嗚呼窮谷中，亦復有馬跡。", "紀事聊此吟，續燭借紙筆。"]'),
('04fc0ac0-9e63-40a2-8781-cb3a0bc9ed79','喜趙賓暘楊華父兩兒兩女互姻','方回','宋','宋诗','song-poetry','','[]','十年役嚴陵，心服趙賓暘。',240,'全唐诗/poet.song.230000.json','["十年役嚴陵，心服趙賓暘。", "絕口不言貧，其氣常揚揚。", "一誦貫千古，一醉舉百觴。", "俗士或近之，白眼視昊蒼。", "包山何巍巍，子雲孫姓楊。", "江海一扁舟，倒屣傾侯王。", "見人有疾病，賜以藥餌良。", "朋友負微過，責善尤諄詳。", "兩翁我獨識，非狷亦非狂。", "兩家結姻好，古道顔色光。", "趙男與楊女，年向十五强。", "一朝馳聘幣，互寫紅箋長。", "趙有五歲女，楊有五歲郎。", "是日併納采，酒雁填高堂。", "兩翁自爲媒，兩家門戶當。", "匪爲門戶當，芝蘭同一香。", "不羨積金璧，不受豐縑緗。", "各喜所臠婿，誦書聲琅琅。", "已能臨法帖，已解工詩章。", "何慚昔羲之，坦腹雙東牀。"]'),
('c98936b3-f397-418e-bff6-f6f22f45a4c1','題戚子雲五雲山圖','方回','宋','宋诗','song-poetry','','[]','不濃不淡烟中樹，如有如無雨外山。',32,'全唐诗/poet.song.230000.json','["不濃不淡烟中樹，如有如無雨外山。", "尺素展看空想像，何由身著畫圖間。"]'),
('c575b40c-26eb-4b98-9f4d-57d303e259b9','贈小窗黄君','方回','宋','宋诗','song-poetry','','[]','渾天星斗胸中轉，動地風雷舌上生。',32,'全唐诗/poet.song.230000.json','["渾天星斗胸中轉，動地風雷舌上生。", "想見少年讀書夜，短檠膏盡小窗明。"]'),
('fd3f429f-08cf-41ed-ab9f-99b941168995','三橋旅邸遇雪','方回','宋','宋诗','song-poetry','','[]','醖雲蒸霧暖如烘，一夜南風變北風。',64,'全唐诗/poet.song.230000.json','["醖雲蒸霧暖如烘，一夜南風變北風。", "不似尋常響窗紙，漸驚分寸壓船篷。", "粉妝已鬬佳人白，酒面還輸老子紅。", "記取今年呵凍筆，三橋西岸小樓中。"]'),
('d06c2e31-0f5d-4174-85fc-339ba4b5a206','十二月十五日晚宿餘杭步','方回','宋','宋诗','song-poetry','','[]','孰令牽率到錢塘，朝暮隨人作酒狂。',64,'全唐诗/poet.song.230000.json','["孰令牽率到錢塘，朝暮隨人作酒狂。", "蛻殻喜離城市路，發蒙驚見水雲鄉。", "四方上下乾坤闊，萬里東西日月望。", "向來樓居不得句，此夕葉舟吟興長。"]'),
('717be1ee-5728-43a7-be2c-bccccfae3150','青山道中','方回','宋','宋诗','song-poetry','','[]','插天天目隠雲中，但見苕溪綠向東。',64,'全唐诗/poet.song.230000.json','["插天天目隠雲中，但見苕溪綠向東。", "半折竹初經臘雪，爭妍麥已眩春風。", "翻飛水鳥偏饒白，窄小村船亦畫紅。", "聞說南塘趙書宅，近來毀賣與琳宮。"]'),
('375b9af6-23bd-4e08-a54f-00dd7cf328ab','訪唐師善山居','方回','宋','宋诗','song-poetry','','[]','苕溪南問舊長橋，渡水穿雲不作遥。',64,'全唐诗/poet.song.230000.json','["苕溪南問舊長橋，渡水穿雲不作遥。", "迂道征鞍何自苦，隔林吟屋屢相邀。", "晚晴濃淡烟俱好，春近高低雪盡消。", "尚覺粗材欠詩料，政須餘馥乞唐瓢。"]'),
('6bdd4f18-68ff-4635-ac2d-6c6840f31246','夜飲唐子雲宅別後簡師善','方回','宋','宋诗','song-poetry','','[]','幽居尋未得，下馬揖比鄰。',96,'全唐诗/poet.song.230000.json','["幽居尋未得，下馬揖比鄰。", "指我道傍叟，即君堂上親。", "儀刑全古雅，談笑極清真。", "匕箸山殽美，樽罍臘釀醇。", "扁門稱道院，闢館養詩人。", "得句揮毫疾，論文剪燭頻。", "乾坤百戰定，父子一家春。", "地僻過從少，誰歟此問津。"]'),
('26d318e4-21ce-4cc3-9c59-6c8c141c68ab','昌化道中','方回','宋','宋诗','song-poetry','','[]','縣街長五里，當路卧耕牛。',120,'全唐诗/poet.song.230000.json','["縣街長五里，當路卧耕牛。", "民戶時常閉，官征瑣屑收。", "永無燈火市，况有管弦樓。", "崖石偏欺馬，湍溪不受舟。", "葷羶何可致，蔬茹尚難求。", "客糴珠同價，村沽水雜篘。", "採樵多遇虎，護果最防猴。", "烟火銷荒店，茅茨潰廢郵。", "兵戈雖幸免，賦役更深憂。", "不是山堪賞，行人步步愁。"]'),
('60953392-427a-459b-806f-d487bb67e79e','春前一日還家','方回','宋','宋诗','song-poetry','','[]','最險王干三嶺路，加之雨滑馬行遲。',64,'全唐诗/poet.song.230000.json','["最險王干三嶺路，加之雨滑馬行遲。", "忽驚山客俱來迓，誰報家人已預知。", "飣果待斟分歲酒，剪蔬先賦立春詩。", "舊聞六十猶癡諺，尚少一年焉不癡。"]'),
('0618b6b3-8019-4374-9bc7-18da53d4d29d','虛谷志歸後賦十首  其一','方回','宋','宋诗','song-poetry','','[]','卦揲家人吉，門迎稚子歡。',48,'全唐诗/poet.song.230000.json','["卦揲家人吉，門迎稚子歡。", "始知鄉國好，全勝道途難。", "砌草陳根綠，庭花凍蕾丹。", "春園容日涉，更敢上長安。"]'),
('0f0d9194-5f29-42e4-9d4a-16f19ee9ee37','虛谷志歸後賦十首  其二','方回','宋','宋诗','song-poetry','','[]','萬事何時足，不如歸故鄉。',48,'全唐诗/poet.song.230000.json','["萬事何時足，不如歸故鄉。", "真能主東道，未愛博西凉。", "雪後春臺暖，梅邊夜枕香。", "孰堪思曠友，共隠剡溪傍。"]'),
('a9745eed-973b-4f44-a5f2-8a12ee0553ee','虛谷志歸後賦十首  其三','方回','宋','宋诗','song-poetry','','[]','涉世癡何甚，休官老自應。',48,'全唐诗/poet.song.230000.json','["涉世癡何甚，休官老自應。", "閒蹤今野鶴，榮念已春冰。", "頻報宣麻相，新交辟穀僧。", "微吟時得句，此外別無能。"]'),
('e4ad4e18-eb0c-4a52-a6ec-d256a11c09f4','虛谷志歸後賦十首  其四','方回','宋','宋诗','song-poetry','','[]','買宅嚴灘上，幽栖十載餘。',48,'全唐诗/poet.song.230000.json','["買宅嚴灘上，幽栖十載餘。", "共憐翁失馬，獨喜我知魚。", "賓客千鍾酒，兒郎萬卷書。", "須移歙州住，緣此是鄉居。"]'),
('4429be6d-2718-45fd-9aa9-19c410f2766b','虛谷志歸後賦十首  其五','方回','宋','宋诗','song-poetry','','[]','年將盈六袠，禮尚記三加。',48,'全唐诗/poet.song.230000.json','["年將盈六袠，禮尚記三加。", "北闕昔分竹，東陵今種瓜。", "閒吟聊復爾，爛醉豈知他。", "海內能詩者，時來問我家。"]'),
('fc26b60b-f411-4a0c-a3f7-170628ce8486','虛谷志歸後賦十首  其六','方回','宋','宋诗','song-poetry','','[]','四十載錢塘，詩狂復酒狂。',48,'全唐诗/poet.song.230000.json','["四十載錢塘，詩狂復酒狂。", "湖山空御苑，市井尚宮粧。", "冶肆淆禪剎，勳門賣節堂。", "歸來念前事，朽骨果誰香。"]'),
('083206e1-7afd-4a1a-afc0-dfd3196ae8da','虛谷志歸後賦十首  其七','方回','宋','宋诗','song-poetry','','[]','艷冶千金笑，喧呼六博投。',48,'全唐诗/poet.song.230000.json','["艷冶千金笑，喧呼六博投。", "不因槐枕寤，未暇草堂謀。", "啖菜貧猶健，簪花老自羞。", "五更山酒醒，何樂亦何憂。"]'),
('9bdfe9c8-388f-4cc9-8e8e-0e27b118984f','虛谷志歸後賦十首  其八','方回','宋','宋诗','song-poetry','','[]','薄俗多端忤，殘生底事成。',48,'全唐诗/poet.song.230000.json','["薄俗多端忤，殘生底事成。", "千年驚鶴化，萬里厭鵬程。", "能保中心定，懸知外物輕。", "祇嫌覓句苦，四海有詩名。"]'),
('8883645d-f883-467a-9276-01d95413ab00','虛谷志歸後賦十首  其九','方回','宋','宋诗','song-poetry','','[]','倚樓趙公子，可與共詩評。',48,'全唐诗/poet.song.230000.json','["倚樓趙公子，可與共詩評。", "道故無終極，文須有主盟。", "轟雷春蟄動，貫月夜珠明。", "高作令吾愧，銷光更屏聲。"]'),
('a2c956bb-9e27-4d8e-b6c1-3ba79c5f0b7a','虛谷志歸後賦十首  其一○','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樂天在知命，行止豈人能。',48,'全唐诗/poet.song.230000.json','["樂天在知命，行止豈人能。", "元亮歸廬阜，延之牧始興。", "時才宜政柄，老我只詩朋。", "何日携君手，西湖共訪僧。"]'),
('70386abf-57ec-468c-a13a-2e1b0c46133d','春後喜晴','方回','宋','宋诗','song-poetry','','[]','挈身歸卧萬山中，多謝燈花夜夜紅。',64,'全唐诗/poet.song.230000.json','["挈身歸卧萬山中，多謝燈花夜夜紅。", "老病面顔開喜色，雪霜天地轉春風。", "菜鮮果脆深杯酌，衾汗鞋泥慢火烘。", "寬著心腸任時運，一頑能禦百憂攻。"]'),
('23abdf51-bf35-4304-b1f1-f682b7e374aa','除夕前大雨雪立春已八日','方回','宋','宋诗','song-poetry','','[]','行園似覺褐袍單，揀好梅枝子細看。',64,'全唐诗/poet.song.230000.json','["行園似覺褐袍單，揀好梅枝子細看。", "節近年年多雨雪，客來草草治杯盤。", "故知更事無如老，豈謂交春便不寒。", "氣數已迴終是好，明朝紅日上雲端。"]'),
('a9a187ab-6bd3-479d-b51e-6ae117109368','除夕前一日記事','方回','宋','宋诗','song-poetry','','[]','殘臘先班隔歲春，怱怱五十九年人。',64,'全唐诗/poet.song.230000.json','["殘臘先班隔歲春，怱怱五十九年人。", "一朝一暮即除夜，萬是萬非餘病身。", "老子附爐無奈癢，小兒索紙卒難嗔。", "僕衫婢粉猶閒事，欠餽時官欠飲鄰。"]'),
('1f0751f0-e03a-4c72-9831-44cbad10b06a','錢塘人來','方回','宋','宋诗','song-poetry','','[]','宿收家信醉慵開，早報潮船泊岸隈。',64,'全唐诗/poet.song.230000.json','["宿收家信醉慵開，早報潮船泊岸隈。", "釣瀨兒將詩篋至，錢塘人索酒錢來。", "道途奔走動千里，時節挨排聊一杯。", "新歲雪晴看吾圃，歙城亦有馬城梅。"]'),
('78896bb4-d5c1-4975-ba39-fa405be0786f','歲除','方回','宋','宋诗','song-poetry','','[]','親情鄰里喜歸來，依舊柴門僻處開。',64,'全唐诗/poet.song.230000.json','["親情鄰里喜歸來，依舊柴門僻處開。", "縱是桃符無可筆，未妨菜餠亦堪杯。", "著寬毛褐觀殘雪，洗古銅壺浸老梅。", "賀客明朝有詩客，踏青同與眺春臺。"]'),
('ba4ba032-1bab-4bb1-8f5c-236baa354a52','郡送桃符戲書','方回','宋','宋诗','song-poetry','','[]','狂頗如豪拙似癡，人難忍者我能之。',64,'全唐诗/poet.song.230000.json','["狂頗如豪拙似癡，人難忍者我能之。", "六旬老境三椽屋，四海虛名萬首詩。", "不惜黄金償酒債，猶將白髪綴花枝。", "兒孫十輩誰家有，心事唯應造物知。"]'),
('d54cd7a8-f0a2-4803-b72e-18e5adce6d07','乙酉元日','方回','宋','宋诗','song-poetry','','[]','摩挲老面受春風，肯爲吹將鬢雪融。',64,'全唐诗/poet.song.230000.json','["摩挲老面受春風，肯爲吹將鬢雪融。", "自合居鄉充父老，尚堪開學教兒童。", "官身歷險元如夢，詩律從寬漸不工。", "有菜可羹花可賞，未妨日日酒頻中。"]'),
('4c7bd223-79ae-41e6-88b3-de334157fa8c','次韻劉元煇元日','方回','宋','宋诗','song-poetry','','[]','九十日春已十日，清晨閒步小園中。',64,'全唐诗/poet.song.230000.json','["九十日春已十日，清晨閒步小園中。", "池痕欲漲去年水，柳色漸迴東畔風。", "砥道歌游全似夢，專槃生化本無窮。", "陰晴寒暖頻占相，世事唯宜歲事豐。"]'),
('60c64645-244b-4e17-94c2-dc69eba796cf','正月十日始晴','方回','宋','宋诗','song-poetry','','[]','穗歷桃符漫告新，漆肌蓬鬢轉成陳。',64,'全唐诗/poet.song.230000.json','["穗歷桃符漫告新，漆肌蓬鬢轉成陳。", "暮年多病全無頼，積雨初晴略似春。", "香火荒山猶古廟，兵戈故國僅遺民。", "承平舊俗吾能憶，差勝如今一輩人。"]'),
('f7ef5575-2067-46a6-b82a-19eca9eccd7d','元夕晴','方回','宋','宋诗','song-poetry','','[]','漸暖風烟添軟媚，新晴草木眩光晶。',64,'全唐诗/poet.song.230000.json','["漸暖風烟添軟媚，新晴草木眩光晶。", "天迴地轉春猶在，物是人非意自驚。", "晚輩未宜欺老病，早年猶及見昇平。", "山城舊與錢塘似，燈火笙歌徹五更。"]'),
('094d359a-f388-4295-b253-901b8427e352','約客未至偶書','方回','宋','宋诗','song-poetry','','[]','一半溪梅點綠苔，妖紅移向小桃開。',64,'全唐诗/poet.song.230000.json','["一半溪梅點綠苔，妖紅移向小桃開。", "稍晴欲暖春猶嫩，解賞能吟客肯來。", "少頃焉知千萬古，吾曹難少兩三杯。", "嘶驄未到柴門靜，蛺蝶雙飛去又迴。"]'),
('2c218c0b-d6be-4195-8f56-5e9231a4cc16','葺圃','方回','宋','宋诗','song-poetry','','[]','山水清音屢見招，經丘尋壑尚逍遥。',64,'全唐诗/poet.song.230000.json','["山水清音屢見招，經丘尋壑尚逍遥。", "宅門南北雙桐木，籬徑高低萬菊苗。", "特創小亭觀蘚石，待穿枯沼架茅橋。", "忽思萬事皆虛幻，何苦空將百慮焦。"]'),
('e6da5e9d-e0b9-414b-8b97-c87231fde3e2','春晴','方回','宋','宋诗','song-poetry','','[]','饕風虐雪到家林，才喜春晴春已深。',64,'全唐诗/poet.song.230000.json','["饕風虐雪到家林，才喜春晴春已深。", "花片紛紛飛蝶亂，樹陰漸漸早蟬吟。", "貧寧不仕元知命，老尚能詩懶用心。", "忽喜客來對棋局，旋沽村酒與同斟。"]'),
('34da187d-7fc6-4b05-9277-b68a6dae89ed','一笑','方回','宋','宋诗','song-poetry','','[]','棘爲籬落板爲扉，堂上春山碧四圍。',64,'全唐诗/poet.song.230000.json','["棘爲籬落板爲扉，堂上春山碧四圍。", "前後相承花百種，往來自在燕雙飛。", "賣田不恥因償債，耽酒無厭更典衣。", "人道家貧詩却富，先生一笑久忘機。"]'),
('3f8bfbfe-5b25-4358-a0ce-6aa3356fbc2b','頻醉','方回','宋','宋诗','song-poetry','','[]','紅塵謫墮侍晨仙，屈指明年六十年。',64,'全唐诗/poet.song.230000.json','["紅塵謫墮侍晨仙，屈指明年六十年。", "身後不營埋骨地，春來頻醉賞花天。", "屢聞漢相誅東市，深羨周農服下田。", "烜赫豈如常寂靜，山中幸有酒如泉。"]'),
('f00d1ad2-e620-453d-a0c3-e70ced02a48b','春日俳體','方回','宋','宋诗','song-poetry','','[]','氣至時來物不違，小園閒步見天機。',64,'全唐诗/poet.song.230000.json','["氣至時來物不違，小園閒步見天機。", "荷錢欲出鳴蛙出，柳絮才飛乳燕飛。", "屋少地寬何不可，家貧春好未全非。", "莫欺白髪渾如雪，杯到猶能疾手揮。"]'),
('dadd5bdf-836f-4047-b7fb-1c6bc39a7908','二月十五晚吳江二親携酒','方回','宋','宋诗','song-poetry','','[]','今日山城好事新，客來誇說齒生津。',64,'全唐诗/poet.song.230000.json','["今日山城好事新，客來誇說齒生津。", "喜晴郊外多遊女，歸暮溪邊盡醉人。", "鮮笋紫泥開玉版，嘉魚碧柳貫金鱗。", "一壺就請衰翁飲，亦與花朝報答春。"]'),
('e79c8066-d19b-4ee5-b633-655d380ef84f','春日小園即事十首  其一','方回','宋','宋诗','song-poetry','','[]','閒園草草欠樓臺，一紀干戈夢裏迴。',32,'全唐诗/poet.song.230000.json','["閒園草草欠樓臺，一紀干戈夢裏迴。", "盡失牡丹三百本，新移初見一枝開。"]'),
('4bb4fc93-f975-4fb3-ac93-4b37462c6b75','春日小園即事十首  其二','方回','宋','宋诗','song-poetry','','[]','小亭新築賞天香，恍惚春風舊洛陽。',32,'全唐诗/poet.song.230000.json','["小亭新築賞天香，恍惚春風舊洛陽。", "人道此翁畦菜手，元來亦解種姚黄。"]'),
('36f98fe3-ed42-4e78-a03f-c1d64b2fa6c2','春日小園即事十首  其三','方回','宋','宋诗','song-poetry','','[]','長憶江湖看雨時，插天掛尾玉龍垂。',32,'全唐诗/poet.song.230000.json','["長憶江湖看雨時，插天掛尾玉龍垂。", "歸來老手今無用，養小魚蝦掘小池。"]'),
('44db8748-80d6-4069-9425-5e0cebbd24ea','春日小園即事十首  其四','方回','宋','宋诗','song-poetry','','[]','摘花不恤種花難，幾日工夫一日殘。',32,'全唐诗/poet.song.230000.json','["摘花不恤種花難，幾日工夫一日殘。", "最是好花留不得，不如只種菜花看。"]'),
('acc9b827-1554-40e7-8335-279e1c6efeab','春日小園即事十首  其五','方回','宋','宋诗','song-poetry','','[]','城中誰道有花村，吟出園門醉入門。',32,'全唐诗/poet.song.230000.json','["城中誰道有花村，吟出園門醉入門。", "共笑老人騎老馬，病身俱瘦壯心存。"]'),
('89099165-80fe-4c55-bd4a-4bbc743e116b','春日小園即事十首  其六','方回','宋','宋诗','song-poetry','','[]','傍宅荒山幾許長，蕘夫芸子縱牛羊。',32,'全唐诗/poet.song.230000.json','["傍宅荒山幾許長，蕘夫芸子縱牛羊。", "何當盡與栽桃李，疊石周遭築短牆。"]'),
('869ea2b2-6554-4dfb-ad35-778090735803','春日小園即事十首  其七','方回','宋','宋诗','song-poetry','','[]','頹然無用一憨癡，雖老元來未可欺。',32,'全唐诗/poet.song.230000.json','["頹然無用一憨癡，雖老元來未可欺。", "鼻涕垂頤病擁塞，幽花香處最先知。"]'),
('c67de19d-ff38-4915-878d-56d1aa87cdf9','春日小園即事十首  其八','方回','宋','宋诗','song-poetry','','[]','蒔藥移花撰石名，稍加心匠可經營。',32,'全唐诗/poet.song.230000.json','["蒔藥移花撰石名，稍加心匠可經營。", "天真不假人爲力，綠樹啼鶑一兩聲。"]'),
('72f4b80f-5904-45a6-8eb4-791bfcbc3f69','春日小園即事十首  其九','方回','宋','宋诗','song-poetry','','[]','四十九時初作郡，帆風笠雨十餘年。',32,'全唐诗/poet.song.230000.json','["四十九時初作郡，帆風笠雨十餘年。", "野花山鳥應相笑，依舊歸來無一錢。"]'),
('2faa9090-f11e-48ee-9682-c3c4d2a40d12','春日小園即事十首  其一○','方回','宋','宋诗','song-poetry','','[]','身隠山中聊復爾，詩傳海外豈其然。',32,'全唐诗/poet.song.230000.json','["身隠山中聊復爾，詩傳海外豈其然。", "□間日有人携酒，□惱如天亦醉眠。"]'),
('4c1e943c-1940-4485-91fe-ecf0e66fe879','問政山拜墓','方回','宋','宋诗','song-poetry','','[]','五十年前幼學時，登山諸父許追隨。',64,'全唐诗/poet.song.230000.json','["五十年前幼學時，登山諸父許追隨。", "兩人兄弟身俱老，萬古乾坤事可知。", "守墓鄰翁姑與酒，傳家後嗣孰能詩。", "獻花餽笋爭歡醉，風樹茫茫意自悲。"]'),
('751d7f7b-0b64-4463-8c87-fa29a1a46d3b','飲興道觀有感五首  其一','方回','宋','宋诗','song-poetry','','[]','十萬長松五百年，今其餘幾亦堪憐。',64,'全唐诗/poet.song.230000.json','["十萬長松五百年，今其餘幾亦堪憐。", "霓旌恍惚剛風外，蕊殿崔嵬劫火前。", "題墨八分吾獨識，藏丹九轉後誰傳。", "山中是事皆非昔，惟見新墳掛紙錢。"]'),
('e4e840cf-7492-4aec-8a5f-7a83fe5bc64c','飲興道觀有感五首  其二','方回','宋','宋诗','song-poetry','','[]','仙洞春深長薜蘿，杜鵑花發蕙風和。',64,'全唐诗/poet.song.230000.json','["仙洞春深長薜蘿，杜鵑花發蕙風和。", "善門有後澆松早，貧戶無憂賣笋多。", "萬古銷沈終塚墓，二儀開闢幾干戈。", "情知來去皆非實，醉後猶能作此歌。"]'),
('427a77f8-e629-4089-9805-15bb96279327','飲興道觀有感五首  其三','方回','宋','宋诗','song-poetry','','[]','戍壘兒郎意氣雄，羣腰刀斧薄榛叢。',64,'全唐诗/poet.song.230000.json','["戍壘兒郎意氣雄，羣腰刀斧薄榛叢。", "尋真亭仆長松少，禮斗壇荒苦竹空。", "菜色可憐窮道士，樵歌不見舊鄰翁。", "存亡得喪知何極，天地悠悠感慨中。"]'),
('c0bb9f13-5f69-4c7f-99cf-e55c20955dbd','飲興道觀有感五首  其四','方回','宋','宋诗','song-poetry','','[]','山門蘚獸石嶙峋，三耳翁今去幾春。',64,'全唐诗/poet.song.230000.json','["山門蘚獸石嶙峋，三耳翁今去幾春。", "螻蟻與誰頻作夢，茯苓應更長如人。", "土饅頭裏無仙骨，金僕姑邊尚戰塵。", "焉得亦如酒家叟，一茅庵住自由身。"]'),
('29742748-3229-4198-8ed5-5f5dda15f068','飲興道觀有感五首  其五','方回','宋','宋诗','song-poetry','','[]','爾時儒者定應無，問政胡爲不問儒。',64,'全唐诗/poet.song.230000.json','["爾時儒者定應無，問政胡爲不問儒。", "五代亂離千血陣，萬山深杳一丹爐。", "能容隠遯猶難必，遽謂飛昇豈不誣。", "我欲卜鄰聊避俗，未須跳入長房壺。"]'),
('3736b29a-b54a-4b66-adb1-aa0737b9ad6a','送譯學靳教授','方回','宋','宋诗','song-poetry','','[]','魯國多逢掖，周官設象胥。',48,'全唐诗/poet.song.230000.json','["魯國多逢掖，周官設象胥。", "精言通九譯，博學本三餘。", "職冷冰相似，心清水不如。", "負才宜大用，別有腹中書。"]'),
('79841916-912b-4da9-8cc4-ddb1b40402ad','酴醾盛開二絕  其一','方回','宋','宋诗','song-poetry','','[]','羅雀閒門未寂寥，小園花事自春饒。',32,'全唐诗/poet.song.230000.json','["羅雀閒門未寂寥，小園花事自春饒。", "日葵霜菊踰千本，更有酴醿十萬條。"]'),
('ebea1e29-4c6b-4e58-a5ea-abc23ad68035','酴醾盛開二絕  其二','方回','宋','宋诗','song-poetry','','[]','雪色聯飛蝶過廊，烏衣交語燕歸梁。',32,'全唐诗/poet.song.230000.json','["雪色聯飛蝶過廊，烏衣交語燕歸梁。", "酴醿花下午酲解，春靜人閒白日長。"]'),
('26d1e9eb-3f34-4eef-b431-5fc31a5c4b6b','孚舟亭新成賦十絕  其一','方回','宋','宋诗','song-poetry','','[]','岸人膽落傍船看，鼉吐鯨吞一葉寒。',32,'全唐诗/poet.song.230000.json','["岸人膽落傍船看，鼉吐鯨吞一葉寒。", "鬼伯神官莫狂蕩，靈臺無愧自平安。"]'),
('9249d003-d71d-46c7-bfd0-3c247db25a0b','孚舟亭新成賦十絕  其二','方回','宋','宋诗','song-poetry','','[]','南北東西四面看，舸軒雖窄自心寬。',32,'全唐诗/poet.song.230000.json','["南北東西四面看，舸軒雖窄自心寬。", "永無金馬門邊夢，豈有黄牛峽裏灘。"]'),
('b627f877-2d9b-4bb2-ad49-26a6d06d8cb8','孚舟亭新成賦十絕  其三','方回','宋','宋诗','song-poetry','','[]','春濃面面透花香，秋皎團團轉月光。',32,'全唐诗/poet.song.230000.json','["春濃面面透花香，秋皎團團轉月光。", "窗戶總空天是壁，如吾肺腑沒遮藏。"]'),
('a32aaf30-4073-4bc4-b20d-90c3ec5f34b5','孚舟亭新成賦十絕  其四','方回','宋','宋诗','song-poetry','','[]','六爻虛實相爲用，二位高卑各有宜。',32,'全唐诗/poet.song.230000.json','["六爻虛實相爲用，二位高卑各有宜。", "順撫說隨心不爽，風漂羅剎有還時。"]'),
('57cf93cf-77ae-4a30-b00b-69d5e6b35b2e','孚舟亭新成賦十絕  其五','方回','宋','宋诗','song-poetry','','[]','傍石橫陳八柱亭，一篷{扌陏}矮似船形。',35,'全唐诗/poet.song.230000.json','["傍石橫陳八柱亭，一篷{扌陏}矮似船形。", "松聲浪作風濤吼，何處風濤不慣經。"]'),
('c21004f9-4217-408b-a4b6-af25f494a81e','孚舟亭新成賦十絕  其六','方回','宋','宋诗','song-poetry','','[]','心許天知不愧天，酣風醉月仰天眠。',32,'全唐诗/poet.song.230000.json','["心許天知不愧天，酣風醉月仰天眠。", "自疑略似知章馬，人道還如太乙蓮。"]'),
('acb9a2f9-1a21-4cbd-9c9e-205e3cc1dfcc','孚舟亭新成賦十絕  其七','方回','宋','宋诗','song-poetry','','[]','不須有客問張憑，且要無人覓庾冰。',32,'全唐诗/poet.song.230000.json','["不須有客問張憑，且要無人覓庾冰。", "好是夜寒風浪靜，月明空載一孤僧。"]'),
('5fa558b4-b2af-4687-ae61-2a8cedf6aa17','孚舟亭新成賦十絕  其八','方回','宋','宋诗','song-poetry','','[]','人間踏地有風波，歸老山林莫問他。',32,'全唐诗/poet.song.230000.json','["人間踏地有風波，歸老山林莫問他。", "身是我船心是柁，早尋岸泊奈儂何。"]'),
('e170e546-7310-4682-9901-523f06699755','孚舟亭新成賦十絕  其九','方回','宋','宋诗','song-poetry','','[]','向來人喚老梢工，解使帆檣八面風。',32,'全唐诗/poet.song.230000.json','["向來人喚老梢工，解使帆檣八面風。", "今日釣魚亦無力，劣能聽雨卧船篷。"]'),
('3db11862-d1f7-4abb-89e8-589d2b472e6f','孚舟亭新成賦十絕  其一○','方回','宋','宋诗','song-poetry','','[]','不待圓□□□□，□□□□□□□。',32,'全唐诗/poet.song.230000.json','["不待圓□□□□，□□□□□□□。", "栖梁燕乳春聲豫，細玩天機坐此亭。"]'),
('f3de7517-0e24-49df-b64b-8eeca5c79162','謝張慵庵文煥見訪','方回','宋','宋诗','song-poetry','','[]','兩年夢寐記冰姿，再挹丰標勝舊時。',64,'全唐诗/poet.song.230000.json','["兩年夢寐記冰姿，再挹丰標勝舊時。", "形穢自憐吾更老，味同乃幸獨相知。", "幽花野竹頻移座，薄酒清茶共說詩。", "晚色柴門掛新月，玉驄欲上步猶遲。"]'),
('b0a5c2da-42fa-428a-ac5d-7519b43f3150','贈數學吳桂子','方回','宋','宋诗','song-poetry','','[]','先天有數妙蓍龜，詫鬼誇神滿卷詩。',32,'全唐诗/poet.song.230000.json','["先天有數妙蓍龜，詫鬼誇神滿卷詩。", "獨一許翁可吾意，預占晴色賞酴醿。"]'),
('2b749531-2938-4d2e-bf64-859ae3e2683e','春晚雜興十二首  其一','方回','宋','宋诗','song-poetry','','[]','七年守郡罷三年，賣盡山中五頃田。',32,'全唐诗/poet.song.230000.json','["七年守郡罷三年，賣盡山中五頃田。", "書籍可捐衣可典，猶能醉面仰看天。"]'),
('c373abe9-6c8c-43cb-a111-d2f679a504f4','春晚雜興十二首  其二','方回','宋','宋诗','song-poetry','','[]','林下蕭然一禿翁，吟髭全白醉顔紅。',32,'全唐诗/poet.song.230000.json','["林下蕭然一禿翁，吟髭全白醉顔紅。", "米鹽薪炭時時絕，自古詩人例合窮。"]'),
('ef78275f-9173-426b-9cc1-88045a43e81c','春晚雜興十二首  其三','方回','宋','宋诗','song-poetry','','[]','賣茶猶說有征譏，蕨菜何爲入市稀。',32,'全唐诗/poet.song.230000.json','["賣茶猶說有征譏，蕨菜何爲入市稀。", "往往提籃採山者，怕逢猛虎竟空歸。"]'),
('c0269437-27e1-428e-80d4-1b1f334c7066','春晚雜興十二首  其四','方回','宋','宋诗','song-poetry','','[]','午亭春醉聳吟肩，終是風流不愧天。',32,'全唐诗/poet.song.230000.json','["午亭春醉聳吟肩，終是風流不愧天。", "屑麥調酥慢熬火，牡丹花共菊芽煎。"]'),
('0e879320-83ee-4ff6-b424-fc067006f57a','春晚雜興十二首  其五','方回','宋','宋诗','song-poetry','','[]','漫浪桐江一把麾，往來今積十年詩。',32,'全唐诗/poet.song.230000.json','["漫浪桐江一把麾，往來今積十年詩。", "次山自序舂陵集，豈望夔州杜二知。"]'),
('90b878ef-ca08-407b-8e69-071208ba3a70','春晚雜興十二首  其六','方回','宋','宋诗','song-poetry','','[]','豈有耶溪父老錢，無朝無暮在樽前。',32,'全唐诗/poet.song.230000.json','["豈有耶溪父老錢，無朝無暮在樽前。", "櫻桃豌豆分兒女，草草春風又一年。"]'),
('14554855-ea52-4b43-8304-13b616add88e','春晚雜興十二首  其七','方回','宋','宋诗','song-poetry','','[]','隨分栽蔬復種花，逐時溫酒又煎茶。',32,'全唐诗/poet.song.230000.json','["隨分栽蔬復種花，逐時溫酒又煎茶。", "兩兒能售嚴州屋，便可歸來共一家。"]'),
('e5236461-fb9d-4a6f-9248-b8fbb71b6cb6','春晚雜興十二首  其八','方回','宋','宋诗','song-poetry','','[]','尪羸老馬尚堪騎，象笏金章已屬誰。',32,'全唐诗/poet.song.230000.json','["尪羸老馬尚堪騎，象笏金章已屬誰。", "政使死時無一物，清心壯膽有天知。"]'),
('808cff30-4ca8-4a47-ac00-40885c25d293','春晚雜興十二首  其九','方回','宋','宋诗','song-poetry','','[]','溪魚山筍佐新篘，大勝長安上酒樓。',32,'全唐诗/poet.song.230000.json','["溪魚山筍佐新篘，大勝長安上酒樓。", "春老猶寒宿酲困，酴醿花下擁綿裘。"]'),
('7f563b1b-7f26-4267-ab65-1563fc922951','春晚雜興十二首  其一○','方回','宋','宋诗','song-poetry','','[]','桐花落盡熟朱櫻，無數珍禽繞樹鳴。',32,'全唐诗/poet.song.230000.json','["桐花落盡熟朱櫻，無數珍禽繞樹鳴。", "繡羽翠衿政堪玩，伊誰輕著彈丸驚。"]'),
('a44659fc-0a44-41bc-a613-cb468cc433c9','春晚雜興十二首  其一一','方回','宋','宋诗','song-poetry','','[]','城市塵埃不見詩，西村東塢可尋誰。',32,'全唐诗/poet.song.230000.json','["城市塵埃不見詩，西村東塢可尋誰。", "夏前十日嘗新麥，政是江南最好時。"]'),
('063a7ac4-e82d-433b-9751-98ee2129e039','春晚雜興十二首  其一二','方回','宋','宋诗','song-poetry','','[]','芳草茸茸沒屨深，清和天氣潤園林。',32,'全唐诗/poet.song.230000.json','["芳草茸茸沒屨深，清和天氣潤園林。", "霏微小雨初晴處，暗數青梅立樹陰。"]'),
('a5856d95-c260-4bf6-a977-7baa1ccad077','漫興九首  其一','方回','宋','宋诗','song-poetry','','[]','索文僧送紙，賭酒客爭棋。',24,'全唐诗/poet.song.230000.json','["索文僧送紙，賭酒客爭棋。", "定要全無事，何由更有詩。"]'),
('9e61dce0-0836-4f18-9873-05bb622b0239','漫興九首  其二','方回','宋','宋诗','song-poetry','','[]','老豈堪從仕，窮應不爲詩。',24,'全唐诗/poet.song.230000.json','["老豈堪從仕，窮應不爲詩。", "死生元有命，病亦莫求醫。"]'),
('91bd947e-b6b0-44ba-acb8-694e746274de','漫興九首  其三','方回','宋','宋诗','song-poetry','','[]','我欲培修竹，新添笋幾根。',24,'全唐诗/poet.song.230000.json','["我欲培修竹，新添笋幾根。", "徘徊看不已，愛惜似兒孫。"]'),
('98cc5149-1407-4ae8-9743-48bb23943904','漫興九首  其四','方回','宋','宋诗','song-poetry','','[]','半落酴醿雪，微舒芍藥丹。',24,'全唐诗/poet.song.230000.json','["半落酴醿雪，微舒芍藥丹。", "薰風交割近，特地更春寒。"]'),
('bf212019-807b-4e2f-a857-6e626288a610','漫興九首  其五','方回','宋','宋诗','song-poetry','','[]','靜院幽花馥，空庭皓月明。',24,'全唐诗/poet.song.230000.json','["靜院幽花馥，空庭皓月明。", "春寒夜更好，未有一蟲鳴。"]'),
('cb091815-a711-4b26-8430-e9bbd76bd121','漫興九首  其六','方回','宋','宋诗','song-poetry','','[]','索果嬌兒怒，胹羹老僕頑。',24,'全唐诗/poet.song.230000.json','["索果嬌兒怒，胹羹老僕頑。", "欲嗔仍復笑，掩卷看南山。"]'),
('2502c220-2fbe-4200-913e-b5fc7ad61441','漫興九首  其七','方回','宋','宋诗','song-poetry','','[]','袍絮無堪換，柴錢久未還。',24,'全唐诗/poet.song.230000.json','["袍絮無堪換，柴錢久未還。", "有人來問字，賒酒醉花間。"]'),
('6091a295-b9a4-47e9-a099-c982346f74bd','漫興九首  其八','方回','宋','宋诗','song-poetry','','[]','淡虀淘大麥，甘酪薦含桃。',24,'全唐诗/poet.song.230000.json','["淡虀淘大麥，甘酪薦含桃。", "風調誰優劣，田家似頗高。"]'),
('9cb8f472-d3bb-4b2d-91bb-6609b89251e6','漫興九首  其九','方回','宋','宋诗','song-poetry','','[]','欲跨羸驂去，江村訪酒家。',24,'全唐诗/poet.song.230000.json','["欲跨羸驂去，江村訪酒家。", "杖頭無阿堵，肯聽錦囊賒。"]'),
('f6ae04d1-ee38-4299-8ad7-8a1cc994edae','殘春感事十首  其一','方回','宋','宋诗','song-poetry','','[]','寒暑元如故，乾坤豈不寬。',48,'全唐诗/poet.song.230000.json','["寒暑元如故，乾坤豈不寬。", "時情工刻薄，生理轉艱難。", "遑恤諸兒笑，終憑後代看。", "淵明詠貧士，感慨異悲酸。"]'),
('e840edfc-0a7d-4f93-a940-10441e10ca72','殘春感事十首  其二','方回','宋','宋诗','song-poetry','','[]','守郡艱危日，還家老病時。',48,'全唐诗/poet.song.230000.json','["守郡艱危日，還家老病時。", "僮奴驚逝謝，賓客聽分離。", "耨草泥霑手，煎茶火燎髭。", "固窮終不怨，百鍊出新詩。"]'),
('b6b3da0f-2af9-4512-af7d-9b7edcd24b6a','殘春感事十首  其三','方回','宋','宋诗','song-poetry','','[]','青簡興亡驟，蒼規代謝頻。',48,'全唐诗/poet.song.230000.json','["青簡興亡驟，蒼規代謝頻。", "懸知千古恨，政似一年春。", "甫換鍾馗舊，俄聞杜宇新。", "梨花自寒食，誰酹石麒麟。"]'),
('f5425cd8-4e42-44a1-9e3f-f72c90689993','殘春感事十首  其四','方回','宋','宋诗','song-poetry','','[]','登高高處望，萬嶂一溪橫。',48,'全唐诗/poet.song.230000.json','["登高高處望，萬嶂一溪橫。", "不滿千家市，今休十載兵。", "訓狐號永夜，猛虎迫荒城。", "此亦關人事，憂端未易平。"]'),
('c3fdba90-a223-482d-96f9-ee18453ebac5','殘春感事十首  其五','方回','宋','宋诗','song-poetry','','[]','學易何須博，乾坤第一爻。',48,'全唐诗/poet.song.230000.json','["學易何須博，乾坤第一爻。", "兩儀能細察，萬象已并包。", "枯秸供羸馬，纖鱗餵乳貓。", "吾衰有三韭，端勝易牙庖。"]'),
('b536abb8-297e-4101-8a47-1c2ee85bbc0b','殘春感事十首  其六','方回','宋','宋诗','song-poetry','','[]','果熟携竿撲，禽鳴挾彈窺。',48,'全唐诗/poet.song.230000.json','["果熟携竿撲，禽鳴挾彈窺。", "自憐多病叟，無奈近鄰兒。", "排闥寧容鎖，踰垣更問籬。", "牡丹才半拆，摘去最紅枝。"]'),
('7faba59e-eb2f-45f3-882c-a53bbd41ae68','殘春感事十首  其七','方回','宋','宋诗','song-poetry','','[]','底用春風急，詩肩暖亦寒。',48,'全唐诗/poet.song.230000.json','["底用春風急，詩肩暖亦寒。", "兒曹如笋長，吾事只梅酸。", "後死猶容健，餘生愈覺難。", "一瓢自窮巷，何止此堪歎。"]'),
('8be10946-4fd4-47fe-8aa0-588e16982850','殘春感事十首  其八','方回','宋','宋诗','song-poetry','','[]','春雨溪橋斷，才晴又淺流。',48,'全唐诗/poet.song.230000.json','["春雨溪橋斷，才晴又淺流。", "端能操古節，何至墮窮愁。", "馮衍嘗爲郡，田豐不願侯。", "吾兒猶未解，餘子復奚尤。"]'),
('a61c583c-3e49-4a60-90bd-bde5cecc87de','殘春感事十首  其九','方回','宋','宋诗','song-poetry','','[]','格磔禽穿戶，延緣蟻上衣。',48,'全唐诗/poet.song.230000.json','["格磔禽穿戶，延緣蟻上衣。", "雨來山氣潤，花過樹陰肥。", "去去春如夢，行行暮獨歸。", "偶無賓友至，自取一杯揮。"]'),
('6d2621ef-5976-4efd-b608-160d642d0327','殘春感事十首  其一○','方回','宋','宋诗','song-poetry','','[]','身起真寒士，名成老腐儒。',48,'全唐诗/poet.song.230000.json','["身起真寒士，名成老腐儒。", "暫時金馬署，終世石魚湖。", "舊種花猶有，新畬粟已無。", "傍人憂餓死，吾自典衣酤。"]'),
('ee710156-0842-4996-a186-692d013098aa','次韻送張文煥  其一','方回','宋','宋诗','song-poetry','','[]','廊廟端非岩壑姿，慵庵未是可慵時。',64,'全唐诗/poet.song.230000.json','["廊廟端非岩壑姿，慵庵未是可慵時。", "浮榮故自無心向，素抱其如有己知。", "天上要途終一武，江南絕景已千詩。", "欲從遠祖赤松子，小待功成亦未遲。"]'),
('85e8e45b-291a-4b61-95bd-e5ca8951eeb7','次韻送張文煥  其二','方回','宋','宋诗','song-poetry','','[]','深愧衰殘蒲柳姿，忽思同眺萬山時。',64,'全唐诗/poet.song.230000.json','["深愧衰殘蒲柳姿，忽思同眺萬山時。", "各將谷雨崖烟寫，獨許溪鷗野鷺知。", "兩載再逢憐我老，五更不寐和公詩。", "願聞事業如房杜，一曲清商自尉遲。"]'),
('1653de86-96cb-4f18-a393-95e8a0dadf37','芍藥十叢近千蕊客飲散一夕而空','方回','宋','宋诗','song-poetry','','[]','雖微風物似揚州，繭栗初紅已遽休。',64,'全唐诗/poet.song.230000.json','["雖微風物似揚州，繭栗初紅已遽休。", "插戴端宜誰粉面，奪攘無奈衆蒼頭。", "未知相謔真何謂，不許當階略少留。", "玉爵彩雲諳往事，可因尤物作閒愁。"]'),
('e940be6f-1afb-4d1b-a2e0-a90af550b05e','惜芍藥再賦','方回','宋','宋诗','song-poetry','','[]','元方除却牡丹兄，俗紫凡紅敢競名。',64,'全唐诗/poet.song.230000.json','["元方除却牡丹兄，俗紫凡紅敢競名。", "天女散花雖不染，道人養馬豈無情。", "一芽才動看承久，千蕊俱空斷送輕。", "三萬卷書總零落，匹如風雨未須驚。"]'),
('7d54ae05-aad2-457c-b080-160d708758a2','計桐江續稿九卷卷百首書其末','方回','宋','宋诗','song-poetry','','[]','詩律中年悟，嫌工更恐肥。',48,'全唐诗/poet.song.230000.json','["詩律中年悟，嫌工更恐肥。", "獨行無與語，每出又空歸。", "薑棗頻煎藥，袍衫屢換衣。", "病身自無頼，猶忍泄天機。"]'),
('a6cc5788-7e13-4d36-8abf-dc0bc2f647b3','先天易吟三十首  其一','方回','宋','宋诗','song-poetry','','[]','不識第一畫，羲皇運腕初。',24,'全唐诗/poet.song.230000.json','["不識第一畫，羲皇運腕初。", "憑空說儀象，枉著汗牛書。"]'),
('f838a0a8-7dca-4133-b074-487a4e3a1b05','先天易吟三十首  其二','方回','宋','宋诗','song-poetry','','[]','舜禹昔禪位，曾將易問蓍。',24,'全唐诗/poet.song.230000.json','["舜禹昔禪位，曾將易問蓍。", "即知重八卦，已自伏羲時。"]'),
('6a6027b0-357a-45d7-9610-87dfb3c1b3f1','先天易吟三十首  其三','方回','宋','宋诗','song-poetry','','[]','高下乾坤位，東西日月門。',24,'全唐诗/poet.song.230000.json','["高下乾坤位，東西日月門。", "正身當午立，一點認心源。"]'),
('239f2c51-74b4-49b3-95e1-ba445e6d1d34','先天易吟三十首  其四','方回','宋','宋诗','song-poetry','','[]','太極元無物，群生性命根。',24,'全唐诗/poet.song.230000.json','["太極元無物，群生性命根。", "一奇仍一偶，萬象滿乾坤。"]'),
('dc34016b-443a-4c1a-823f-ca13576db43f','先天易吟三十首  其五','方回','宋','宋诗','song-poetry','','[]','四象寫老少，兩儀書偶奇。',24,'全唐诗/poet.song.230000.json','["四象寫老少，兩儀書偶奇。", "四從兩上判，惟一邵翁知。"]'),
('70d470c6-8e19-40ef-a79a-d7abab40c40f','先天易吟三十首  其六','方回','宋','宋诗','song-poetry','','[]','八卦各爲八，枝從幹上橫。',24,'全唐诗/poet.song.230000.json','["八卦各爲八，枝從幹上橫。", "厥初有何物，萬物一根生。"]'),
('e3f59da4-0964-48eb-af3a-49cee1033a4c','先天易吟三十首  其七','方回','宋','宋诗','song-poetry','','[]','鍾律及星歷，軍師兼井田。',24,'全唐诗/poet.song.230000.json','["鍾律及星歷，軍師兼井田。", "方圓兩圖在，萬古立鼇天。"]'),
('a40580c2-3ba1-4a2f-af55-121d2ae63eb7','先天易吟三十首  其八','方回','宋','宋诗','song-poetry','','[]','從來二生四，誰謂二生三。',24,'全唐诗/poet.song.230000.json','["從來二生四，誰謂二生三。", "迷路求玄牝，精微未許探。"]'),
('7091195e-3d9c-44b3-996c-2f2f28b75020','先天易吟三十首  其九','方回','宋','宋诗','song-poetry','','[]','首言天地易，次語贊羲皇。',24,'全唐诗/poet.song.230000.json','["首言天地易，次語贊羲皇。", "繫傳誰精玩，先看第一章。"]'),
('4170b2c8-b742-49fd-90c2-0fdb9e9521fe','先天易吟三十首  其一○','方回','宋','宋诗','song-poetry','','[]','子半至午半，南方旋北方。',24,'全唐诗/poet.song.230000.json','["子半至午半，南方旋北方。", "往來分逆順，治亂判陰陽。"]'),
('5c808b4c-f7ea-4729-b0f8-457d48e2c0d6','先天易吟三十首  其一一','方回','宋','宋诗','song-poetry','','[]','有畫無言語，斯文豈易知。',24,'全唐诗/poet.song.230000.json','["有畫無言語，斯文豈易知。", "人心對天一，更向畫前窺。"]'),
('4e1e78c5-d354-4981-95b6-a99dac9c1703','先天易吟三十首  其一二','方回','宋','宋诗','song-poetry','','[]','天地有定位，地天陽泰三。',24,'全唐诗/poet.song.230000.json','["天地有定位，地天陽泰三。", "更於通氣處，細認澤山咸。"]'),
('7f61306b-ea1a-4adb-91b7-aa63f7eb6c94','先天易吟三十首  其一三','方回','宋','宋诗','song-poetry','','[]','乾坤坎離位，元會運世篇。',24,'全唐诗/poet.song.230000.json','["乾坤坎離位，元會運世篇。", "三百六十歲，才似一周年。"]'),
('a9d74466-1b1b-44b3-8ee0-5a63d9ec0215','先天易吟三十首  其一四','方回','宋','宋诗','song-poetry','','[]','瀛登唐治日，奎聚宋興年。',24,'全唐诗/poet.song.230000.json','["瀛登唐治日，奎聚宋興年。", "子午復南北，一聲啼杜鵑。"]'),
('41d653c4-03b1-4981-b7ad-756ed800863b','先天易吟三十首  其一五','方回','宋','宋诗','song-poetry','','[]','圓象天儀轉，方侔地里分。',24,'全唐诗/poet.song.230000.json','["圓象天儀轉，方侔地里分。", "獨超形器外，寂感一靈君。"]'),
('481342b8-06bd-4897-a681-1de04684611e','先天易吟三十首  其一六','方回','宋','宋诗','song-poetry','','[]','河圖天地數，五與十居中。',24,'全唐诗/poet.song.230000.json','["河圖天地數，五與十居中。", "所拱中一點，心爲八位宗。"]'),
('5eaef96b-8059-4bb7-93a2-b41c6f440d01','先天易吟三十首  其一七','方回','宋','宋诗','song-poetry','','[]','六爻六畫後，六位六虛中。',24,'全唐诗/poet.song.230000.json','["六爻六畫後，六位六虛中。", "此處曾著眼，玄哉無極翁。"]'),
('922222a2-b8cc-4c69-b100-3fc1a48de740','先天易吟三十首  其一八','方回','宋','宋诗','song-poetry','','[]','萬世復萬世，人心無改時。',24,'全唐诗/poet.song.230000.json','["萬世復萬世，人心無改時。", "此理本非古，伏羲先得之。"]'),
('b42ea327-7163-4a6d-93e6-e19ccc2d3468','先天易吟三十首  其一九','方回','宋','宋诗','song-poetry','','[]','先覺欲覺後，三峰列四圖。',24,'全唐诗/poet.song.230000.json','["先覺欲覺後，三峰列四圖。", "求精由藴入，言說本來無。"]'),
('7ab55d09-5ab6-43df-85d6-56ca4671f424','先天易吟三十首  其二○','方回','宋','宋诗','song-poetry','','[]','心法先天易，盍於離位求。',24,'全唐诗/poet.song.230000.json','["心法先天易，盍於離位求。", "儻非明出地，長夜使人愁。"]'),
('6ae98f9d-a995-4e3a-a74d-deb8399453ed','先天易吟三十首  其二一','方回','宋','宋诗','song-poetry','','[]','天地囿於氣，聖賢脩此心。',24,'全唐诗/poet.song.230000.json','["天地囿於氣，聖賢脩此心。", "範圍非有許，生聚尚斯今。"]'),
('41c972f9-81cc-47af-8bd4-fb5969227d37','先天易吟三十首  其二二','方回','宋','宋诗','song-poetry','','[]','水旱堯湯有，先天數可推。',24,'全唐诗/poet.song.230000.json','["水旱堯湯有，先天數可推。", "聖君得賢相，翻是太平時。"]'),
('e483f94d-5307-474a-abe9-39a70c8b22ec','先天易吟三十首  其二三','方回','宋','宋诗','song-poetry','','[]','神農嘗毒藥，軒后設難經。',24,'全唐诗/poet.song.230000.json','["神農嘗毒藥，軒后設難經。", "認取卦中意，仁心救未形。"]'),
('fbc9b894-4c62-4c47-bd10-9219e67fd1bf','先天易吟三十首  其二四','方回','宋','宋诗','song-poetry','','[]','水平民不溺，穀播世無饑。',24,'全唐诗/poet.song.230000.json','["水平民不溺，穀播世無饑。", "氣數如寒暑，能無理轉移。"]'),
('bacb2c1d-86a6-432b-b687-49dbd7b84b3a','先天易吟三十首  其二五','方回','宋','宋诗','song-poetry','','[]','誰識歸奇意，專爲禦患謀。',24,'全唐诗/poet.song.230000.json','["誰識歸奇意，專爲禦患謀。", "將寒儲纊絮，未暮貯膏油。"]'),
('15520b61-bd7c-4072-8eff-2faa53c2db9b','先天易吟三十首  其二六','方回','宋','宋诗','song-poetry','','[]','兩重三畫卦，半束百莖蓍。',24,'全唐诗/poet.song.230000.json','["兩重三畫卦，半束百莖蓍。", "避就殊凶吉，元無巧與奇。"]'),
('51e06bfa-b00b-42b5-8392-d6653bc90665','先天易吟三十首  其二七','方回','宋','宋诗','song-poetry','','[]','畫處本天地，占時通鬼神。',24,'全唐诗/poet.song.230000.json','["畫處本天地，占時通鬼神。", "自然大道理，絲髪不由人。"]'),
